-- Poems batch 445
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-27','酬張繼','皇甫冉','唐','御定全唐诗','yuding','','[]','悵望南徐登北固，迢遙西塞恨東關。',32,'御定全唐詩/json/250.json','["悵望南徐登北固，迢遙西塞恨東關。", "落日臨川問音信，寒潮唯帶夕陽還。"]'),
('yuding-28','送柳八員外赴江西','皇甫冉','唐','御定全唐诗','yuding','','[]','岐路窮無極，長江九派分。行人隨旅雁，楚樹入湘雲。',48,'御定全唐詩/json/250.json','["岐路窮無極，長江九派分。行人隨旅雁，楚樹入湘雲。", "久在征南役，何殊薊北勳。離心不可問，歲暮雪紛紛。"]'),
('yuding-29','賦長道一絕送陸邃潛夫','皇甫冉','唐','御定全唐诗','yuding','','[]','高山迥欲登，遠水深難渡。杳杳複漫漫，行人別家去。',24,'御定全唐詩/json/250.json','["高山迥欲登，遠水深難渡。杳杳複漫漫，行人別家去。"]'),
('yuding-30','又得雲字','皇甫冉','唐','御定全唐诗','yuding','','[]','何事千年遇聖君，坐令雙鬢老如雲。',32,'御定全唐詩/json/250.json','["何事千年遇聖君，坐令雙鬢老如雲。", "南行更入深山淺，岐路悠悠水自分。"]'),
('yuding-31','送陸潛夫往茅山賦得華陽洞','皇甫冉','唐','御定全唐诗','yuding','','[]','遊仙洞兮訪真官，奠瑤席兮禮石壇。忽仿佛兮雲擾，',37,'御定全唐詩/json/250.json','["遊仙洞兮訪真官，奠瑤席兮禮石壇。忽仿佛兮雲擾，", "有昏嫁兮嬰纏，綿歸來兮已久。"]'),
('yuding-32','又送陸潛夫茅山尋友','皇甫冉','唐','御定全唐诗','yuding','','[]','登山自補屐，訪友不齎糧。坐嘯青楓晚，行吟白日長。',48,'御定全唐詩/json/250.json','["登山自補屐，訪友不齎糧。坐嘯青楓晚，行吟白日長。", "人煙隔水見，草氣入林香。誰作招尋侶，清齋宿紫陽。"]'),
('yuding-33','賦得越山三韻','皇甫冉','唐','御定全唐诗','yuding','','[]','西陵猶隔水，北岸已春山。獨鳥連天去，孤雲伴客還。',36,'御定全唐詩/json/250.json','["西陵猶隔水，北岸已春山。獨鳥連天去，孤雲伴客還。", "只應結茅宇，出入石林間。"]'),
('yuding-34','送盧郎中使君赴京','皇甫冉','唐','御定全唐诗','yuding','','[]','三年期上國，萬里自東溟。曲蓋遵長道，油幢憩短亭。',48,'御定全唐詩/json/250.json','["三年期上國，萬里自東溟。曲蓋遵長道，油幢憩短亭。", "楚雲山隱隱，淮雨草青青。康樂多新興，題詩紀所經。"]'),
('yuding-35','楊氏林亭探得古槎','皇甫冉','唐','御定全唐诗','yuding','','[]','千年古貌多，八月秋濤晚。偶被主人留，那知來近遠。',24,'御定全唐詩/json/250.json','["千年古貌多，八月秋濤晚。偶被主人留，那知來近遠。"]'),
('yuding-36','送鄭二之茅山','皇甫冉','唐','御定全唐诗','yuding','','[]','水流絕澗終日，草長深山暮春。',28,'御定全唐詩/json/250.json','["水流絕澗終日，草長深山暮春。", "犬吠雞鳴幾處，條桑種杏何人。"]'),
('yuding-37','和王給事禁省梨花詠','皇甫冉','唐','御定全唐诗','yuding','','[]','巧解逢人笑，還能亂蝶飛。春時風入戶，幾片落朝衣。',24,'御定全唐詩/json/250.json','["巧解逢人笑，還能亂蝶飛。春時風入戶，幾片落朝衣。"]'),
('yuding-38','送鄭員外入茅山居','皇甫冉','唐','御定全唐诗','yuding','','[]','但見全家去，寧知幾日還。白雲迎穀口，流水出人間。',48,'御定全唐詩/json/250.json','["但見全家去，寧知幾日還。白雲迎穀口，流水出人間。", "冠冕情遺世，神仙事滿山。其中應有物，豈貴一身閑。"]'),
('yuding-39','送志彌師往淮南','皇甫冉','唐','御定全唐诗','yuding','','[]','已能持律藏，複去禮禪亭。長老偏摩頂，時流尚誦經。',48,'御定全唐詩/json/250.json','["已能持律藏，複去禮禪亭。長老偏摩頂，時流尚誦經。", "獨行寒野曠，旅宿遠山青。眷屬空相望，鴻飛已杳冥。"]'),
('yuding-40','謝韋大夫柳栽','皇甫冉','唐','御定全唐诗','yuding','','[]','本在胡笳曲，今從漢將營。濃陰方待庇，弱植豈無情。',48,'御定全唐詩/json/250.json','["本在胡笳曲，今從漢將營。濃陰方待庇，弱植豈無情。", "比雪花應吐，藏烏葉未成。五株蒙遠賜，應使號先生。"]'),
('yuding-41','問李二司直所居雲山','皇甫冉','唐','御定全唐诗','yuding','','[]','門外水流何處？天邊樹繞誰家？',28,'御定全唐詩/json/250.json','["門外水流何處？天邊樹繞誰家？", "山色東西多少？朝朝幾度雲遮。"]'),
('yuding-42','劉侍禦朝命許停官歸侍','皇甫冉','唐','御定全唐诗','yuding','','[]','孟孫唯問孝，萊子複辭官。幸遂溫凊願，其甘稼穡難。',72,'御定全唐詩/json/250.json','["孟孫唯問孝，萊子複辭官。幸遂溫凊願，其甘稼穡難。", "采芝供上藥，拾槿奉晨餐。棟裏雲藏雨，山中暑帶寒。", "非時應有筍，閑地盡生蘭。賜告承優詔，長筵永日歡。"]'),
('yuding-43','送陸鴻漸赴越','皇甫冉','唐','御定全唐诗','yuding','','[]','行隨新樹深，夢隔重江遠。迢遞風日間，蒼茫洲渚晚。',24,'御定全唐詩/json/250.json','["行隨新樹深，夢隔重江遠。迢遞風日間，蒼茫洲渚晚。"]'),
('yuding-44','送竇叔向','皇甫冉','唐','御定全唐诗','yuding','','[]','楚客怨逢秋，閑吟興非一。棄官守貧病，作賦推文律。',60,'御定全唐詩/json/250.json','["楚客怨逢秋，閑吟興非一。棄官守貧病，作賦推文律。", "樵徑未經霜，茅簷初負日。今看泛月去，偶見乘潮出。", "蔔地會為鄰，還依仲長室。"]'),
('yuding-45','題蔣道士房','皇甫冉','唐','御定全唐诗','yuding','','[]','軒窗縹緲起煙霞，誦訣存思白日斜。',32,'御定全唐詩/json/250.json','["軒窗縹緲起煙霞，誦訣存思白日斜。", "聞道昆侖有仙籍，何時青鳥送丹砂。"]'),
('yuding-46','夜集張諲所居','皇甫冉','唐','御定全唐诗','yuding','','[]','江南成久客，門館日蕭條。惟有圖書在，多傷鬢髮凋。',60,'御定全唐詩/json/250.json','["江南成久客，門館日蕭條。惟有圖書在，多傷鬢髮凋。", "諸生陪講誦，稚子給漁樵。虛室寒燈靜，空階落葉飄。", "滄洲自有趣，誰道隱須招。"]'),
('yuding-47','酬權器','皇甫冉','唐','御定全唐诗','yuding','','[]','南望江南滿山雪，此情惆悵將誰說。徒隨群吏不曾閑，',48,'御定全唐詩/json/250.json','["南望江南滿山雪，此情惆悵將誰說。徒隨群吏不曾閑，", "終日白雲應自足，明年芳草又何如。人生有懷若不展，"]'),
('yuding-48','寄劉方平大谷田家','皇甫冉','唐','御定全唐诗','yuding','','[]','故山聞獨往，樵路憶相從。冰結泉聲絕，霜清野翠濃。',48,'御定全唐詩/json/250.json','["故山聞獨往，樵路憶相從。冰結泉聲絕，霜清野翠濃。", "籬邊潁陽道，竹外少姨峰。日夕田家務，寒煙隔幾重。"]'),
('yuding-49','送雲陽少府','皇甫冉','唐','御定全唐诗','yuding','','[]','渭曲春光無遠近，池陽谷口倍芳菲。',32,'御定全唐詩/json/250.json','["渭曲春光無遠近，池陽谷口倍芳菲。", "官舍村橋來幾日，殘花寥落待君歸。"]'),
('yuding-50','魯山送別','皇甫冉','唐','御定全唐诗','yuding','','[]','淒淒遊子若飄蓬，明月清樽只暫同。',32,'御定全唐詩/json/250.json','["淒淒遊子若飄蓬，明月清樽只暫同。", "南望千山如黛色，愁君客路在其中。"]'),
('yuding-51','題高雲客舍','皇甫冉','唐','御定全唐诗','yuding','','[]','孤興日自深，浮雲非所仰。窗中西城峻，樹外東川廣。',120,'御定全唐詩/json/250.json','["孤興日自深，浮雲非所仰。窗中西城峻，樹外東川廣。", "晏起簪葛巾，閑吟倚藜杖。阮公道在醉，莊子生常養。", "五柳轉扶疏，千峰恣來往。清秋香粳獲，白露寒菜長。", "吳國滯風煙，平陵延夢想。時人趨纓弁，高鳥違羅網。", "世事徒亂紛，吾心方浩蕩。唯將山與水，處處諧真賞。"]'),
('yuding-52','臺頭寺願上人院古松下有小松裁毫末新生與纖草不辨重其有凌雲干霄之志與趙八員外裴十補闕同賦之','皇甫冉','唐','御定全唐诗','yuding','','[]','細草亦全高，秋毫乍堪比。及至幹霄日，何人複居此。',24,'御定全唐詩/json/250.json','["細草亦全高，秋毫乍堪比。及至幹霄日，何人複居此。"]'),
('yuding-53','漁子溝寄趙員外裴補闕','皇甫冉','唐','御定全唐诗','yuding','','[]','欲逐淮潮上，暫停漁子溝。相望知不見，終是屢回頭。',24,'御定全唐詩/json/250.json','["欲逐淮潮上，暫停漁子溝。相望知不見，終是屢回頭。"]'),
('yuding-54','送崔使君赴壽州','皇甫冉','唐','御定全唐诗','yuding','','[]','列郡專城分國憂，彤幨皂蓋古諸侯。仲華遇主年猶少，',40,'御定全唐詩/json/250.json','["列郡專城分國憂，彤幨皂蓋古諸侯。仲華遇主年猶少，", "千里相思如可見，淮南木落早驚秋。"]'),
('yuding-55','送謝十二判官','皇甫冉','唐','御定全唐诗','yuding','','[]','四牡驅馳千里餘，越山稠疊海林疏。',32,'御定全唐詩/json/250.json','["四牡驅馳千里餘，越山稠疊海林疏。", "不辭終日離家遠，應為劉公一紙書。"]'),
('yuding-56','送處州裴使君赴京','皇甫冉','唐','御定全唐诗','yuding','','[]','使君朝北闕，車騎發東方。別喜天書召，寧憂地脈長。',72,'御定全唐詩/json/250.json','["使君朝北闕，車騎發東方。別喜天書召，寧憂地脈長。", "山行朝複夕，水宿露為霜。秋草連秦塞，孤帆落漢陽。", "新銜趨建禮，舊位識文昌。唯有東歸客，應隨南雁翔。"]'),
('yuding-57','送田濟之揚州赴選','皇甫冉','唐','御定全唐诗','yuding','','[]','家貧不自給，求祿為荒年。調補無高位，卑棲屈此賢。',48,'御定全唐詩/json/250.json','["家貧不自給，求祿為荒年。調補無高位，卑棲屈此賢。", "江山欲霜雪，吳楚接風煙。相去誠非遠，離心亦渺然。"]'),
('yuding-58','送袁郎中破賊北歸','皇甫冉','唐','御定全唐诗','yuding','','[]','優詔親賢時獨稀，中途紫紱換征衣。黃香省闥登朝去，',40,'御定全唐詩/json/250.json','["優詔親賢時獨稀，中途紫紱換征衣。黃香省闥登朝去，", "□□□□□□□，但將詞賦奉恩輝。"]'),
('yuding-59','同李萬晚望南嶽寺懷普門上人','皇甫冉','唐','御定全唐诗','yuding','','[]','釋子身心無垢紛，獨將衣缽去人群。',32,'御定全唐詩/json/250.json','["釋子身心無垢紛，獨將衣缽去人群。", "相思晚望松林寺，唯有鐘聲出白雲。"]'),
('yuding-60','奉和獨孤中丞游法華寺','皇甫冉','唐','御定全唐诗','yuding','','[]','謝君臨郡府，越國舊山川。訪道三千界，當仁五百年。',132,'御定全唐詩/json/250.json','["謝君臨郡府，越國舊山川。訪道三千界，當仁五百年。", "岩空騶馭響，樹密旆旌連。閣影淩空壁，松聲助亂泉。", "開門得初地，伏檻接諸天。向背春光滿，樓臺古制全。", "群峰爭彩翠，百穀會風煙。香象隨僧久，祥烏報客先。", "清心乘暇日，稽首慕良緣。法證無生偈，詩成大雅篇。", "蒼生望已久，回駕獨依然。"]'),
('yuding-61','之京留別劉方平','皇甫冉','唐','御定全唐诗','yuding','','[]','客子慕儔侶，含淒整晨裝。邀歡日不足，況乃前期長。',72,'御定全唐詩/json/250.json','["客子慕儔侶，含淒整晨裝。邀歡日不足，況乃前期長。", "離袂惜嘉月，遠還勞折芳。遲回越二陵，回首但蒼茫。", "喬木清宿雨，故關愁夕陽。人言長安樂，其奈緬相望。"]'),
('yuding-62','出塞','皇甫冉','唐','御定全唐诗','yuding','','[]','吹角出塞門，前瞻即胡地。三軍盡回首，皆灑望鄉淚。',48,'御定全唐詩/json/250.json','["吹角出塞門，前瞻即胡地。三軍盡回首，皆灑望鄉淚。", "轉念關山長，行看風景異。由來征戍客，負得輕生義。"]'),
('yuding-63','赴李少府莊失路','皇甫冉','唐','御定全唐诗','yuding','','[]','君家南郭白雲連，正待情人弄石泉。',32,'御定全唐詩/json/250.json','["君家南郭白雲連，正待情人弄石泉。", "月照煙花迷客路，蒼蒼何處是伊川。"]'),
('yuding-64','雨雪','皇甫冉','唐','御定全唐诗','yuding','','[]','風沙悲久戍，雨雪更勞師。絕漠無人境，將軍苦戰時。',48,'御定全唐詩/json/250.json','["風沙悲久戍，雨雪更勞師。絕漠無人境，將軍苦戰時。", "山川迷向背，氛霧失旌旗。徒念天涯隔，中人芳草期。"]'),
('yuding-65','館陶李丞舊居','皇甫冉','唐','御定全唐诗','yuding','','[]','盛名天下挹餘芳，棄置終身不拜郎。詞藻世傳平子賦，',40,'御定全唐詩/json/250.json','["盛名天下挹餘芳，棄置終身不拜郎。詞藻世傳平子賦，", "日日青松成古木，只應來者為心傷。"]'),
('yuding-66','送劉兵曹還隴山居','皇甫冉','唐','御定全唐诗','yuding','','[]','離堂徒宴語，行子但悲辛。雖是還家路，終為隴上人。',48,'御定全唐詩/json/250.json','["離堂徒宴語，行子但悲辛。雖是還家路，終為隴上人。", "先秋雪已滿，近夏草初新。唯有聞羌笛，梅花曲裏春。"]'),
('yuding-67','同李三月夜作','皇甫冉','唐','御定全唐诗','yuding','','[]','霜風驚度雁，月露皓疏林。處處砧聲發，星河秋夜深。',24,'御定全唐詩/json/250.json','["霜風驚度雁，月露皓疏林。處處砧聲發，星河秋夜深。"]'),
('yuding-68','同裴少府安居寺對雨','皇甫冉','唐','御定全唐诗','yuding','','[]','共結尋真會，還當退食初。爐煙雲氣合，林葉雨聲餘。',48,'御定全唐詩/json/250.json','["共結尋真會，還當退食初。爐煙雲氣合，林葉雨聲餘。", "溽暑銷珍簟，浮涼入綺疏。歸心從念遠，懷此複何如。"]'),
('yuding-69','送元晟歸潛山所居','皇甫冉','唐','御定全唐诗','yuding','','[]','深山秋事早，君去複何如。裛露收新稼，迎寒葺舊廬。',48,'御定全唐詩/json/250.json','["深山秋事早，君去複何如。裛露收新稼，迎寒葺舊廬。", "題詩即招隱，作賦是閒居。別後空相憶，嵇康懶寄書。"]'),
('yuding-70','送康判官往新安賦得江路西南永','皇甫冉','唐','御定全唐诗','yuding','','[]','不向新安去，那知江路長。猿聲比廬霍，水色勝瀟湘。',48,'御定全唐詩/json/250.json','["不向新安去，那知江路長。猿聲比廬霍，水色勝瀟湘。", "驛樹收殘雨，漁家帶夕陽。何須愁旅泊，使者有輝光。"]'),
('yuding-71','宿洞靈觀','皇甫冉','唐','御定全唐诗','yuding','','[]','孤煙靈洞遠，積雪滿山寒。松柏淩高殿，莓苔封古壇。',48,'御定全唐詩/json/250.json','["孤煙靈洞遠，積雪滿山寒。松柏淩高殿，莓苔封古壇。", "客來清夜久，仙去白雲殘。明日開金籙，焚香更沐蘭。"]'),
('yuding-72','酬盧十一過宿','皇甫冉','唐','御定全唐诗','yuding','','[]','乞還方未遂，日夕望雲林。況複逢春草，何勞問此心。',48,'御定全唐詩/json/250.json','["乞還方未遂，日夕望雲林。況複逢春草，何勞問此心。", "閉門公務散，枉策故情深。遙夜他鄉酒，同君梁甫吟。"]'),
('yuding-73','酬裴十四','皇甫冉','唐','御定全唐诗','yuding','','[]','淮海各聯翩，三年方一見。素心終不易，玄發何須變。',48,'御定全唐詩/json/250.json','["淮海各聯翩，三年方一見。素心終不易，玄發何須變。", "舊國想平陵，春山滿陽羨。鄰雞莫遽唱，共惜良夜晏。"]'),
('yuding-74','彭祖井','皇甫冉','唐','御定全唐诗','yuding','','[]','上公旌節在徐方，舊井莓苔近寢堂。訪古因知彭祖宅，',40,'御定全唐詩/json/250.json','["上公旌節在徐方，舊井莓苔近寢堂。訪古因知彭祖宅，", "聞道延年如玉液，欲將調鼎獻明光。"]'),
('yuding-75','奉和對雪','皇甫冉','唐','御定全唐诗','yuding','','[]','春雪偏當夜，暄風卻變寒。庭深不復掃，城曉更宜看。',48,'御定全唐詩/json/250.json','["春雪偏當夜，暄風卻變寒。庭深不復掃，城曉更宜看。", "命酒閑令酌，披蓑晚未冠。連營鼓角動，忽似戰桑幹。"]'),
('yuding-76','送蕭獻士','皇甫冉','唐','御定全唐诗','yuding','','[]','惆悵煙郊晚，依然此送君。長河隔旅夢，浮客伴孤雲。',48,'御定全唐詩/json/250.json','["惆悵煙郊晚，依然此送君。長河隔旅夢，浮客伴孤雲。", "淇上春山直，黎陽大道分。西陵倘一吊，應有士衡文。"]'),
('yuding-77','賣藥人處得南陽朱山人書','皇甫冉','唐','御定全唐诗','yuding','','[]','賣藥何為者，逃名市井居。唯通遠山信，因致逸人書。',48,'御定全唐詩/json/250.json','["賣藥何為者，逃名市井居。唯通遠山信，因致逸人書。", "已報還丹效，全將世事疏。秋風景溪裏，蕭散寄樵漁。"]'),
('yuding-78','初出沅江夜入湖','皇甫冉','唐','御定全唐诗','yuding','','[]','放溜出江口，回瞻松栝深。不知舟中月，更引湖間心。',24,'御定全唐詩/json/250.json','["放溜出江口，回瞻松栝深。不知舟中月，更引湖間心。"]'),
('yuding-79','送裴員外往江南','皇甫冉','唐','御定全唐诗','yuding','','[]','分務江南遠，留歡幕下榮。楓林縈楚塞，水驛到湓城。',48,'御定全唐詩/json/250.json','["分務江南遠，留歡幕下榮。楓林縈楚塞，水驛到湓城。", "岸草知春晚，沙禽好夜驚。風帆幾泊處，處處暮潮清。"]'),
('yuding-80','奉和王相公早春登徐州城','皇甫冉','唐','御定全唐诗','yuding','','[]','落日憑危堞，春風似故鄉。川流通楚塞，山色繞徐方。',48,'御定全唐詩/json/250.json','["落日憑危堞，春風似故鄉。川流通楚塞，山色繞徐方。", "壁壘依寒草，旌旗動夕陽。元戎資上策，南畝起耕桑。"]'),
('yuding-81','奉和對山僧','皇甫冉','唐','御定全唐诗','yuding','','[]','吏散重門掩，僧來閉閣閑。遠心馳北闕，春興寄東山。',48,'御定全唐詩/json/250.json','["吏散重門掩，僧來閉閣閑。遠心馳北闕，春興寄東山。", "草長風光裏，鶯喧靜默間。芳辰不可住，惆悵暮禽還。"]'),
('yuding-82','奉和待勤照上人不至','皇甫冉','唐','御定全唐诗','yuding','','[]','東洛居賢相，南方待本師。旌麾儼欲動，杯錫杳仍遲。',48,'御定全唐詩/json/250.json','["東洛居賢相，南方待本師。旌麾儼欲動，杯錫杳仍遲。", "積雪迷何處，驚風泊幾時。大臣能護法，況有故山期。"]'),
('yuding-83','奉和漢祖廟下之作','皇甫冉','唐','御定全唐诗','yuding','','[]','古廟風煙積，春城車騎過。方修漢祖祀，更使沛童歌。',48,'御定全唐詩/json/250.json','["古廟風煙積，春城車騎過。方修漢祖祀，更使沛童歌。", "寢帳巢禽出，香煙水霧和。神心降福處，應在故鄉多。"]'),
('yuding-84','和朝郎中揚子玩雪寄山陰嚴維','皇甫冉','唐','御定全唐诗','yuding','','[]','凝陰晦長箔，積雪滿通川。征客寒猶去，愁人晝更眠。',48,'御定全唐詩/json/250.json','["凝陰晦長箔，積雪滿通川。征客寒猶去，愁人晝更眠。", "謝家興詠日，漢將出師年。聞有招尋興，隨君訪戴船。"]'),
('yuding-85','閒居作','皇甫冉','唐','御定全唐诗','yuding','','[]','多病辭官罷，閒居作賦成。圖書唯藥籙，飲食止藜羹。',120,'御定全唐詩/json/250.json','["多病辭官罷，閒居作賦成。圖書唯藥籙，飲食止藜羹。", "學謝淹中術，詩無鄴下名。不堪趨建禮，詎是厭承明。", "已輟金門步，方從石路行。遠山期道士，高柳覓先生。", "性懶尤因疾，家貧自省營。種苗雖尚短，谷價幸全輕。", "篇詠投康樂，壺觴就步兵。何人肯相訪，開戶一逢迎。"]'),
('yuding-86','歸渡洛水','皇甫冉','唐','御定全唐诗','yuding','','[]','暝色赴春愁，歸人南渡頭。渚煙空翠合，灘月碎光流。',48,'御定全唐詩/json/250.json','["暝色赴春愁，歸人南渡頭。渚煙空翠合，灘月碎光流。", "澧浦饒芳草，滄浪有釣舟。誰知放歌客，此意正悠悠。"]'),
('yuding-87','送鄭二員外','皇甫冉','唐','御定全唐诗','yuding','','[]','置酒竟長宵，送君登遠道。羈心看旅雁，晚泊依秋草。',72,'御定全唐詩/json/250.json','["置酒竟長宵，送君登遠道。羈心看旅雁，晚泊依秋草。", "秋草尚芊芊，離憂亦渺然。元戎辟才彥，行子犯風煙。", "風煙積惆悵，淮海殊飄蕩。明日是重陽，登高遠相望。"]'),
('yuding-88','酬崔侍禦期籍道士不至兼寄','皇甫冉','唐','御定全唐诗','yuding','','[]','一心求妙道，幾歲候真師。丹灶今何在，白雲無定期。',48,'御定全唐詩/json/250.json','["一心求妙道，幾歲候真師。丹灶今何在，白雲無定期。", "昆侖煙景絕，汗漫往還遲。君但焚香待，人間到有時。"]'),
('yuding-89','送裴陟歸常州','皇甫冉','唐','御定全唐诗','yuding','','[]','夜雨須停棹，秋風暗入衣。見君嘗北望，何事卻南歸。',24,'御定全唐詩/json/250.json','["夜雨須停棹，秋風暗入衣。見君嘗北望，何事卻南歸。"]'),
('yuding-90','贈別','皇甫冉','唐','御定全唐诗','yuding','','[]','南橋春日暮，楊柳帶青渠。不得同攜手，空成意有餘。',24,'御定全唐詩/json/250.json','["南橋春日暮，楊柳帶青渠。不得同攜手，空成意有餘。"]'),
('yuding-91','和袁郎中破賊後經剡中山水','皇甫冉','唐','御定全唐诗','yuding','','[]','武庫分帷幄，儒衣事鼓鼙。兵連越徼外，寇盡海門西。',72,'御定全唐詩/json/250.json','["武庫分帷幄，儒衣事鼓鼙。兵連越徼外，寇盡海門西。", "節比全疏勒，功當雪會稽。旌旗回剡嶺，士馬濯耶溪。", "受律梅初發，班師草未齊。行看佩金印，豈得訪丹梯。"]'),
('yuding-92','徐州送丘侍禦之越','皇甫冉','唐','御定全唐诗','yuding','','[]','時鳥催春色，離人惜歲華。遠山隨擁傳，芳草引還家。',48,'御定全唐詩/json/250.json','["時鳥催春色，離人惜歲華。遠山隨擁傳，芳草引還家。", "北固潮當闊，西陵路稍斜。縱令寒食過，猶有鏡中花。"]'),
('yuding-93','閒居','皇甫冉','唐','御定全唐诗','yuding','','[]','桃紅複含宿雨，柳綠更帶春煙。',28,'御定全唐詩/json/250.json','["桃紅複含宿雨，柳綠更帶春煙。", "花落家童未掃，鶯啼山客猶眠。"]'),
('yuding-94','送延陵陳法師赴上元','皇甫冉','唐','御定全唐诗','yuding','','[]','延陵初罷講，建業去隨緣。翻譯推多學，壇場最少年。',48,'御定全唐詩/json/250.json','["延陵初罷講，建業去隨緣。翻譯推多學，壇場最少年。", "浣衣逢野水，乞食向人煙。遍禮南朝寺，焚香古像前。"]'),
('yuding-95','賦得海邊樹','皇甫冉','唐','御定全唐诗','yuding','','[]','歷歷緣荒岸，溟溟入遠天。每同沙草發，長共水雲連。',48,'御定全唐詩/json/250.json','["歷歷緣荒岸，溟溟入遠天。每同沙草發，長共水雲連。", "搖落潮風早，離披海雨偏。故傷遊子意，多在客舟前。"]'),
('yuding-96','題昭上人房','皇甫冉','唐','御定全唐诗','yuding','','[]','沃州傳教後，百衲老空林。慮盡朝昏磬，禪隨坐臥心。',48,'御定全唐詩/json/250.json','["沃州傳教後，百衲老空林。慮盡朝昏磬，禪隨坐臥心。", "鶴飛湖草迥，門閉野雲深。地與天臺接，中峰早晚尋。"]'),
('yuding-97','送李使君赴撫州','皇甫冉','唐','御定全唐诗','yuding','','[]','遠送臨川守，還同康樂侯。歲時徒改易，今古接風流。',48,'御定全唐詩/json/250.json','["遠送臨川守，還同康樂侯。歲時徒改易，今古接風流。", "五馬嘶長道，雙旌向本州。鄉心寄西北，應上郡城樓。"]'),
('yuding-98','同樊潤州遊郡東山','皇甫冉','唐','御定全唐诗','yuding','','[]','北固多陳跡，東山複盛遊。鐃聲發大道，草色引行騶。',48,'御定全唐詩/json/250.json','["北固多陳跡，東山複盛遊。鐃聲發大道，草色引行騶。", "此地何時有，長江自古流。頻隨公府步，南客寄徐州。"]'),
('yuding-99','酬楊侍禦寺中見招','皇甫冉','唐','御定全唐诗','yuding','','[]','貧居依柳市，閒步在蓮宮。高閣宜春雨，長廊好嘯風。',36,'御定全唐詩/json/250.json','["貧居依柳市，閒步在蓮宮。高閣宜春雨，長廊好嘯風。", "誠如雙樹下，豈比一丘中。"]'),
('yuding-100','重陽日酬李觀','皇甫冉','唐','御定全唐诗','yuding','','[]','不見白衣來送酒，但令黃菊自開花。',32,'御定全唐詩/json/250.json','["不見白衣來送酒，但令黃菊自開花。", "愁看日晚良辰過，步步行尋陶令家。"]'),
('yuding-101','寄權器','皇甫冉','唐','御定全唐诗','yuding','','[]','露濕青蕪時欲晚，水流黃葉意無窮。',32,'御定全唐詩/json/250.json','["露濕青蕪時欲晚，水流黃葉意無窮。", "節近重陽念歸否，眼前籬菊帶秋風。"]'),
('yuding-102','酬李判官度梨嶺見寄','皇甫冉','唐','御定全唐诗','yuding','','[]','隴首怨西征，嶺南雁北顧。行人與流水，共向閩中去。',24,'御定全唐詩/json/250.json','["隴首怨西征，嶺南雁北顧。行人與流水，共向閩中去。"]'),
('yuding-103','送魏六侍禦葬','皇甫冉','唐','御定全唐诗','yuding','','[]','哭葬寒郊外，行將何所從。盛曹徒列柏，新墓已栽松。',120,'御定全唐詩/json/250.json','["哭葬寒郊外，行將何所從。盛曹徒列柏，新墓已栽松。", "海月同千古，江雲覆幾重。舊書曾諫獵，遺草議登封。", "疇昔輕三事，嘗期老一峰。門臨商嶺道，窗引洛城鐘。", "應積泉中恨，無因世上逢。招尋偏見厚，疏慢亦相容。", "張範唯通夢，求羊永絕蹤。誰知長卿疾，歌賦不還邛。"]'),
('yuding-104','送張道士歸茅山謁李尊師','皇甫冉','唐','御定全唐诗','yuding','','[]','向山獨有一人行，近洞應逢雙鶴迎。嘗以素書傳弟子，',40,'御定全唐詩/json/250.json','["向山獨有一人行，近洞應逢雙鶴迎。嘗以素書傳弟子，", "師事少君年歲久，欲隨旄節往層城。"]'),
('yuding-105','酬裴補闕吳寺見尋','皇甫冉','唐','御定全唐诗','yuding','','[]','東林初結構，已有晚鐘聲。窗戶背流水，房廊半架城。',48,'御定全唐詩/json/250.json','["東林初結構，已有晚鐘聲。窗戶背流水，房廊半架城。", "遠山重疊見，芳草淺深生。每與君攜手，多煩長老迎。"]'),
('yuding-106','送王相公之幽州','皇甫冉','唐','御定全唐诗','yuding','','[]','自昔蕭曹任，難兼衛霍功。勤勞無遠近，旌節屢西東。',72,'御定全唐詩/json/250.json','["自昔蕭曹任，難兼衛霍功。勤勞無遠近，旌節屢西東。", "不選三河卒，還令萬里通。雁行緣古塞，馬鬣起長風。", "遮虜關山靜，防秋鼓角雄。徒思一攀送，羸老蓽門中。"]'),
('yuding-107','題竹扇贈別','皇甫冉','唐','御定全唐诗','yuding','','[]','湘竹殊堪制，齊紈且未工。幸親芳袖日，猶帶舊林風。',48,'御定全唐詩/json/250.json','["湘竹殊堪制，齊紈且未工。幸親芳袖日，猶帶舊林風。", "掩笑歌筵裏，傳書臥閣中。竟將為別贈，甯與合歡同。"]'),
('yuding-108','歸陽羨兼送劉八長卿','皇甫冉','唐','御定全唐诗','yuding','','[]','湖上孤帆別，江南謫宦歸。前程愁更遠，臨水淚沾衣。',48,'御定全唐詩/json/250.json','["湖上孤帆別，江南謫宦歸。前程愁更遠，臨水淚沾衣。", "雲夢春山遍，瀟湘過客稀。武陵招我隱，歲晚閉柴扉。"]'),
('yuding-109','東郊迎春','皇甫冉','唐','御定全唐诗','yuding','','[]','曉見蒼龍駕，東郊春已迎。彩雲天仗合，玄象太階平。',72,'御定全唐詩/json/250.json','["曉見蒼龍駕，東郊春已迎。彩雲天仗合，玄象太階平。", "佳氣山川秀，和風政令行。句陳霜騎肅，禦道雨師清。", "律向韶陽變，人隨草木榮。遙觀上林樹，今日遇遷鶯。"]'),
('yuding-110','招隱寺送閻判官還江州','皇甫冉','唐','御定全唐诗','yuding','','[]','離別那逢秋氣悲，東林更作上方期。共知客路浮雲外，',40,'御定全唐詩/json/250.json','["離別那逢秋氣悲，東林更作上方期。共知客路浮雲外，", "借問潯陽在何處，每看潮落一相思。"]'),
('yuding-111','送李山人還','皇甫冉','唐','御定全唐诗','yuding','','[]','從來無檢束，只欲老煙霞。雞犬聲相應，深山有幾家。',24,'御定全唐詩/json/250.json','["從來無檢束，只欲老煙霞。雞犬聲相應，深山有幾家。"]'),
('yuding-112','韋中丞西廳海榴','皇甫冉','唐','御定全唐诗','yuding','','[]','海花爭讓候榴花，犯雪先開內史家。',32,'御定全唐詩/json/250.json','["海花爭讓候榴花，犯雪先開內史家。", "末客朝朝鈴閣下，從公步履玩年華。"]'),
('yuding-113','洪澤館壁見故禮部尚書題詩','皇甫冉','唐','御定全唐诗','yuding','','[]','底事洪澤壁，空留黃絹詞。年年淮水上，行客不勝悲。',24,'御定全唐詩/json/250.json','["底事洪澤壁，空留黃絹詞。年年淮水上，行客不勝悲。"]'),
('yuding-114','望南山雪懷山寺普上人','皇甫冉','唐','御定全唐诗','yuding','','[]','夜夜夢蓮宮，無由見遠公。朝來出門望，知在雪山中。',24,'御定全唐詩/json/250.json','["夜夜夢蓮宮，無由見遠公。朝來出門望，知在雪山中。"]'),
('yuding-115','送夔州班使君','皇甫冉','唐','御定全唐诗','yuding','','[]','晚日照樓邊，三軍拜峽前。白雲隨浪散，青壁與山連。',48,'御定全唐詩/json/250.json','["晚日照樓邊，三軍拜峽前。白雲隨浪散，青壁與山連。", "萬嶺岷峨雪，千家橘柚川。還如赴河內，天上去經年。"]'),
('yuding-116','尋戴處士','皇甫冉','唐','御定全唐诗','yuding','','[]','車馬長安道，誰知大隱心。蠻僧留古鏡，蜀客寄新琴。',48,'御定全唐詩/json/250.json','["車馬長安道，誰知大隱心。蠻僧留古鏡，蜀客寄新琴。", "曬藥竹齋暖，搗茶松院深。思君一相訪，殘雪似山陰。"]'),
('yuding-117','早發中嚴寺別契上人','皇甫冉','唐','御定全唐诗','yuding','','[]','蒼蒼松桂陰，殘月半西岑。素壁寒燈暗，紅爐夜火深。',48,'御定全唐詩/json/250.json','["蒼蒼松桂陰，殘月半西岑。素壁寒燈暗，紅爐夜火深。", "廚開山鼠散，鐘盡嶺猿吟。行役方如此，逢師懶話心。"]'),
('yuding-118','華清宮','皇甫冉','唐','御定全唐诗','yuding','','[]','驪岫接新豐，岧嶢駕翠空。鑿山開秘殿，隱霧閉仙宮。',72,'御定全唐詩/json/250.json','["驪岫接新豐，岧嶢駕翠空。鑿山開秘殿，隱霧閉仙宮。", "絳闕猶棲鳳，雕梁尚帶虹。溫泉曾浴日，華館舊迎風。", "肅穆瞻雲輦，沈深閉綺櫳。東郊倚望處，瑞氣靄濛濛。"]'),
('yuding-119','送孔巢父赴河南軍','皇甫冉','唐','御定全唐诗','yuding','','[]','江城相送阻煙波，況複新秋一雁過。聞道全師征北虜，',40,'御定全唐詩/json/250.json','["江城相送阻煙波，況複新秋一雁過。聞道全師征北虜，", "共許陳琳工奏記，知君名宦未蹉跎。"]'),
('yuding-120','李二侍禦丹陽東去新亭','皇甫冉','唐','御定全唐诗','yuding','','[]','姑蘇東望海陵間，幾度裁書信未還。長在府中持白簡，',40,'御定全唐詩/json/250.json','["姑蘇東望海陵間，幾度裁書信未還。長在府中持白簡，", "舊日新亭更攜手，他鄉風景亦相關。"]'),
('yuding-121','夜發沅江寄李潁川劉侍郎','皇甫冉','唐','御定全唐诗','yuding','','[]','半夜回舟入楚鄉，月明山水共蒼蒼。',32,'御定全唐詩/json/250.json','["半夜回舟入楚鄉，月明山水共蒼蒼。", "孤猿更發秋風裏，不是愁人亦斷腸。"]'),
('yuding-122','浪淘沙二首','皇甫冉','唐','御定全唐诗','yuding','','[]','蠻歌豆蔻北人愁，松雨蒲風野艇秋。',64,'御定全唐詩/json/250.json','["蠻歌豆蔻北人愁，松雨蒲風野艇秋。", "浪起鵁鶄眠不得，寒沙細細入江流。", "瀨頭細草接疏林，惡浪罾船半欲沈。", "宿鷺眠洲非舊浦，去年沙觜是江心。"]'),
('yuding-123','春思','皇甫冉','唐','御定全唐诗','yuding','','[]','鶯啼燕語報新年，馬邑龍堆路幾千。家住秦城鄰漢苑，',40,'御定全唐詩/json/250.json','["鶯啼燕語報新年，馬邑龍堆路幾千。家住秦城鄰漢苑，", "為問元戎竇車騎，何時反旆勒燕然。"]'),
('yuding-124','逢莊納因贈','皇甫冉','唐','御定全唐诗','yuding','','[]','世故還相見，天涯共向東。春歸江海上，人老別離中。',48,'御定全唐詩/json/250.json','["世故還相見，天涯共向東。春歸江海上，人老別離中。", "郡吏名何晚，沙鷗道自同。甘泉須早獻，且莫歎飄蓬。"]'),
('yuding-125','送韋山人歸鐘山所居','皇甫冉','唐','御定全唐诗','yuding','','[]','逸人歸路遠，弟子出山迎。服藥顏雖駐，耽書癖已成。',48,'御定全唐詩/json/250.json','["逸人歸路遠，弟子出山迎。服藥顏雖駐，耽書癖已成。", "柴扉度歲月，藜杖見公卿。更作儒林傳，還應有姓名。"]'),
('yuding-126','送普門上人','皇甫冉','唐','御定全唐诗','yuding','','[]','花宮難久別，道者憶千燈。殘雪入林路，深山歸寺僧。',48,'御定全唐詩/json/250.json','["花宮難久別，道者憶千燈。殘雪入林路，深山歸寺僧。", "日光依嫩草，泉響滴春冰。何用求方便，看心是一乘。"]'),
('yuding-127','怨回紇歌二首','皇甫冉','唐','御定全唐诗','yuding','','[]','白首南朝女，愁聽異域歌。收兵頡利國，飲馬胡蘆河。',96,'御定全唐詩/json/250.json','["白首南朝女，愁聽異域歌。收兵頡利國，飲馬胡蘆河。", "毳布腥膻久，穹廬歲月多。雕巢城上宿，吹笛淚滂沱。", "祖席駐征棹，開帆信候潮。隔煙桃葉泣，吹管杏花飄。", "船去鷗飛閣，人歸塵上橋。別離惆悵淚，江路濕紅蕉。"]'),
('yuding-128','句','皇甫冉','唐','御定全唐诗','yuding','','[]','微官同侍蒼龍闕，直諫偏推白馬生。',17,'御定全唐詩/json/250.json','["微官同侍蒼龍闕，直諫偏推白馬生。", "。"]'),
('yuding-0','代宛轉歌二首','劉方平','唐','御定全唐诗','yuding','','[]','星參差，明月二八燈五枝。黃鶴瑤琴將別去，',40,'御定全唐詩/json/251.json','["星參差，明月二八燈五枝。黃鶴瑤琴將別去，", "曉將近，黃姑織女銀河盡。九華錦衾無複情，"]'),
('yuding-1','烏棲曲二首','劉方平','唐','御定全唐诗','yuding','','[]','蛾眉曼臉傾城國，鳴環動佩新相識。',64,'御定全唐詩/json/251.json','["蛾眉曼臉傾城國，鳴環動佩新相識。", "銀漢斜臨白玉堂，芙蓉行障掩燈光。", "畫舸雙艚錦為纜，芙蓉花發蓮葉暗。", "門前月色映橫塘，感郎中夜度瀟湘。"]'),
('yuding-2','巫山高','劉方平','唐','御定全唐诗','yuding','','[]','楚國巫山秀，清猿日夜啼。萬重春樹合，十二碧峰齊。',48,'御定全唐詩/json/251.json','["楚國巫山秀，清猿日夜啼。萬重春樹合，十二碧峰齊。", "峽出朝雲下，江來暮雨西。陽臺歸路直，不畏向家迷。"]'),
('yuding-3','巫山神女','劉方平','唐','御定全唐诗','yuding','','[]','神女藏難識，巫山秀莫群。今宵為大雨，昨日作孤雲。',48,'御定全唐詩/json/251.json','["神女藏難識，巫山秀莫群。今宵為大雨，昨日作孤雲。", "散漫愁巴峽，徘徊戀楚君。先王為立廟，春樹幾氛氳。"]'),
('yuding-4','梅花落','劉方平','唐','御定全唐诗','yuding','','[]','新歲芳梅樹，繁花四面同。春風吹漸落，一夜幾枝空。',48,'御定全唐詩/json/251.json','["新歲芳梅樹，繁花四面同。春風吹漸落，一夜幾枝空。", "少婦今如此，長城恨不窮。莫將遼海雪，來比後庭中。"]'),
('yuding-5','銅雀妓','劉方平','唐','御定全唐诗','yuding','','[]','遺令奉君王，嚬蛾強一妝。歲移陵樹色，恩在舞衣香。',48,'御定全唐詩/json/251.json','["遺令奉君王，嚬蛾強一妝。歲移陵樹色，恩在舞衣香。", "玉座生秋氣，銅台下夕陽。淚痕沾井幹，舞袖為誰長。"]'),
('yuding-6','秋夜思','劉方平','唐','御定全唐诗','yuding','','[]','旅夢何時盡，征途望每賒。晚秋淮上水，新月楚人家。',48,'御定全唐詩/json/251.json','["旅夢何時盡，征途望每賒。晚秋淮上水，新月楚人家。", "猿嘯空山近，鴻飛極浦斜。明朝南岸去，言折桂枝花。"]'),
('yuding-7','秋夜泛舟','劉方平','唐','御定全唐诗','yuding','','[]','林塘夜發舟，蟲響荻颼颼。萬影皆因月，千聲各為秋。',48,'御定全唐詩/json/251.json','["林塘夜發舟，蟲響荻颼颼。萬影皆因月，千聲各為秋。", "歲華空複晚，鄉思不堪愁。西北浮雲外，伊川何處流。"]'),
('yuding-8','折楊枝','劉方平','唐','御定全唐诗','yuding','','[]','官渡初楊柳，風來亦動搖。武昌行路好，應為最長條。',48,'御定全唐詩/json/251.json','["官渡初楊柳，風來亦動搖。武昌行路好，應為最長條。", "葉映黃鸝夕，花繁白雪朝。年年攀折意，流恨入纖腰。"]'),
('yuding-9','班婕妤','劉方平','唐','御定全唐诗','yuding','','[]','夕殿別君王，宮深月似霜。人幽在長信，螢出向昭陽。',48,'御定全唐詩/json/251.json','["夕殿別君王，宮深月似霜。人幽在長信，螢出向昭陽。", "露浥紅蘭濕，秋凋碧樹傷。惟當合歡扇，從此篋中藏。"]'),
('yuding-10','新春','劉方平','唐','御定全唐诗','yuding','','[]','南陌春風早，東鄰曙色斜。一花開楚國，雙燕入盧家。',48,'御定全唐詩/json/251.json','["南陌春風早，東鄰曙色斜。一花開楚國，雙燕入盧家。", "眠罷梳雲髻，妝成上錦車。誰知如昔日，更浣越溪紗。"]'),
('yuding-11','寄嚴八判官','劉方平','唐','御定全唐诗','yuding','','[]','洛陽新月動秋砧，瀚海沙場天半陰。出塞能全仲叔策，',40,'御定全唐詩/json/251.json','["洛陽新月動秋砧，瀚海沙場天半陰。出塞能全仲叔策，", "懷袖未傳三歲字，相思空作隴頭吟。"]'),
('yuding-12','秋夜寄皇甫冉鄭豐','劉方平','唐','御定全唐诗','yuding','','[]','洛陽清夜白雲歸，城裏長河列宿稀。秋後見飛千里雁，',40,'御定全唐詩/json/251.json','["洛陽清夜白雲歸，城裏長河列宿稀。秋後見飛千里雁，", "借問客書何所寄，用心不啻兩鄉違。"]'),
('yuding-13','寄隴右嚴判官','劉方平','唐','御定全唐诗','yuding','','[]','副相西征重，蒼生屬望晨。還同周薄伐，不取漢和親。',192,'御定全唐詩/json/251.json','["副相西征重，蒼生屬望晨。還同周薄伐，不取漢和親。", "虜陣摧枯易，王師決勝頻。高旗臨鼓角，太白靜風塵。", "赤狄爭歸化，青羌已請臣。遙傳閫外美，盛選幕中賓。", "玉劍光初發，冰壺色自真。忠貞期報主，章服豈榮身。", "邊草含風綠，征鴻過月新。胡笳長出塞，隴水半歸秦。", "絕漠多來往，連年厭苦辛。路經西漢雪，家擲後園春。", "誰念煙雲裏，深居汝潁濱。一叢黃菊地，九日白衣人。", "松葉疏開嶺，桃花密映津。縑書若有寄，為訪許由鄰。"]'),
('yuding-14','擬娼樓節怨','劉方平','唐','御定全唐诗','yuding','','[]','上苑離離鶯度，昆明冪冪蒲生。',28,'御定全唐詩/json/251.json','["上苑離離鶯度，昆明冪冪蒲生。", "時光春華可惜，何須對鏡含情。"]'),
('yuding-15','採蓮曲','劉方平','唐','御定全唐诗','yuding','','[]','落日晴江裏，荊歌豔楚腰。採蓮從小慣，十五即乘潮。',24,'御定全唐詩/json/251.json','["落日晴江裏，荊歌豔楚腰。採蓮從小慣，十五即乘潮。"]'),
('yuding-16','長信宮','劉方平','唐','御定全唐诗','yuding','','[]','夢裏君王近，宮中河漢高。秋風能再熱，團扇不辭勞。',24,'御定全唐詩/json/251.json','["夢裏君王近，宮中河漢高。秋風能再熱，團扇不辭勞。"]'),
('yuding-17','京兆眉','劉方平','唐','御定全唐诗','yuding','','[]','新作蛾眉樣，誰將月裏同。有來凡幾日，相效滿城中。',24,'御定全唐詩/json/251.json','["新作蛾眉樣，誰將月裏同。有來凡幾日，相效滿城中。"]'),
('yuding-18','春雪','劉方平','唐','御定全唐诗','yuding','','[]','飛雪帶春風，裴回亂繞空。君看似花處，偏在洛陽東。',24,'御定全唐詩/json/251.json','["飛雪帶春風，裴回亂繞空。君看似花處，偏在洛陽東。"]'),
('yuding-19','望夫石','劉方平','唐','御定全唐诗','yuding','','[]','佳人成古石，蘚駁覆花黃。猶有春山杏，枝枝似薄妝。',24,'御定全唐詩/json/251.json','["佳人成古石，蘚駁覆花黃。猶有春山杏，枝枝似薄妝。"]'),
('yuding-20','送別','劉方平','唐','御定全唐诗','yuding','','[]','華亭霽色滿今朝，雲裏檣竿去轉遙。',32,'御定全唐詩/json/251.json','["華亭霽色滿今朝，雲裏檣竿去轉遙。", "莫怪山前深複淺，清淮一日兩回潮。"]'),
('yuding-21','夜月','劉方平','唐','御定全唐诗','yuding','','[]','更深月色半人家，北斗闌幹南斗斜。',32,'御定全唐詩/json/251.json','["更深月色半人家，北斗闌幹南斗斜。", "今夜偏知春氣暖，蟲聲新透綠窗紗。"]'),
('yuding-22','春怨','劉方平','唐','御定全唐诗','yuding','','[]','紗窗日落漸黃昏，金屋無人見淚痕。',32,'御定全唐詩/json/251.json','["紗窗日落漸黃昏，金屋無人見淚痕。", "寂寞空庭春欲晚，梨花滿地不開門。"]'),
('yuding-23','代春怨','劉方平','唐','御定全唐诗','yuding','','[]','朝日殘鶯伴妾啼，開簾只見草萋萋。',32,'御定全唐詩/json/251.json','["朝日殘鶯伴妾啼，開簾只見草萋萋。", "庭前時有東風入，楊柳千條盡向西。"]'),
('yuding-0','宣州東峰亭各賦一物得古壁苔','劉太真','唐','御定全唐诗','yuding','','[]','苒苒溫寒泉，綿綿古危壁。光含孤翠動，色與暮雲寂。',36,'御定全唐詩/json/252.json','["苒苒溫寒泉，綿綿古危壁。光含孤翠動，色與暮雲寂。", "深淺松月間，幽人自登曆。"]'),
('yuding-1','顧十二況左遷過韋蘇州房杭州韋睦州三使君皆有郡中燕集詩辭章高麗鄙夫之所仰慕顧生既至留連笑語因亦成篇以繼三君子之風焉','劉太真','唐','御定全唐诗','yuding','','[]','寵至乃不驚，罪及非無由。奔迸曆畏途，緬邈赴偏陬。',132,'御定全唐詩/json/252.json','["寵至乃不驚，罪及非無由。奔迸曆畏途，緬邈赴偏陬。", "牧此凋弊甿，屬當賦斂秋。夙興諒無補，旬暇焉敢休。", "前日懷友生，獨登城上樓。迢迢西北望，遠思不可收。", "今日車騎來，曠然銷人憂。晨迎東齋飯，晚度南溪遊。", "以我碧流水，泊君青翰舟。莫將遷客程，不為勝境留。", "飛劄謝三守，斯篇希見酬。"]'),
('yuding-2','貢院寄前主司蕭尚書聽','劉太真','唐','御定全唐诗','yuding','','[]','獨坐貢闈裏，愁心芳草生。山公昨夜事，應見此時情。',24,'御定全唐詩/json/252.json','["獨坐貢闈裏，愁心芳草生。山公昨夜事，應見此時情。"]'),
('yuding-3','東峰亭同劉太真各賦一物得垂澗藤','袁傪','唐','御定全唐诗','yuding','','[]','寒澗流不息，古藤終日垂。迎風仍未定，拂水更相宜。',36,'御定全唐詩/json/252.json','["寒澗流不息，古藤終日垂。迎風仍未定，拂水更相宜。", "新花與舊葉，惟有幽人知。"]'),
('yuding-4','喜陸侍禦破石埭草寇東峰亭賦詩','袁傪','唐','御定全唐诗','yuding','','[]','古寺東峰上，登臨興有餘。同觀白簡使，新報赤囊書。',72,'御定全唐詩/json/252.json','["古寺東峰上，登臨興有餘。同觀白簡使，新報赤囊書。", "幾處閑烽堠，千方慶裏閭。欣欣夏木長，寂寂晚煙徐。", "戰罷言歸馬，還師賦出車。因知越範蠡，湖海意何如。"]'),
('yuding-5','東峰亭各賦一物得嶺上雲','崔何','唐','御定全唐诗','yuding','','[]','佇立增遠意，中峰見孤雲。溶溶傍危石，片片宜夕曛。',36,'御定全唐詩/json/252.json','["佇立增遠意，中峰見孤雲。溶溶傍危石，片片宜夕曛。", "漸向群木盡，殘飛更氤氳。"]'),
('yuding-6','喜陸侍禦破石埭草寇東峰亭賦詩','崔何','唐','御定全唐诗','yuding','','[]','絕景西溪寺，連延近郭山。高深清扃外，行止翠微間。',72,'御定全唐詩/json/252.json','["絕景西溪寺，連延近郭山。高深清扃外，行止翠微間。", "江澈煙塵靜，川源草樹閑。中丞健步到，柱史捷書還。", "一戰清戎越，三吳變險艱。功名麟閣上，得詠入秦關。"]'),
('yuding-7','東峰亭各賦一物得幽徑石','王緯','唐','御定全唐诗','yuding','','[]','片石東溪上，陰崖剩阻修。雨餘青石靄，歲晚綠苔幽。',36,'御定全唐詩/json/252.json','["片石東溪上，陰崖剩阻修。雨餘青石靄，歲晚綠苔幽。", "從來不可轉，今日為人留。"]'),
('yuding-8','喜陸侍禦破石埭草寇東峰亭賦詩','王緯','唐','御定全唐诗','yuding','','[]','蜂蠆聚吳州，推賢奉聖憂。忠誠資上策，仁勇佐前籌。',72,'御定全唐詩/json/252.json','["蜂蠆聚吳州，推賢奉聖憂。忠誠資上策，仁勇佐前籌。", "草木成鵝鸛，戈鋋複鬥牛。戎車一戰後，殘壘五兵收。", "野靜山戎險，江平水面流。更憐羈旅客，從此罷葵丘。"]'),
('yuding-9','東峰亭各賦一物得臨軒桂','郭澹','唐','御定全唐诗','yuding','','[]','青青芳桂樹，幽陰在庭軒。向日陰還合，從風葉乍翻。',36,'御定全唐詩/json/252.json','["青青芳桂樹，幽陰在庭軒。向日陰還合，從風葉乍翻。", "共看霜雪後，終不變涼暄。"]'),
('yuding-10','喜陸侍禦破石埭草寇東峰亭賦詩','郭澹','唐','御定全唐诗','yuding','','[]','介胄鷹揚出，山林蟻聚空。忽聞飛簡報，曾是坐籌功。',72,'御定全唐詩/json/252.json','["介胄鷹揚出，山林蟻聚空。忽聞飛簡報，曾是坐籌功。", "迥夜昏氛滅，危亭眺望雄。茂勳推世上，餘興寄杯中。", "喜色煙霞改，歡忻裏巷同。幸茲尊俎末，飲至又從公。"]'),
('yuding-11','東峰亭各賦一物得林中翠','高傪','唐','御定全唐诗','yuding','','[]','杳靄無定狀，霏微常滿林。清風光不散，過雨色偏深。',36,'御定全唐詩/json/252.json','["杳靄無定狀，霏微常滿林。清風光不散，過雨色偏深。", "幽意賞難盡，終朝再招尋。"]'),
('yuding-12','東峰亭各賦一物得棲煙鳥','李岑1','唐','御定全唐诗','yuding','','[]','從來養毛羽，昔日曾飛遷。變轉對朝陽，差池棲夕煙。',36,'御定全唐詩/json/252.json','["從來養毛羽，昔日曾飛遷。變轉對朝陽，差池棲夕煙。", "遇此枝葉覆，夙舉冀沖天。"]'),
('yuding-13','東峰亭各賦一物得寒溪草','蘇','唐','御定全唐诗','yuding','','[]','冪zx溪邊草，遊人不厭看。餘芳幽處老，深色望中寒。',37,'御定全唐詩/json/252.json','["冪zx溪邊草，遊人不厭看。餘芳幽處老，深色望中寒。", "幸得陪情興，青青賞未闌。"]'),
('yuding-14','東峰亭各賦一物得陰崖竹','袁邕','唐','御定全唐诗','yuding','','[]','終歲寒苔色，寂寥幽思深。朝歌猶夕嵐，日永流清陰。',36,'御定全唐詩/json/252.json','["終歲寒苔色，寂寥幽思深。朝歌猶夕嵐，日永流清陰。", "龍鍾負煙雪，自有淩雲心。"]'),
('yuding-15','唐德明興聖廟樂章：迎神','李紓','唐','御定全唐诗','yuding','','[]','元尊九德，佐堯光宅。烈祖太宗，方周作伯。',40,'御定全唐詩/json/252.json','["元尊九德，佐堯光宅。烈祖太宗，方周作伯。", "響懷霜露，樂變金石。白雲清風，仿佛來格。"]'),
('yuding-16','唐德明興聖廟樂章：登歌奠幣','李紓','唐','御定全唐诗','yuding','','[]','四時有典，百事來祭。尊祖奉宗，嚴禋大帝。',40,'御定全唐詩/json/252.json','["四時有典，百事來祭。尊祖奉宗，嚴禋大帝。", "禮先蒼璧，奠備黝制。于萬期年，熙成帝系。"]'),
('yuding-17','唐德明興聖廟樂章：迎俎','李紓','唐','御定全唐诗','yuding','','[]','盛牲實俎，涓選休成。鼎煁陽燧，玉盥陰精。',40,'御定全唐詩/json/252.json','["盛牲實俎，涓選休成。鼎煁陽燧，玉盥陰精。", "有飶嘉豆，既和大羹。侑以清樂，細齊人情。"]'),
('yuding-18','唐德明興聖廟樂章：德明酌獻','李紓','唐','御定全唐诗','yuding','','[]','清廟奕奕，和樂雍雍。器尊犧象，禮屬宗公。',40,'御定全唐詩/json/252.json','["清廟奕奕，和樂雍雍。器尊犧象，禮屬宗公。", "白水方祼，黃流在中。謨明之德，萬古清風。"]'),
('yuding-19','唐德明興聖廟樂章：興聖酌獻','李紓','唐','御定全唐诗','yuding','','[]','閟宮靜謐，合樂周張。泰尊始獻，百末重觴。',40,'御定全唐詩/json/252.json','["閟宮靜謐，合樂周張。泰尊始獻，百末重觴。", "震澹存誠，庶幾迪嘗。遙源之祚，天漢靈長。"]'),
('yuding-20','唐德明興聖廟樂章：亞獻終獻','李紓','唐','御定全唐诗','yuding','','[]','惟清惟肅，靡聞靡見。舉備九成，俯終三獻。',40,'御定全唐詩/json/252.json','["惟清惟肅，靡聞靡見。舉備九成，俯終三獻。", "慶彰曼壽，胙撤嘉薦。瘞玉埋牲，禮神斯遍。"]'),
('yuding-21','唐德明興聖廟樂章：送神','李紓','唐','御定全唐诗','yuding','','[]','元精回復，靈貺繁滋。風灑蘭路，雲搖桂旗。',40,'御定全唐詩/json/252.json','["元精回復，靈貺繁滋。風灑蘭路，雲搖桂旗。", "高丘緬邈，涼部逶遲。瞻望靡及，纏綿永思。"]'),
('yuding-22','讓皇帝廟樂章：迎神','李紓','唐','御定全唐诗','yuding','','[]','皇矣天宗，德先王季。因心則友，克讓以位。',40,'御定全唐詩/json/252.json','["皇矣天宗，德先王季。因心則友，克讓以位。", "爰命有司，式尊前志。神其降靈，昭饗祀事。"]'),
('yuding-23','讓皇帝廟樂章：奠幣','李紓','唐','御定全唐诗','yuding','','[]','惟帝時若，去而上仙。祀用商武，樂備宮懸。',40,'御定全唐詩/json/252.json','["惟帝時若，去而上仙。祀用商武，樂備宮懸。", "白璧加薦，玄纁告虔。子孫拜後，承茲吉蠲。"]'),
('yuding-24','讓皇帝廟樂章：迎俎','李紓','唐','御定全唐诗','yuding','','[]','祀盛體薦，禮協粢盛。方周假廟，用魯純牲。',40,'御定全唐詩/json/252.json','["祀盛體薦，禮協粢盛。方周假廟，用魯純牲。", "捧撤祗敬，擊拊和鳴。受厘歸胙，既戒而平。"]'),
('yuding-25','讓皇帝廟樂章：酌獻','李紓','唐','御定全唐诗','yuding','','[]','八音具舉，三壽既盥。潔茲宗彝，瑟彼圭瓚。',40,'御定全唐詩/json/252.json','["八音具舉，三壽既盥。潔茲宗彝，瑟彼圭瓚。", "蘭肴重錯，椒醑飄散。降祚維城，永為藩翰。"]'),
('yuding-26','讓皇帝廟樂章：亞獻終獻','李紓','唐','御定全唐诗','yuding','','[]','秩禮有序，和音既同。九儀不忒，三揖將終。',40,'御定全唐詩/json/252.json','["秩禮有序，和音既同。九儀不忒，三揖將終。", "孝感藩後，相維辟公。四時之典，永永無窮。"]'),
('yuding-27','讓皇帝廟樂章：送神','李紓','唐','御定全唐诗','yuding','','[]','奠獻已事，昏昕載分。風搖雨散，靈衛絪縕。',40,'御定全唐詩/json/252.json','["奠獻已事，昏昕載分。風搖雨散，靈衛絪縕。", "龍駕帝服，已騰五雲。泮宮複閟，寂寞無聞。"]'),
('yuding-28','釋奠武成王樂章：迎神','于邵','唐','御定全唐诗','yuding','','[]','蔔畋不從，兆發非熊。乃傾荒政，爰佐一戎。盛烈載垂，',25,'御定全唐詩/json/252.json','["蔔畋不從，兆發非熊。乃傾荒政，爰佐一戎。盛烈載垂，"]'),
('yuding-29','釋奠武成王樂章：奠幣登歌','于邵','唐','御定全唐诗','yuding','','[]','管磬升，壇薌集。上公進，嘉幣執。信以通，僾如及。',48,'御定全唐詩/json/252.json','["管磬升，壇薌集。上公進，嘉幣執。信以通，僾如及。", "恢帝功，錫後邑。四維張，百度立。綿億載，邈難挹。"]'),
('yuding-30','釋奠武成王樂章：迎俎酌獻','于邵','唐','御定全唐诗','yuding','','[]','五齊絜，九牢碩。梡橛循，罍斝滌。進具物，揚鴻績。',48,'御定全唐詩/json/252.json','["五齊絜，九牢碩。梡橛循，罍斝滌。進具物，揚鴻績。", "和奏發，高靈寂。虔告終，繁祉錫。昭秩祀，永無易。"]'),
('yuding-31','釋奠武成王樂章：亞獻終獻','于邵','唐','御定全唐诗','yuding','','[]','貳觴以獻，三變其終。顧此非馨，尚達斯衷。茅縮可致，',25,'御定全唐詩/json/252.json','["貳觴以獻，三變其終。顧此非馨，尚達斯衷。茅縮可致，"]'),
('yuding-32','釋奠武成王樂章：送神','于邵','唐','御定全唐诗','yuding','','[]','明祀方終，備樂斯闋。黝纁就瘞，豆籩告撤。',40,'御定全唐詩/json/252.json','["明祀方終，備樂斯闋。黝纁就瘞，豆籩告撤。", "肸蚃尚餘，光景雲滅。返歸虛極，神心則悅。"]'),
('yuding-0','登鸛雀樓','王之渙','唐','御定全唐诗','yuding','','[]','白日依山盡，黃河入海流。欲窮千里目，更上一層樓。',24,'御定全唐詩/json/253.json','["白日依山盡，黃河入海流。欲窮千里目，更上一層樓。"]'),
('yuding-1','送別','王之渙','唐','御定全唐诗','yuding','','[]','楊柳東風樹，青青夾禦河。近來攀折苦，應為別離多。',24,'御定全唐詩/json/253.json','["楊柳東風樹，青青夾禦河。近來攀折苦，應為別離多。"]'),
('yuding-2','涼州詞二首','王之渙','唐','御定全唐诗','yuding','','[]','黃河遠上白雲間，一片孤城萬仞山。',64,'御定全唐詩/json/253.json','["黃河遠上白雲間，一片孤城萬仞山。", "羌笛何須怨楊柳，春光不度玉門關。", "單于北望拂雲堆，殺馬登壇祭幾回。", "漢家天子今神武，不肯和親歸去來。"]'),
('yuding-3','宴詞','王之渙','唐','御定全唐诗','yuding','','[]','長堤春水綠悠悠，畎入漳河一道流。',32,'御定全唐詩/json/253.json','["長堤春水綠悠悠，畎入漳河一道流。", "莫聽聲聲催去棹，桃溪淺處不勝舟。"]'),
('yuding-4','九日送別','王之渙','唐','御定全唐诗','yuding','','[]','薊庭蕭瑟故人稀，何處登高且送歸。',32,'御定全唐詩/json/253.json','["薊庭蕭瑟故人稀，何處登高且送歸。", "今日暫同芳菊酒，明朝應作斷蓬飛。"]'),
('yuding-5','晚秋石門禮拜','閻防','唐','御定全唐诗','yuding','','[]','輕策臨絕壁，招提謁金仙。舟車無由徑，岩嶠乃屬天。',96,'御定全唐詩/json/253.json','["輕策臨絕壁，招提謁金仙。舟車無由徑，岩嶠乃屬天。", "躑躅淹昃景，夷猶望新弦。石門變暝色，穀口生人煙。", "陽雁叫平楚，秋風急寒川。馳暉苦代謝，浮脆慚貞堅。", "永欲臥丘壑，息心依梵筵。誓將曆劫願，無以外物牽。"]'),
('yuding-6','百丈溪新理茅茨讀書','閻防','唐','御定全唐诗','yuding','','[]','浪跡棄人世，還山自幽獨。始傍巢由蹤，吾其獲心曲。',96,'御定全唐詩/json/253.json','["浪跡棄人世，還山自幽獨。始傍巢由蹤，吾其獲心曲。", "荒庭何所有，老樹半空腹。秋蜩鳴北林，暮鳥穿我屋。", "棲遲樂遵渚，恬曠寡所欲。開卦推盈虛，散帙攻節目。", "養閑度人事，達命知止足。不學東周儒，俟時勞伐輻。"]'),
('yuding-7','宿岸道人精舍','閻防','唐','御定全唐诗','yuding','','[]','早歲參道風，放情入寥廓。重因息心侶，遂果岩下諾。',72,'御定全唐詩/json/253.json','["早歲參道風，放情入寥廓。重因息心侶，遂果岩下諾。", "斂跡辭人間，杜門守寂寞。秋風翦蘭蕙，霜氣冷淙壑。", "山牖見然燈，竹房聞搗藥。願言舍塵事，所趣非龍蠖。"]'),
('yuding-8','夕次鹿門山作','閻防','唐','御定全唐诗','yuding','','[]','龐公嘉遁所，浪跡難追攀。浮舟暝始至，抱杖聊自閑。',108,'御定全唐詩/json/253.json','["龐公嘉遁所，浪跡難追攀。浮舟暝始至，抱杖聊自閑。", "雙岩開鹿門，百穀集珠灣。噴薄湍上水，舂容漂裏山。", "焦原不足險，梁壑未成艱。我行自春仲，夏鳥忽綿蠻。", "蕙草色已晚，客心殊倦還。遠遊非避地，訪道愛童顏。", "安能徇機巧，爭奪錐刀間。"]'),
('yuding-9','與永樂諸公夜泛黃河作','閻防','唐','御定全唐诗','yuding','','[]','煙深載酒入，但覺暮川虛。映水見山火，鳴榔聞夜漁。',48,'御定全唐詩/json/253.json','["煙深載酒入，但覺暮川虛。映水見山火，鳴榔聞夜漁。", "愛茲山水趣，忽與人世疏。無暇然官燭，中流有望舒。"]'),
('yuding-10','句','閻防','唐','御定全唐诗','yuding','','[]','熊踞庭中樹，龍蒸棟裏雲。',12,'御定全唐詩/json/253.json','["熊踞庭中樹，龍蒸棟裏雲。"]'),
('yuding-11','懷哉行','薛據','唐','御定全唐诗','yuding','','[]','明時無廢人，廣廈無棄材。良工不我顧，有用寧自媒。',144,'御定全唐詩/json/253.json','["明時無廢人，廣廈無棄材。良工不我顧，有用寧自媒。", "懷策望君門，歲晏空遲回。秦城多車馬，日夕飛塵埃。", "伐鼓千門啟，鳴珂雙闕來。我聞雷雨施，天澤罔不該。", "何意斯人徒，棄之如死灰。主好臣必效，時禁權不開。", "俗流實驕矜，得志輕草萊。文王賴多士，漢帝資群才。", "一言並拜相，片善咸居台。夫君何不遇，為泣黃金台。"]'),
('yuding-12','古興','薛據','唐','御定全唐诗','yuding','','[]','日中望雙闕，軒蓋揚飛塵。鳴佩初罷朝，自言皆近臣。',108,'御定全唐詩/json/253.json','["日中望雙闕，軒蓋揚飛塵。鳴佩初罷朝，自言皆近臣。", "光華滿道路，意氣安可親。歸來宴高堂，廣筵羅八珍。", "僕妾盡綺紈，歌舞夜達晨。四時固相代，誰能久要津。", "已看覆前車，未見易後輪。丈夫須兼濟，豈能樂一身。", "君今皆得志，肯顧憔悴人。"]'),
('yuding-13','冬夜寓居寄儲太祝','薛據','唐','御定全唐诗','yuding','','[]','自為洛陽客，夫子吾知音。愛義能下士，時人無此心。',48,'御定全唐詩/json/253.json','["自為洛陽客，夫子吾知音。愛義能下士，時人無此心。", "奈何離居夜，巢鳥飛空林。愁坐至月上，複聞南鄰砧。"]'),
('yuding-14','登秦望山','薛據','唐','御定全唐诗','yuding','','[]','南登秦望山，目極大海空。朝陽半蕩漾，晃朗天水紅。',96,'御定全唐詩/json/253.json','["南登秦望山，目極大海空。朝陽半蕩漾，晃朗天水紅。", "溪壑爭噴薄，江湖遞交通。而多漁商客，不悟歲月窮。", "振緡迎早潮，弭棹候長風。予本萍泛者，乘流任西東。", "茫茫天際帆，棲泊何時同。將尋會稽跡，從此訪任公。"]'),
('yuding-15','西陵口觀海','薛據','唐','御定全唐诗','yuding','','[]','長江漫湯湯，近海勢彌廣。在昔胚渾凝，融為百川泱。',120,'御定全唐詩/json/253.json','["長江漫湯湯，近海勢彌廣。在昔胚渾凝，融為百川泱。", "地形失端倪，天色灒滉漾。東南際萬里，極目遠無象。", "山影乍浮沉，潮波忽來往。孤帆或不見，棹歌猶想像。", "日暮長風起，客心空振盪。浦口霞未收，潭心月初上。", "林嶼幾邅回，亭皋時偃仰。歲晏訪蓬瀛，真遊非外獎。"]'),
('yuding-16','題鶴林寺','薛據','唐','御定全唐诗','yuding','','[]','道門隱形勝，向背臨法橋。松覆山殿冷，花藏溪路遙。',72,'御定全唐詩/json/253.json','["道門隱形勝，向背臨法橋。松覆山殿冷，花藏溪路遙。", "珊珊寶幡掛，焰焰明燈燒。遲日半空谷，春風連上潮。", "少憑水木興，暫忝身心調。願謝攜手客，茲山禪侶饒。"]'),
('yuding-17','初去郡齋書懷','薛據','唐','御定全唐诗','yuding','','[]','肅徒辭汝潁，懷古獨淒然。尚想文王化，猶思巢父賢。',120,'御定全唐詩/json/253.json','["肅徒辭汝潁，懷古獨淒然。尚想文王化，猶思巢父賢。", "時移多讒巧，大道竟誰傳。況是疾風起，悠悠旌旆懸。", "征鳥無返翼，歸流不停川。已經霜雪下，乃驗松柏堅。", "回首望城邑，迢迢間雲煙。志士不傷物，小人皆自妍。", "感時惟責己，在道非怨天。從此適樂土，東歸知幾年。"]'),
('yuding-18','出青門往南山下別業','薛據','唐','御定全唐诗','yuding','','[]','舊居在南山，夙駕自城闕。榛莽相蔽虧，去爾漸超忽。',96,'御定全唐詩/json/253.json','["舊居在南山，夙駕自城闕。榛莽相蔽虧，去爾漸超忽。", "散漫餘雪晴，蒼茫季冬月。寒風吹長林，白日原上沒。", "懷抱曠莫伸，相知阻胡越。弱年好棲隱，煉藥在岩窟。", "及此離垢氛，興來亦因物。末路期赤松，斯言庶不伐。"]'),
('yuding-19','泊震澤口','薛據','唐','御定全唐诗','yuding','','[]','日落草木陰，舟徒泊江汜。蒼茫萬象開，合遝聞風水。',120,'御定全唐詩/json/253.json','["日落草木陰，舟徒泊江汜。蒼茫萬象開，合遝聞風水。", "洄沿值漁翁，窈窕逢樵子。雲開天宇靜，月明照萬里。", "早雁湖上飛，晨鐘海邊起。獨坐嗟遠遊，登岸望孤洲。", "零落星欲盡，朣朧氣漸收。行藏空自秉，智識仍未周。", "伍胥既仗劍，範蠡亦乘流。歌竟鼓楫去，三江多客愁。"]'),
('yuding-20','題丹陽陶司馬廳壁','薛據','唐','御定全唐诗','yuding','','[]','高鑒清洞徹，儒風入進難。詔書增寵命，才子益能官。',48,'御定全唐詩/json/253.json','["高鑒清洞徹，儒風入進難。詔書增寵命，才子益能官。", "門帶山光晚，城臨江水寒。唯餘好文客，時得詠幽蘭。"]'),
('yuding-21','古興','薛據','唐','御定全唐诗','yuding','','[]','投珠恐見疑，抱玉但垂泣。道在君不舉，功成歎何及。',24,'御定全唐詩/json/253.json','["投珠恐見疑，抱玉但垂泣。道在君不舉，功成歎何及。"]'),
('yuding-22','早發上東門','薛據','唐','御定全唐诗','yuding','','[]','十五能文西入秦，三十無家作路人。',32,'御定全唐詩/json/253.json','["十五能文西入秦，三十無家作路人。", "時命不將明主合，布衣空惹洛陽塵。"]'),
('yuding-23','句','薛據','唐','御定全唐诗','yuding','','[]','省署開文苑，滄浪學釣翁。（《紀事》雲：「此二句據',60,'御定全唐詩/json/253.json','["省署開文苑，滄浪學釣翁。（《紀事》雲：「此二句據", "之詩也，子美懷據詩即用為句雲：「獨當省署開文苑，", "窮冬時短晷，日盡西南天。"]'),
('yuding-24','秋夕會友','姚系','唐','御定全唐诗','yuding','','[]','倦客易相失，歡遊無良辰。忽然一夕間，稍慰闔家貧。',60,'御定全唐詩/json/253.json','["倦客易相失，歡遊無良辰。忽然一夕間，稍慰闔家貧。", "白露下庭梧，孤琴始悲辛。回風入幽草，蟲響滿四鄰。", "會遇更何時，持杯重殷勤。"]'),
('yuding-25','荊山獨往','姚系','唐','御定全唐诗','yuding','','[]','宿昔山水上，抱琴聊躑躅。山遠去難窮，琴悲多斷續。',84,'御定全唐詩/json/253.json','["宿昔山水上，抱琴聊躑躅。山遠去難窮，琴悲多斷續。", "岩重丹陽樹，泉咽聞陰穀。時下白雲中，淹留秋水曲。", "秋水石欄深，潺湲如噴玉。雜芳被陰岸，墜露方消綠。", "恣此平生懷，獨遊還自足。"]'),
('yuding-26','五老峰大明觀贈隱者','姚系','唐','御定全唐诗','yuding','','[]','雲觀此山北，與君攜手稀。林端涉橫水，洞口入斜暉。',72,'御定全唐詩/json/253.json','["雲觀此山北，與君攜手稀。林端涉橫水，洞口入斜暉。", "頗覺鸞鶴邇，忽為煙霧飛。故人清和客，默會琴心微。", "丹術幸可授，青龍當未歸。悠悠平生意，此日複相違。"]'),
('yuding-27','送周願判官歸嶺南','姚系','唐','御定全唐诗','yuding','','[]','早蟬望秋鳴，夜琴怨離聲。眇然多異感，值子江山行。',96,'御定全唐詩/json/253.json','["早蟬望秋鳴，夜琴怨離聲。眇然多異感，值子江山行。", "由來重義人，感激事縱橫。往復念遐阻，淹留慕平生。", "晨奔九衢餞，暮始萬里程。山驛風月榭，海門煙霞城。", "易綃泉源近，拾翠沙漵明。蘭蕙一為贈，貧交空複情。"]'),
('yuding-28','送陸渾主簿趙宗儒之任','姚系','唐','御定全唐诗','yuding','','[]','山中眇然意，此意乃平生。常日望鳴皋，遙對洛陽城。',96,'御定全唐詩/json/253.json','["山中眇然意，此意乃平生。常日望鳴皋，遙對洛陽城。", "故人吏為隱，懷此若蓬瀛。夕氣冒岩上，晨流瀉岸明。", "存亡區中事，影響羽人情。溪寂值猿下，雲歸聞鶴聲。", "及茲春始暮，花葛正明榮。會有攜手日，悠悠去無程。"]'),
('yuding-29','楊參軍莊送宇文邈','姚系','唐','御定全唐诗','yuding','','[]','秋雲冒原隰，野鳥滿林聲。愛此田舍事，稽君車馬程。',72,'御定全唐詩/json/253.json','["秋雲冒原隰，野鳥滿林聲。愛此田舍事，稽君車馬程。", "離堂慘不喧，脈脈複盈盈。蘭葉一經霜，香銷為贈輕。", "燈光耿方寂，蟲思隱餘清。相望忽無際，如含江海情。"]'),
('yuding-30','京西遇舊識兼送往隴西','姚系','唐','御定全唐诗','yuding','','[]','蟬鳴一何急，日暮秋風樹。即此不勝愁，隴陰人更去。',36,'御定全唐詩/json/253.json','["蟬鳴一何急，日暮秋風樹。即此不勝愁，隴陰人更去。", "相逢與相失，共是亡羊路。"]'),
('yuding-31','古別離','姚系','唐','御定全唐诗','yuding','','[]','涼風已嫋嫋，露重木蘭枝。獨上高樓望，行人遠不知。',48,'御定全唐詩/json/253.json','["涼風已嫋嫋，露重木蘭枝。獨上高樓望，行人遠不知。", "輕寒入洞戶，明月滿秋池。燕去鴻方至，年年是別離。"]'),
('yuding-32','野居池上看月','姚系','唐','御定全唐诗','yuding','','[]','悠然雲間月，複此照池塘。泫露蒼茫濕，沉波澹灩光。',48,'御定全唐詩/json/253.json','["悠然雲間月，複此照池塘。泫露蒼茫濕，沉波澹灩光。", "應門當未曙，歌吹滿昭陽。遠近徒傷目，清輝靄自長。"]'),
('yuding-33','庭柳','姚系','唐','御定全唐诗','yuding','','[]','嫋嫋柳楊枝，當軒雜佩垂。交陰總共密，分條各自宜。',48,'御定全唐詩/json/253.json','["嫋嫋柳楊枝，當軒雜佩垂。交陰總共密，分條各自宜。", "因依似永久，攬結更傷離。愛此陽春色，秋風莫遽吹。"]'),
('yuding-34','硤州旅舍奉懷蘇州韋郎中','令狐峘','唐','御定全唐诗','yuding','','[]','儒服學從政，遂為塵事嬰。銜命東複西，孰堪異鄉情。',96,'御定全唐詩/json/253.json','["儒服學從政，遂為塵事嬰。銜命東複西，孰堪異鄉情。", "懷祿且懷恩，策名敢逃名。羨彼農畝人，白首親友並。", "江山入秋氣，草木凋晚榮。方塘寒露凝，旅管涼飆生。", "懿交守東吳，夢想聞頌聲。雲水方浩浩，離憂何平時。"]'),
('yuding-35','釋奠日國學觀禮聞雅頌','令狐峘','唐','御定全唐诗','yuding','','[]','肅肅先師廟，依依胄子群。滿庭陳舊禮，開戶拜清芬。',72,'御定全唐詩/json/253.json','["肅肅先師廟，依依胄子群。滿庭陳舊禮，開戶拜清芬。", "萬舞當華燭，簫韶入翠雲。頌歌清曉聽，雅吹度風聞。", "澹泊調元氣，中和美聖君。唯餘東魯客，蹈舞向南熏。"]'),
('yuding-36','釋奠日國學觀禮聞雅頌','滕珦','唐','御定全唐诗','yuding','','[]','太學時觀禮，東方曉色分。威儀何棣棣，環佩又紛紛。',72,'御定全唐詩/json/253.json','["太學時觀禮，東方曉色分。威儀何棣棣，環佩又紛紛。", "古樂從空盡，清歌幾處聞。六和成遠吹，九奏動行雲。", "聖上尊儒學，春秋奠茂勳。幸因陪齒列，聊以頌斯文。"]'),
('yuding-0','奉和聖制麟德殿燕百僚應制','常袞','唐','御定全唐诗','yuding','','[]','雲辟禦筵張，山呼聖壽長。玉闌豐瑞草，金陛立神羊。',72,'御定全唐詩/json/254.json','["雲辟禦筵張，山呼聖壽長。玉闌豐瑞草，金陛立神羊。", "台鼎資庖膳，天星奉酒漿。蠻夷陪作位，犀象舞成行。", "網已祛三面，歌因守四方。千秋不可極，花發滿宮香。"]'),
('yuding-1','晚秋集賢院即事寄徐薛二侍郎','常袞','唐','御定全唐诗','yuding','','[]','穆穆上清居，沉沉中秘書。金鋪深內殿，石甃淨寒渠。',144,'御定全唐詩/json/254.json','["穆穆上清居，沉沉中秘書。金鋪深內殿，石甃淨寒渠。", "花樹台斜倚，空煙閣半虛。縹囊披錦繡，翠軸卷瓊琚。", "墨潤冰文繭，香銷蠹字魚。翻黃桐葉老，吐白桂花初。", "舊德雙遊處，聯芳十載餘。北朝榮庾薛，西漢盛嚴徐。", "侍講親花扆，征吟步綺疏。綴簾金翡翠，賜硯玉蟾蜍。", "序秩東南遠，離憂歲月除。承明期重入，江海意何如。"]'),
('yuding-2','早秋望華清宮樹因以成詠','常袞','唐','御定全唐诗','yuding','','[]','可憐雲木叢，滿禁碧濛濛。色潤靈泉近，陰清輦路通。',120,'御定全唐詩/json/254.json','["可憐雲木叢，滿禁碧濛濛。色潤靈泉近，陰清輦路通。", "玉壇標八桂，金井識雙桐。交映凝寒露，相和起夜風。", "數枝磐石上，幾葉落雲中。燕拂宜秋霽，蟬鳴覺晝空。", "翠屏更隱見，珠綴共玲瓏。雷雨生成早，樵蘇禁令雄。", "野藤高助綠，仙果迥呈紅。惆悵繚坦暮，茲山聞暗蟲。"]'),
('yuding-3','和考功員外杪秋憶終南舊宅之作','常袞','唐','御定全唐诗','yuding','','[]','靜憶溪邊宅，知君許謝公。曉霜凝耒耜，初日照梧桐。',96,'御定全唐詩/json/254.json','["靜憶溪邊宅，知君許謝公。曉霜凝耒耜，初日照梧桐。", "澗鼠喧藤蔓，山禽竄石叢。白雲當嶺雨，黃葉繞階風。", "野果垂橋上，高泉落水中。歡榮來自間，羸賤賞曾通。", "月滿珠藏海，天晴鶴在籠。餘陰如可寄，願得隱牆東。"]'),
('yuding-4','題金吾郭將軍石洑茅堂','常袞','唐','御定全唐诗','yuding','','[]','雲戟曙沉沉，軒墀清且深。家傳成棟美，堯寵結茅心。',96,'御定全唐詩/json/254.json','["雲戟曙沉沉，軒墀清且深。家傳成棟美，堯寵結茅心。", "玉佩多依石，油幢亦在林。爐香諸洞暖，殿影眾山陰。", "草奏風生筆，筵開雪滿琴。客從龍闕至，僧自虎溪尋。", "瀟灑延清賞，周流會素襟。終朝惜塵步，一醉見華簪。"]'),
('yuding-5','登棲霞寺','常袞','唐','御定全唐诗','yuding','','[]','林香雨氣新，山寺綠無塵。遂結雲外侶，共遊天上春。',72,'御定全唐詩/json/254.json','["林香雨氣新，山寺綠無塵。遂結雲外侶，共遊天上春。", "鶴鳴金閣麗，僧語竹房鄰。待月水流急，惜花風起頻。", "何方非壞境，此地有歸人。回首空門外，皤然一幻身。"]'),
('yuding-6','逢南中使寄嶺外故人','常袞','唐','御定全唐诗','yuding','','[]','見說南來處，蒼梧指桂林。過秋天更暖，邊海日長陰。',72,'御定全唐詩/json/254.json','["見說南來處，蒼梧指桂林。過秋天更暖，邊海日長陰。", "巴路緣雲出，蠻鄉入洞深。信回人自老，夢到月應沈。", "碧水通春色，青山寄遠心。炎方難久客，為爾一沾襟。"]'),
('yuding-7','代員將軍罷戰後歸故里','常袞','唐','御定全唐诗','yuding','','[]','結髮事疆場，全生到海鄉。連雲防鐵嶺，同日破漁陽。',96,'御定全唐詩/json/254.json','["結髮事疆場，全生到海鄉。連雲防鐵嶺，同日破漁陽。", "牧馬胡天晚，移軍磧路長。枕戈眠古戍，吹角立繁霜。", "歸老勳仍在，酬恩虜未忘。獨行過邑裏，多病對農桑。", "雄劍依塵橐，兵符寄藥囊。空餘麾下將，猶逐羽林郎。"]'),
('yuding-8','詠冬瑰花','常袞','唐','御定全唐诗','yuding','','[]','獨鶴寄煙霜，雙鸞思晚芳。舊陰依謝宅，新豔出蕭牆。',96,'御定全唐詩/json/254.json','["獨鶴寄煙霜，雙鸞思晚芳。舊陰依謝宅，新豔出蕭牆。", "蝶散搖輕露，鶯銜入夕陽。雨朝勝濯錦，風夜劇焚香。", "麗日千層豔，孤霞一片光。密來驚葉少，動處覺枝長。", "布影期高賞，留春為遠方。嘗聞贈瓊玖，叨和愧升堂。"]'),
('yuding-9','句','常袞','唐','御定全唐诗','yuding','','[]','風候已應同嶺北，雲山仍喜似終南。',16,'御定全唐詩/json/254.json','["風候已應同嶺北，雲山仍喜似終南。"]'),
('yuding-10','登聖善寺閣','褚朝陽','唐','御定全唐诗','yuding','','[]','飛閣青霞裏，先秋獨早涼。天花映窗近，月桂拂簷香。',48,'御定全唐詩/json/254.json','["飛閣青霞裏，先秋獨早涼。天花映窗近，月桂拂簷香。", "華嶽三峰小，黃河一帶長。空間指歸路，煙際有垂楊。"]'),
('yuding-11','五絲','褚朝陽','唐','御定全唐诗','yuding','','[]','越人傳楚俗，截竹競縈絲。水底深休也，日中還賀之。',72,'御定全唐詩/json/254.json','["越人傳楚俗，截竹競縈絲。水底深休也，日中還賀之。", "章施文勝質，列匹美于姬。錦繡侔新段，羔羊寢舊詩。", "但誇端午節，誰薦屈原祠。把酒時伸奠，汨羅空遠而。"]'),
('yuding-12','奉上徐中書','褚朝陽','唐','御定全唐诗','yuding','','[]','中禁仙池越鳳凰，池邊詞客紫薇郎。',32,'御定全唐詩/json/254.json','["中禁仙池越鳳凰，池邊詞客紫薇郎。", "既能作頌雄風起，何不時吹蘭蕙香。"]'),
('yuding-0','小洞庭洄源亭宴四郡太守詩','蘇源明','唐','御定全唐诗','yuding','','[]','小洞庭兮牽方舟，風嫋嫋兮離平流。牽方舟兮小洞庭，',64,'御定全唐詩/json/255.json','["小洞庭兮牽方舟，風嫋嫋兮離平流。牽方舟兮小洞庭，", "馮夷逝兮護輕橈，蛟龍行兮落增潮。泊中湖兮澹而閑，", "尚君子兮壽厥身，承明主兮憂斯人。"]'),
('yuding-1','秋夜小洞庭離宴詩','蘇源明','唐','御定全唐诗','yuding','','[]','浮漲湖兮莽迢遙，川後禮兮扈予橈。橫增沃兮蓬仙延，',40,'御定全唐詩/json/255.json','["浮漲湖兮莽迢遙，川後禮兮扈予橈。橫增沃兮蓬仙延，", "夜既良兮酒且多，樂方作兮奈別何。"]'),
('yuding-2','閨情','鄭虔','唐','御定全唐诗','yuding','','[]','銀鑰開香閣，金台照夜燈。長征君自慣，獨臥妾何曾。',24,'御定全唐詩/json/255.json','["銀鑰開香閣，金台照夜燈。長征君自慣，獨臥妾何曾。"]'),
('yuding-3','古意','畢耀','唐','御定全唐诗','yuding','','[]','璿閨繡戶斜光入，千金女兒倚門立。橫波美目雖往來，',40,'御定全唐詩/json/255.json','["璿閨繡戶斜光入，千金女兒倚門立。橫波美目雖往來，", "願得侍兒為道意，後堂羅帳一相親。"]'),
('yuding-4','情人玉清歌','畢耀','唐','御定全唐诗','yuding','','[]','洛陽有人名玉清，可憐玉清如其名。善踏斜柯能獨立，',66,'御定全唐詩/json/255.json','["洛陽有人名玉清，可憐玉清如其名。善踏斜柯能獨立，", "悠悠滿天星。黃金閣上晚妝成，雲和曲中為曼聲。", "玉梯不得蹈，搖袂兩盈盈。城頭之日複何情。"]'),
('yuding-5','《贈獨孤常州','畢耀','唐','御定全唐诗','yuding','','[]','洪爐無久停，日月速若飛。忽然沖人身，飲酒不須疑。',24,'御定全唐詩/json/255.json','["洪爐無久停，日月速若飛。忽然沖人身，飲酒不須疑。"]'),
('yuding-6','奉和聖制次瓊岳應制','韋濟','唐','御定全唐诗','yuding','','[]','陸海披晴雪，千旗獵早陽。岳臨秦路險，河繞漢垣長。',48,'御定全唐詩/json/255.json','["陸海披晴雪，千旗獵早陽。岳臨秦路險，河繞漢垣長。", "行漏通鳷鵲，離宮接建章。都門信宿近，歌舞從周王。"]'),
('yuding-7','成都為客作','田澄','唐','御定全唐诗','yuding','','[]','蜀郡將之遠，城南萬里橋。衣緣鄉淚濕，貌以客愁銷。',48,'御定全唐詩/json/255.json','["蜀郡將之遠，城南萬里橋。衣緣鄉淚濕，貌以客愁銷。", "地富魚為米，山芳桂是樵。旅遊唯得酒，今日過明朝。"]'),
('yuding-8','奉和苑舍人宿直曉玩新池寄南省友','沈東美','唐','御定全唐诗','yuding','','[]','傳聞閶闔裏，寓直有神仙。史為三墳博，郎因五字遷。',144,'御定全唐詩/json/255.json','["傳聞閶闔裏，寓直有神仙。史為三墳博，郎因五字遷。", "晨臨翔鳳沼，春注躍龍泉。去似登天上，來如看鏡前。", "影搖宸翰發，波淨列星懸。既濟仍懷友，流謙欲進賢。", "彈冠聲實貴，覆被渥恩偏。溫室言雖阻，文場契獨全。", "玉珂光赫奕，朱紱氣蟬聯。興逸潘仁賦，名高謝脁篇。", "青雲仰不逮，白雪和難牽。苒苒胡為此，甘心老歲年。"]'),
('yuding-9','變律','蘇渙','唐','御定全唐诗','yuding','','[]','日月東西行，寒暑冬夏易。陰陽無停機，造化渺莫測。',228,'御定全唐詩/json/255.json','["日月東西行，寒暑冬夏易。陰陽無停機，造化渺莫測。", "開目為晨光，閉目為夜色。一開複一閉，明晦無休息。", "居然六合外，曠哉天地德。天地且不言，世人浪喧喧。", "毒蜂成一窠，高掛惡木枝。行人百步外，目斷魂亦飛。", "長安大道邊，挾彈誰家兒。右手持金丸，引滿無所疑。", "一中紛下來，勢若風雨隨。身如萬箭攢，宛轉迷所之。", "徒有疾噁心，奈何不知幾。", "養蠶為素絲，葉盡蠶不老。傾筐對空林，此意向誰道。", "一女不得織，萬夫受其寒。一夫不得意，四海行路難。", "禍亦不在大，福亦不在先。世路險孟門，吾徒當勉旃。"]'),
('yuding-10','《贈零陵僧','蘇渙','唐','御定全唐诗','yuding','','[]','張顛沒在二十年，謂言草聖無人傳。零陵沙門繼其後，',112,'御定全唐詩/json/255.json','["張顛沒在二十年，謂言草聖無人傳。零陵沙門繼其後，", "忽如裴旻舞雙劍，七星錯落纏蛟龍。又如吳生畫鬼神，", "西河舞劍氣淩雲，孤蓬自振唯有君。今日華堂看灑落，", "琅誦□句三百字，何似醉僧顛複狂。忽然告我游南溟，", "南中紙價當日貴，只恐貪泉成墨池。"]'),
('yuding-0','江南曲','劉昚虛','唐','御定全唐诗','yuding','','[]','美人何蕩漾，湖上風日長。玉手欲有贈，裴回雙明璫。',48,'御定全唐詩/json/256.json','["美人何蕩漾，湖上風日長。玉手欲有贈，裴回雙明璫。", "歌聲隨綠水，怨色起青陽。日暮還家望，雲波橫洞房。"]'),
('yuding-1','九日送人','劉昚虛','唐','御定全唐诗','yuding','','[]','海上正搖落，客中還別離。同舟去未已，遠送新相知。',48,'御定全唐詩/json/256.json','["海上正搖落，客中還別離。同舟去未已，遠送新相知。", "流水意何極，滿尊徒爾為。從來菊花節，早已醉東籬。"]'),
('yuding-2','暮秋揚子江寄孟浩然','劉昚虛','唐','御定全唐诗','yuding','','[]','木葉紛紛下，東南日煙霜。林山相晚暮，天海空青蒼。',72,'御定全唐詩/json/256.json','["木葉紛紛下，東南日煙霜。林山相晚暮，天海空青蒼。", "暝色況複久，秋聲亦何長。孤舟兼微月，獨夜仍越鄉。", "寒笛對京口，故人在襄陽。詠思勞今夕，江漢遙相望。"]'),
('yuding-3','潯陽陶氏別業','劉昚虛','唐','御定全唐诗','yuding','','[]','陶家習先隱，種柳長江邊。朝夕潯陽郭，白衣來幾年。',72,'御定全唐詩/json/256.json','["陶家習先隱，種柳長江邊。朝夕潯陽郭，白衣來幾年。", "霽雲明孤嶺，秋水澄寒天。物象自清曠，野情何綿聯。", "蕭蕭丘中賞，明宰非徒然。願守黍稷稅，歸耕東山田。"]'),
('yuding-4','登廬山峰頂寺','劉昚虛','唐','御定全唐诗','yuding','','[]','孤峰臨萬象，秋氣何高清。天際南郡出，林端西江明。',72,'御定全唐詩/json/256.json','["孤峰臨萬象，秋氣何高清。天際南郡出，林端西江明。", "山門二緇叟，振錫聞幽聲。心照有無界，業懸前後生。", "雖知真機靜，尚與愛網並。方首金門路，未遑參道情。"]'),
('yuding-5','尋東溪還湖中作','劉昚虛','唐','御定全唐诗','yuding','','[]','出山更回首，日暮清溪深。東嶺新別處，數猿叫空林。',72,'御定全唐詩/json/256.json','["出山更回首，日暮清溪深。東嶺新別處，數猿叫空林。", "昔游有初跡，此路還獨尋。幽興方在往，歸懷複為今。", "雲峰勞前意，湖水成遠心。望望已超越，坐鳴舟中琴。"]'),
('yuding-6','送韓平兼寄郭微','劉昚虛','唐','御定全唐诗','yuding','','[]','上客夜相過，小童能酤酒。即為臨水處，正值歸雁後。',84,'御定全唐詩/json/256.json','["上客夜相過，小童能酤酒。即為臨水處，正值歸雁後。", "前路望鄉山，近家見門柳。到時春未暮，風景自應有。", "餘憶東州人，經年別來久。殷勤為傳語，日夕念攜手。", "兼問前寄書，書中複達否。"]'),
('yuding-7','寄閻防','劉昚虛','唐','御定全唐诗','yuding','','[]','青冥南山口，君與緇錫鄰。深路入古寺，亂花隨暮春。',96,'御定全唐詩/json/256.json','["青冥南山口，君與緇錫鄰。深路入古寺，亂花隨暮春。", "紛紛對寂寞，往往落衣巾。松色空照水，經聲時有人。", "晚心複南望，山遠情獨親。應以修往業，亦惟立此身。", "深林度空夜，煙月資清真。莫歎文明日，彌年徒隱淪。"]'),
('yuding-8','海上詩送薛文學歸海東','劉昚虛','唐','御定全唐诗','yuding','','[]','何處歸且遠，送君東悠悠。滄溟千萬里，日夜一孤舟。',108,'御定全唐詩/json/256.json','["何處歸且遠，送君東悠悠。滄溟千萬里，日夜一孤舟。", "曠望絕國所，微茫天際愁。有時近仙境，不定若夢遊。", "或見青色古，孤山百里秋。前心方杳眇，後路勞夷猶。", "離別惜吾道，風波敬皇休。春浮花氣遠，思逐海水流。", "日暮驪歌後，永懷空滄洲。"]'),
('yuding-9','越中問海客','劉昚虛','唐','御定全唐诗','yuding','','[]','風雨滄洲暮，一帆今始歸。自雲發南海，萬里速如飛。',96,'御定全唐詩/json/256.json','["風雨滄洲暮，一帆今始歸。自雲發南海，萬里速如飛。", "初謂落何處，永將無所依。冥茫漸西見，山色越中微。", "誰念去時遠，人經此路稀。泊舟悲且泣，使我亦沾衣。", "浮海焉用說，憶鄉難久違。縱為魯連子，山路有柴扉。"]'),
('yuding-10','闕題','劉昚虛','唐','御定全唐诗','yuding','','[]','道由白雲盡，春與青溪長。時有落花至，遠隨流水香。',48,'御定全唐詩/json/256.json','["道由白雲盡，春與青溪長。時有落花至，遠隨流水香。", "閑門向山路，深柳讀書堂。幽映每白日，清輝照衣裳。"]'),
('yuding-11','寄江滔求孟六遺文','劉昚虛','唐','御定全唐诗','yuding','','[]','南望襄陽路，思君情轉親。偏知漢水廣，應與孟家鄰。',48,'御定全唐詩/json/256.json','["南望襄陽路，思君情轉親。偏知漢水廣，應與孟家鄰。", "在日貪為善，昨來聞更貧。相如有遺草，一為問家人。"]'),
('yuding-12','積雪為小山','劉昚虛','唐','御定全唐诗','yuding','','[]','飛雪伴春還，春庭曉自閑。虛心應任道，遇賞遂成山。',72,'御定全唐詩/json/256.json','["飛雪伴春還，春庭曉自閑。虛心應任道，遇賞遂成山。", "峰小形全秀，岩虛勢莫攀。以幽能皎潔，謂近可迴圈。", "孤影臨冰鏡，寒光對玉顏。不隨遲日盡，留顧歲華間。"]'),
('yuding-13','贈喬琳','劉昚虛','唐','御定全唐诗','yuding','','[]','去年上策不見收，今年寄食仍淹留。羨君有酒能共醉，',48,'御定全唐詩/json/256.json','["去年上策不見收，今年寄食仍淹留。羨君有酒能共醉，", "如今七貴方自尊，羨君不過七貴門。丈夫會應有知己，"]'),
('yuding-14','茙葵花歌','劉昚虛','唐','御定全唐诗','yuding','','[]','昨日一花開，今日一花開；今日花正好，昨日花已老。',48,'御定全唐詩/json/256.json','["昨日一花開，今日一花開；今日花正好，昨日花已老。", "人生不得長少年，莫惜床頭酤酒錢；請君有錢向酒家，"]'),
('yuding-15','句','劉昚虛','唐','御定全唐诗','yuding','','[]','歸夢如春水，悠悠繞故鄉。',24,'御定全唐詩/json/256.json','["歸夢如春水，悠悠繞故鄉。", "駐馬渡江處，望鄉待歸舟。"]'),
('yuding-0','冬夜宴蕭十丈因餞殷郭二子西上','息夫牧','唐','御定全唐诗','yuding','','[]','有琴斯鳴，於宰之庭。君子蒞止，其心孔平。政既告成，',70,'御定全唐詩/json/257.json','["有琴斯鳴，於宰之庭。君子蒞止，其心孔平。政既告成，", "聞詩聞禮，斐兮璨璨。鳴琴其怡，於潁之湄。二子翰飛，", "烘煁有煒，酒醴惟旨。喟我寤歎，籲其別矣。"]'),
('yuding-1','蟬鳴一篇五章','宋華','唐','御定全唐诗','yuding','','[]','蟬其鳴矣，於彼疏桐。庇影容跡，何所不容。嘒嘒其長，',125,'御定全唐詩/json/257.json','["蟬其鳴矣，於彼疏桐。庇影容跡，何所不容。嘒嘒其長，", "彼蟬鳴矣，于林之表。含風飲露，以樂吾道。有懷載遷，", "蟬鳴蟬鳴，幽暢乎而。肅肅爾庭，遠近涼颸。言赴高柳，", "蟬鳴伊何，時運未與。匪歎秋徂，怨斯路阻。願言莫從，", "歲之秋深，蟬其夕吟。披衣軒除，蕭蕭風林。我友來斯，"]'),
('yuding-2','寄蕭穎士補正字','鄒象先','唐','御定全唐诗','yuding','','[]','六月度開雲，三峰玩山翠。爾時黃綬屈，別後青雲致。',24,'御定全唐詩/json/257.json','["六月度開雲，三峰玩山翠。爾時黃綬屈，別後青雲致。"]'),
('yuding-3','河中晚霽','韋建','唐','御定全唐诗','yuding','','[]','湖廣舟自輕，江天欲澄霽。是時清楚望，氣色猶霾曀。',120,'御定全唐詩/json/257.json','["湖廣舟自輕，江天欲澄霽。是時清楚望，氣色猶霾曀。", "踟躕金霞白，波上日初麗。煙紅落鏡中，樹木生天際。", "杳杳涯欲斑，濛濛雲複閉。言垂星漢明，又睹寰瀛勢。", "微興從此愜，悠然不知歲。試歌滄浪清，遂覺乾坤細。", "肯念客衣薄，將期永投袂。遲回漁父間，一雁聲嘹唳。"]'),
('yuding-4','泊舟盱眙','韋建','唐','御定全唐诗','yuding','','[]','泊舟淮水次，霜降夕流清。夜久潮侵岸，天寒月近城。',48,'御定全唐詩/json/257.json','["泊舟淮水次，霜降夕流清。夜久潮侵岸，天寒月近城。", "平沙依雁宿，候館聽雞鳴。鄉國雲霄外，誰堪羈旅情。"]'),
('yuding-5','銓試後征山別業寄源侍禦','殷寅','唐','御定全唐诗','yuding','','[]','別業在征山，登高望畿甸。嚴令天地肅，城闕如何見。',132,'御定全唐詩/json/257.json','["別業在征山，登高望畿甸。嚴令天地肅，城闕如何見。", "藹藹王侯門，華軒日遊衒。幸逢休明代，山虜尚交戰。", "投策去園林，率名皆拜選。聖君性則哲，濟濟多英彥。", "裴楷能清通，山濤急推薦。謏才甘自屏，薄伎忝餘眷。", "雖承國士恩，尚乏中人援。疇昔相知者，今茲秉天憲。", "朱紱何赫赫，繡衣複蔥蒨。"]'),
('yuding-6','玄元皇帝應見賀聖祚無疆','殷寅','唐','御定全唐诗','yuding','','[]','應曆生周日，修祠表漢年。複茲秦嶺上，更似霍山前。',96,'御定全唐詩/json/257.json','["應曆生周日，修祠表漢年。複茲秦嶺上，更似霍山前。", "昔贊神功啟，今符聖祚延。已題金簡字，仍訪玉堂仙。", "睿祖光元始，曾孫體又玄。言因六夢接，慶葉九齡傳。", "北闕心超矣，南山壽固然。無由同拜慶，竊抃賀陶甄。"]'),
('yuding-7','秋怨','柳中庸','唐','御定全唐诗','yuding','','[]','玉樹起涼煙，凝情一葉前。別離傷曉鏡，搖落思秋弦。',48,'御定全唐詩/json/257.json','["玉樹起涼煙，凝情一葉前。別離傷曉鏡，搖落思秋弦。", "漢壘關山月，胡笳塞北天。不知腸斷夢，空繞幾山川。"]'),
('yuding-8','春思贈人','柳中庸','唐','御定全唐诗','yuding','','[]','紅粉當三五，青娥豔一雙。綺羅回錦陌，弦管入花江。',48,'御定全唐詩/json/257.json','["紅粉當三五，青娥豔一雙。綺羅回錦陌，弦管入花江。", "落雁驚金彈，拋杯瀉玉缸。誰知褐衣客，憔悴在書窗。"]'),
('yuding-9','幽院早春','柳中庸','唐','御定全唐诗','yuding','','[]','草短花初拆，苔青柳半黃。隔簾春雨細，高枕曉鶯長。',48,'御定全唐詩/json/257.json','["草短花初拆，苔青柳半黃。隔簾春雨細，高枕曉鶯長。", "無事含閑夢，多情識異香。欲尋蘇小小，何處覓錢塘。"]'),
('yuding-10','寒食戲贈','柳中庸','唐','御定全唐诗','yuding','','[]','春暮越江邊，春陰寒食天。杏花香麥粥，柳絮伴秋千。',48,'御定全唐詩/json/257.json','["春暮越江邊，春陰寒食天。杏花香麥粥，柳絮伴秋千。", "酒是芳菲節，人當桃李年。不知何處恨，已解入箏弦。"]'),
('yuding-11','聽箏','柳中庸','唐','御定全唐诗','yuding','','[]','抽弦促柱聽秦箏，無限秦人悲怨聲。似逐春風知柳態，',40,'御定全唐詩/json/257.json','["抽弦促柱聽秦箏，無限秦人悲怨聲。似逐春風知柳態，", "更入幾重離別恨，江南岐路洛陽城。"]'),
('yuding-12','河陽橋送別','柳中庸','唐','御定全唐诗','yuding','','[]','黃河流出有浮橋，晉國歸人此路遙。',32,'御定全唐詩/json/257.json','["黃河流出有浮橋，晉國歸人此路遙。", "若傍闌幹千里望，北風驅馬雨蕭蕭。"]'),
('yuding-13','征怨','柳中庸','唐','御定全唐诗','yuding','','[]','歲歲金河複玉關，朝朝馬策與刀環。',32,'御定全唐詩/json/257.json','["歲歲金河複玉關，朝朝馬策與刀環。", "三春白雪歸青塚，萬里黃河繞黑山。"]'),
('yuding-14','涼州曲二首','柳中庸','唐','御定全唐诗','yuding','','[]','關山萬里遠征人，一望關山淚滿巾。',64,'御定全唐詩/json/257.json','["關山萬里遠征人，一望關山淚滿巾。", "青海戍頭空有月，黃沙磧裏本無春。", "高檻連天望武威，窮陰拂地戍金微。", "九城弦管聲遙發，一夜關山雪滿飛。"]'),
('yuding-15','江行','柳中庸','唐','御定全唐诗','yuding','','[]','繁陰乍隱洲，落葉初飛浦。蕭蕭楚客帆，暮入寒江雨。',24,'御定全唐詩/json/257.json','["繁陰乍隱洲，落葉初飛浦。蕭蕭楚客帆，暮入寒江雨。"]'),
('yuding-16','丁評事宅秋夜宴集','柳中庸','唐','御定全唐诗','yuding','','[]','翠幕卷回廊，銀燈開後堂。風驚擁砌葉，月冷滿庭霜。',48,'御定全唐詩/json/257.json','["翠幕卷回廊，銀燈開後堂。風驚擁砌葉，月冷滿庭霜。", "綺席人將醉，繁弦夜未央。共憐今促席，誰道客愁長。"]'),
('yuding-17','夜渡江','柳中庸','唐','御定全唐诗','yuding','','[]','夜渚帶浮煙，蒼茫晦遠天。舟輕不覺動，纜急始知牽。',48,'御定全唐詩/json/257.json','["夜渚帶浮煙，蒼茫晦遠天。舟輕不覺動，纜急始知牽。", "聽笛遙尋岸，聞香暗識蓮。唯看去帆影，常恐客心懸。"]'),
('yuding-18','揚子途中','柳中庸','唐','御定全唐诗','yuding','','[]','楚塞望蒼然，寒林古戍邊。秋風人渡水，落日雁飛天。',24,'御定全唐詩/json/257.json','["楚塞望蒼然，寒林古戍邊。秋風人渡水，落日雁飛天。"]'),
('yuding-0','宴城東莊','崔惠童','唐','御定全唐诗','yuding','','[]','一月主人笑幾回，相逢相識且銜杯。',32,'御定全唐詩/json/258.json','["一月主人笑幾回，相逢相識且銜杯。", "眼看春色如流水，今日殘花昨日開。"]'),
('yuding-1','宴城東莊','崔敏童','唐','御定全唐诗','yuding','','[]','一年始有一年春，百歲曾無百歲人。',32,'御定全唐詩/json/258.json','["一年始有一年春，百歲曾無百歲人。", "能向花前幾回醉，十千沽酒莫辭貧。"]'),
('yuding-2','奉和聖制早登太行山中言志','苗晉卿','唐','御定全唐诗','yuding','','[]','金吾戒道清，羽騎動天聲。砥路方南絕，重岩始北征。',96,'御定全唐詩/json/258.json','["金吾戒道清，羽騎動天聲。砥路方南絕，重岩始北征。", "關樓前望遠，河邑下觀平。喜氣回輿合，祥風入旆輕。", "祝堯三老至，會禹百神迎。月令農先急，春搜禮複行。", "仍親後土祭，更理晉陽兵。不似勞車轍，空留八駿名。"]'),
('yuding-3','賦虞書歌','賈躭','唐','御定全唐诗','yuding','','[]','眾書之中虞書巧，體法自然歸大道。不同懷素只攻顛，',48,'御定全唐詩/json/258.json','["眾書之中虞書巧，體法自然歸大道。不同懷素只攻顛，", "孤青似竹更颼飀，闊白如波長浩渺。能方正，不隳倒，"]'),
('yuding-4','雲門山投龍詩','趙居貞','唐','御定全唐诗','yuding','','[]','曉登雲門山，直上一千尺。絕頂彌孤聳，盤途幾傾窄。',192,'御定全唐詩/json/258.json','["曉登雲門山，直上一千尺。絕頂彌孤聳，盤途幾傾窄。", "前對豎裂峰，下臨削成壁。陽巘靈芝秀，陰崖半天赤。", "大壑靜不波，渺溟無際極。是時雪初霽，冱寒水更積。", "披展送龍儀，甯安服狐白。沛恩惟聖主，祈福在方伯。", "三元章醮升，五域□□覿。帟幕翠微亙，機茵丹洞辟。", "祝起鳴天鼓，拜傳端素冊。霞間朱紱縈，嵐際黃裳襞。", "玉策奉誠信，仙佩俟奔驛。香氣入岫門，瑞雲出岩石。", "至誠必招感，大福旋來格。空中忽神言，帝壽萬千百。"]'),
('yuding-5','扈從回鑾應制','蕭華','唐','御定全唐诗','yuding','','[]','粵在秦京日，議乎封禪難。豈知陶唐主，道濟蒼生安。',96,'御定全唐詩/json/258.json','["粵在秦京日，議乎封禪難。豈知陶唐主，道濟蒼生安。", "惟彼烈祖事，增修實榮觀。聲名朝萬國，玉帛禮三壇。", "纂聖德重光，建元功載刊。仍開舊馳道，不記昔回鑾。", "羽衛搖晴日，弓戈生早寒。猶思檢玉處，卻望白雲端。"]'),
('yuding-6','西河郡太原守張夫人挽歌','李岑2','唐','御定全唐诗','yuding','','[]','鵲印慶仍傳，魚軒寵莫先。從夫元凱貴，訓子孟軻賢。',48,'御定全唐詩/json/258.json','["鵲印慶仍傳，魚軒寵莫先。從夫元凱貴，訓子孟軻賢。", "龍是雙歸日，鸞非獨舞年。哀榮今共盡，悽愴杜陵田。"]'),
('yuding-7','玄元皇帝應見賀聖祚無疆','李岑2','唐','御定全唐诗','yuding','','[]','皇綱歸有道，帝系祖玄元。運表南山祚，神通北極尊。',96,'御定全唐詩/json/258.json','["皇綱歸有道，帝系祖玄元。運表南山祚，神通北極尊。", "大同齊日月，興廢應乾坤。聖後趨庭禮，宗臣稽首言。", "千官欣肆覲，萬國賀深恩。錫宴雲天接，飛聲雷地喧。", "祥光浮紫閣，喜氣繞皇軒。未預承天命，空勤望帝門。"]'),
('yuding-8','複遊浯溪','元友讓','唐','御定全唐诗','yuding','','[]','昔到才三歲，今來鬢已蒼。剝苔看篆字，薙草覓書堂。',72,'御定全唐詩/json/258.json','["昔到才三歲，今來鬢已蒼。剝苔看篆字，薙草覓書堂。", "引客登臺上，呼童掃樹旁。石渠疏擁水，門徑劚叢篁。", "田地潛更主，林園盡廢荒。悲涼問耆耋，疆界指垂楊。"]'),
('yuding-9','南溪別業','蔣冽','唐','御定全唐诗','yuding','','[]','結宇依青嶂，開軒對綠疇。樹交花兩色，溪合水同流。',48,'御定全唐詩/json/258.json','["結宇依青嶂，開軒對綠疇。樹交花兩色，溪合水同流。", "竹徑春來掃，蘭尊夜不收。逍遙自得意，鼓腹醉中游。"]'),
('yuding-10','古意','蔣冽','唐','御定全唐诗','yuding','','[]','冉冉紅羅帳，開君玉樓上。畫作同心鳥，銜花兩相向。',48,'御定全唐詩/json/258.json','["冉冉紅羅帳，開君玉樓上。畫作同心鳥，銜花兩相向。", "春風正可憐，吹映綠窗前。妾意空相感，君心何處邊。"]'),
('yuding-11','台中書懷','蔣冽','唐','御定全唐诗','yuding','','[]','持憲當休明，飭躬免顛沛。直繩備豪右，正色清冠蓋。',96,'御定全唐詩/json/258.json','["持憲當休明，飭躬免顛沛。直繩備豪右，正色清冠蓋。", "寄切才恨薄，職雄班匪大。坐居三獨中，立在百僚外。", "簡牘時休暇，依然秋興多。披書唯骨鯁，循跡少閑和。", "庭樹淩霜柏，池傾萎露荷。歲寒應可見，感此遂成歌。"]'),
('yuding-12','經埋輪地','蔣冽','唐','御定全唐诗','yuding','','[]','漢家張禦史，晉國綠珠樓。時代邈已遠，共謝洛陽秋。',132,'御定全唐詩/json/258.json','["漢家張禦史，晉國綠珠樓。時代邈已遠，共謝洛陽秋。", "洛陽大道邊，舊地尚依然。下馬獨太息，擾擾城市喧。", "時人欣綠珠，詩滿金穀園。千載埋輪地，無人興一言。", "正直死猶忌，況乃未死前。汨羅有翻浪，恐是嫌屈原。", "我聞太古水，上與天相連。如何一落地，又作九曲泉。", "萬古惟高步，可以旌我賢。"]'),
('yuding-13','山行見鵲巢','蔣冽','唐','御定全唐诗','yuding','','[]','鵲巢性本高，更在西山木。朝下清泉戲，夜近明月宿。',48,'御定全唐詩/json/258.json','["鵲巢性本高，更在西山木。朝下清泉戲，夜近明月宿。", "非直避網羅，兼能免傾覆。豈憂五陵子，挾彈來相逐。"]'),
('yuding-14','巫山之陽，香溪之陰，明妃神女舊跡存焉','蔣冽','唐','御定全唐诗','yuding','','[]','神女歸巫峽，明妃入漢宮。擣衣餘石在，薦枕舊台空。',48,'御定全唐詩/json/258.json','["神女歸巫峽，明妃入漢宮。擣衣餘石在，薦枕舊台空。", "行雨有時度，溪流何日窮。至今詞賦裏，悽愴寫遺風。"]'),
('yuding-15','夜飛鵲','蔣冽','唐','御定全唐诗','yuding','','[]','北林夜方久，南月影頻移。何啻飛三匝，猶言未得枝。',24,'御定全唐詩/json/258.json','["北林夜方久，南月影頻移。何啻飛三匝，猶言未得枝。"]'),
('yuding-16','途次維揚望京口寄白下諸公','蔣渙','唐','御定全唐诗','yuding','','[]','北望情何限，南行路轉深。晚帆低荻葉，寒日下楓林。',48,'御定全唐詩/json/258.json','["北望情何限，南行路轉深。晚帆低荻葉，寒日下楓林。", "雲白蘭陵渚，煙青建業岑。江天秋向盡，無處不傷心。"]'),
('yuding-17','登棲霞寺塔','蔣渙','唐','御定全唐诗','yuding','','[]','三休尋磴道，九折步雲霓。瀍澗臨江北，郊原極海西。',48,'御定全唐詩/json/258.json','["三休尋磴道，九折步雲霓。瀍澗臨江北，郊原極海西。", "沙平瓜步出，樹遠綠楊低。南指晴天外，青峰是會稽。"]'),
('yuding-18','和徐侍郎書叢筱韻','蔣渙','唐','御定全唐诗','yuding','','[]','中禁夕沉沉，幽篁別作林。色連雞樹近，影落鳳池深。',48,'御定全唐詩/json/258.json','["中禁夕沉沉，幽篁別作林。色連雞樹近，影落鳳池深。", "為重淩霜節，能虛應物心。年年承雨露，長對紫庭陰。"]'),
('yuding-19','故太常卿贈禮部尚書李公及夫人挽歌二首','蔣渙','唐','御定全唐诗','yuding','','[]','白簡嘗持憲，黃圖複尹京。能標百郡則，威肅一朝清。',96,'御定全唐詩/json/258.json','["白簡嘗持憲，黃圖複尹京。能標百郡則，威肅一朝清。", "典秩崇三禮，臨戎振五兵。更聞傳世業，才子有高名。", "封樹遵同穴，生平此共歸。鏡埋鸞已去，泉掩鳳何飛。", "薤挽疑笳曲，松風思翟衣。揚名將寵贈，泉路滿光輝。"]'),
('yuding-20','挽湧泉寺僧懷玉','段懷然','唐','御定全唐诗','yuding','','[]','我師一念登初地，佛國笙歌兩度來。',32,'御定全唐詩/json/258.json','["我師一念登初地，佛國笙歌兩度來。", "唯有門前古槐樹，枝低只為掛銀台。"]'),
('yuding-21','辭房相公','張偁','唐','御定全唐诗','yuding','','[]','秋風颯颯雨霏霏，愁殺恓遑一布衣。',32,'御定全唐詩/json/258.json','["秋風颯颯雨霏霏，愁殺恓遑一布衣。", "辭君且作隨陽鳥，海內無家何處歸。"]'),
('yuding-22','移耶溪舊居呈陳元初校書','陳孫','唐','御定全唐诗','yuding','','[]','雞犬漁舟裏，長謠任興行。即令邀客醉，已被遠山迎。',48,'御定全唐詩/json/258.json','["雞犬漁舟裏，長謠任興行。即令邀客醉，已被遠山迎。", "書笈將非重，荷衣著甚輕。謝安無個事，忽起為蒼生。"]'),
('yuding-23','西河郡太原守張夫人挽歌','李峰','唐','御定全唐诗','yuding','','[]','鵲印慶仍傳，魚軒寵莫先。從夫元凱貴，訓子孟軻賢。',48,'御定全唐詩/json/258.json','["鵲印慶仍傳，魚軒寵莫先。從夫元凱貴，訓子孟軻賢。", "龍是雙歸日，鸞非獨舞年。哀榮今共盡，悽愴杜陵田。"]'),
('yuding-0','感懷弟妹','沈千運','唐','御定全唐诗','yuding','','[]','今日春氣暖，東風杏花拆。筋力久不如，卻羨澗中石。',144,'御定全唐詩/json/259.json','["今日春氣暖，東風杏花拆。筋力久不如，卻羨澗中石。", "神仙杳難准，中壽稀滿百。近世多夭傷，喜見鬢髮白。", "杖藜竹樹間，宛宛舊行跡。豈知林園主，卻是林園客。", "兄弟可存半，空為亡者惜。冥冥無再期，哀哀望松柏。", "骨肉能幾人，年大自疏隔。性情誰免此，與我不相易。", "唯念得爾輩，時看慰朝夕。平生茲已矣，此外盡非適。"]'),
('yuding-1','贈史修文','沈千運','唐','御定全唐诗','yuding','','[]','故人阻千里，會面非別期。握手於此地，當歡反成悲。',96,'御定全唐詩/json/259.json','["故人阻千里，會面非別期。握手於此地，當歡反成悲。", "念離宛猶昨，俄已經數期。疇昔皆少年，別來鬢如絲。", "不道舊姓名，相逢知是誰。曩遊盡鶱翥，與君仍布衣。", "豈曰無其才，命理應有時。別路漸欲少，不覺生涕洟。"]'),
('yuding-2','濮中言懷','沈千運','唐','御定全唐诗','yuding','','[]','聖朝優賢良，草澤無遺匿。人生各有命，在余胡不淑。',120,'御定全唐詩/json/259.json','["聖朝優賢良，草澤無遺匿。人生各有命，在余胡不淑。", "一生但區區，五十無寸祿。衰退當棄捐，貧賤招毀讟。", "棲棲去人世，屯躓日窮迫。不如守田園，歲晏望豐熟。", "壯年失宜盡，老大無筋力。始覺前計非，將貽後生福。", "童兒新學稼，少女未能織。顧此煩知己，終日求衣食。"]'),
('yuding-3','山中作','沈千運','唐','御定全唐诗','yuding','','[]','棲隱非別事，所願離風塵。不辭城邑游，禮樂拘束人。',84,'御定全唐詩/json/259.json','["棲隱非別事，所願離風塵。不辭城邑游，禮樂拘束人。", "邇來歸山林，庶事皆吾身。何者為形骸，誰是智與仁。", "寂寞了閒事，而後知天真。咳唾矜崇華，迂俯相屈伸。", "如何巢與由，天子不知臣。"]'),
('yuding-4','古歌','沈千運','唐','御定全唐诗','yuding','','[]','北邙不種田，但種松與柏。松柏未生處，留待市朝客。',24,'御定全唐詩/json/259.json','["北邙不種田，但種松與柏。松柏未生處，留待市朝客。"]'),
('yuding-5','別李季友','王季友1','唐','御定全唐诗','yuding','','[]','棲鳥不戀枝，喈喈在同聲。行子馳出戶，依依主人情。',60,'御定全唐詩/json/259.json','["棲鳥不戀枝，喈喈在同聲。行子馳出戶，依依主人情。", "昔時霜台鏡，醜婦羞爾形。閉匣二十年，皎潔常獨明。", "今日照離別，前途白髮生。"]'),
('yuding-6','寄韋子春','王季友1','唐','御定全唐诗','yuding','','[]','出山秋雲曙，山木已再春。食我山中藥，不憶山中人。',96,'御定全唐詩/json/259.json','["出山秋雲曙，山木已再春。食我山中藥，不憶山中人。", "山中誰余密，白髮日相親。雀鼠晝夜無，知我廚廩貧。", "依依北舍松，不厭吾南鄰。有情盡棄捐，土石為同身。", "夫子質千尋，天澤枝葉新。余以不材壽，非智免斧斤。"]'),
('yuding-7','雜詩','王季友1','唐','御定全唐诗','yuding','','[]','采山仍采隱，在山不在深。持斧事遠遊，固非匠者心。',72,'御定全唐詩/json/259.json','["采山仍采隱，在山不在深。持斧事遠遊，固非匠者心。", "翳翳青桐枝，樵爨日所侵。斧聲出岩壑，四聽無知音。", "豈為鼎下薪，當複堂上琴。鳳鳥久不棲，且與枳棘林。"]'),
('yuding-8','滑中贈崔高士瑾','王季友1','唐','御定全唐诗','yuding','','[]','夫子保藥命，外身得無咎。日月不能老，化腸為筋否。',144,'御定全唐詩/json/259.json','["夫子保藥命，外身得無咎。日月不能老，化腸為筋否。", "十年前見君，甲子過我壽。于何今相逢，華髮在我後。", "近而知其遠，少見今白首。遙信蓬萊宮，不死世世有。", "玄石采盈擔，神方秘其肘。問家惟指雲，愛氣常言酒。", "攝生固如此，履道當不朽。未能太玄同，願亦天地久。", "實腹以芝朮，賤形乃芻狗。自勉將勉餘，良藥在苦口。"]'),
('yuding-9','還山留別長安知己','王季友1','唐','御定全唐诗','yuding','','[]','出山不見家，還山見家在。山門是門前，此去長樵采。',48,'御定全唐詩/json/259.json','["出山不見家，還山見家在。山門是門前，此去長樵采。", "青溪誰招隱，白髮自相待。惟餘澗底松，依依色不改。"]'),
('yuding-10','代賀若令譽贈沈千運','王季友1','唐','御定全唐诗','yuding','','[]','相逢問姓名亦存，別時無子今有孫。山上雙松長不改，',64,'御定全唐詩/json/259.json','["相逢問姓名亦存，別時無子今有孫。山上雙松長不改，", "澗中磊磊十裏石，河上淤泥種桑麥。平坡塚墓皆我親，", "分手如何更此地，回頭不語淚潸然。"]'),
('yuding-11','酬李十六岐','王季友1','唐','御定全唐诗','yuding','','[]','煉丹文武火未成，賣藥販履俱逃名。出穀迷行洛陽道，',88,'御定全唐詩/json/259.json','["煉丹文武火未成，賣藥販履俱逃名。出穀迷行洛陽道，", "朝飲杖懸沽酒錢，暮餐囊有松花飯。于何車馬日憧憧，", "下筆新詩行滿壁，立談古人坐在席。問我草堂有臥雲，", "亦知世上公卿貴，且養丘中草木年。"]'),
('yuding-12','宿東溪李十五山亭','王季友1','唐','御定全唐诗','yuding','','[]','上山下山入山谷，溪中落日留我宿。松石依依當主人，',40,'御定全唐詩/json/259.json','["上山下山入山谷，溪中落日留我宿。松石依依當主人，", "本意由來是山水，何用相逢語舊懷。"]'),
('yuding-13','觀於舍人壁畫山水','王季友1','唐','御定全唐诗','yuding','','[]','野人宿在人家少，朝見此山謂山曉。半壁仍棲嶺上雲，',40,'御定全唐詩/json/259.json','["野人宿在人家少，朝見此山謂山曉。半壁仍棲嶺上雲，", "于公大笑向予說，小弟丹青能爾為。"]'),
('yuding-14','玉壺冰','王季友1','唐','御定全唐诗','yuding','','[]','玉壺知素結，止水複中澄。堅白能虛受，清寒得自凝。',72,'御定全唐詩/json/259.json','["玉壺知素結，止水複中澄。堅白能虛受，清寒得自凝。", "分形同曉鏡，照物掩宵燈。壁映圓光入，人驚爽氣淩。", "金罍何足貴，瑤席幾回升。正值求珪瓚，提攜共飲冰。"]'),
('yuding-15','古塞曲','王季友1','唐','御定全唐诗','yuding','','[]','進軍飛狐北，窮寇勢將變。日落沙塵昏，背河更一戰。',72,'御定全唐詩/json/259.json','["進軍飛狐北，窮寇勢將變。日落沙塵昏，背河更一戰。", "騂馬黃金勒，雕弓白羽箭。射殺左賢王，歸奏未央殿。", "欲言塞下事，天子不召見。東出咸陽門，哀哀淚如霰。"]'),
('yuding-16','野外行','於逖','唐','御定全唐诗','yuding','','[]','老病無樂事，歲秋悲更長。窮郊日蕭索，生意已蒼黃。',96,'御定全唐詩/json/259.json','["老病無樂事，歲秋悲更長。窮郊日蕭索，生意已蒼黃。", "小弟發亦白，兩男俱不強。有才且未達，況我非賢良。", "幸以朽鈍姿，野外老風霜。寒鴉噪晚景，喬木思故鄉。", "魏人宅蓬池，結網佇鱣魴。水清魚不來，歲暮空彷徨。"]'),
('yuding-17','憶舍弟','于逖','唐','御定全唐诗','yuding','','[]','衰門少兄弟，兄弟唯兩人。饑寒各流浪，感念傷我神。',84,'御定全唐詩/json/259.json','["衰門少兄弟，兄弟唯兩人。饑寒各流浪，感念傷我神。", "夏期秋未來，安知無他因。不怨別天長，但願見爾身。", "茫茫天地間，萬類各有親。安知汝與我，乖隔同胡秦。", "何時對形影，憤懣當共陳。"]'),
('yuding-18','雜詩','張彪','唐','御定全唐诗','yuding','','[]','富貴多勝事，貧賤無良圖。上德兼濟心，中才不如愚。',96,'御定全唐詩/json/259.json','["富貴多勝事，貧賤無良圖。上德兼濟心，中才不如愚。", "商者多巧智，農者爭膏腴。儒生未遇時，衣食不自如。", "久與故交別，他榮我窮居。到門懶入門，何況千里餘。", "君子有褊性，矧乃尋常徒。行行任天地，無為強親疏。"]'),
('yuding-19','神仙','張彪','唐','御定全唐诗','yuding','','[]','神仙可學無，百歲名大約。天地何蒼茫，人間半哀樂。',84,'御定全唐詩/json/259.json','["神仙可學無，百歲名大約。天地何蒼茫，人間半哀樂。", "浮生亮多惑，善事翻為惡。爭先等馳驅，中路苦瘦弱。", "長老思養壽，後生笑寂寞。五穀非長年，四氣乃靈藥。", "列子何必待，吾心滿寥廓。"]'),
('yuding-20','北游還酬孟雲卿','張彪','唐','御定全唐诗','yuding','','[]','忽忽忘前事，志願能相乖。衣馬久羸弊，誰信文與才。',84,'御定全唐詩/json/259.json','["忽忽忘前事，志願能相乖。衣馬久羸弊，誰信文與才。", "善道居貧賤，潔服蒙塵埃。行行無定心，壈坎難歸來。", "慈母憂疾疹，至家念棲哀。與君宿姻親，深見中外懷。", "俟餘惜時節，悵望臨高臺。"]'),
('yuding-21','古別離','張彪','唐','御定全唐诗','yuding','','[]','別離無遠近，事歡情亦悲。不聞車輪聲，後會將何時。',48,'御定全唐詩/json/259.json','["別離無遠近，事歡情亦悲。不聞車輪聲，後會將何時。", "去日忘寄書，來日乖前期。縱知明當返，一息千萬思。"]'),
('yuding-22','回軍跛者','趙征明','唐','御定全唐诗','yuding','','[]','既老又不全，始得離邊城。一枝假枯木，步步向南行。',84,'御定全唐詩/json/259.json','["既老又不全，始得離邊城。一枝假枯木，步步向南行。", "去時日一百，來時月一程。常恐道路旁，掩棄狐兔塋。", "所願死鄉里，到日不願生。聞此哀怨詞，念念不忍聽。", "惜無異人術，倏忽具爾形。"]'),
('yuding-23','挽歌詞','趙征明','唐','御定全唐诗','yuding','','[]','寒日蒿上明，淒淒郭東路。素車誰家子，丹旐引將去。',60,'御定全唐詩/json/259.json','["寒日蒿上明，淒淒郭東路。素車誰家子，丹旐引將去。", "原下荊棘叢，叢邊有新墓。人間痛傷別，此是長別處。", "曠野多蕭條，青松白楊樹。"]'),
('yuding-24','思歸','趙征明','唐','御定全唐诗','yuding','','[]','為別未幾日，去日如三秋。猶疑望可見，日日上高樓。',48,'御定全唐詩/json/259.json','["為別未幾日，去日如三秋。猶疑望可見，日日上高樓。", "惟見分手處，白蘋滿芳洲。寸心寧死別，不忍生離憂。"]'),
('yuding-25','泉上雨後作','元季川','唐','御定全唐诗','yuding','','[]','風雨蕩繁暑，雷息佳霽初。眾峰帶雲雨，清氣入我廬。',84,'御定全唐詩/json/259.json','["風雨蕩繁暑，雷息佳霽初。眾峰帶雲雨，清氣入我廬。", "颯颯涼飆來，臨窺愜所圖。綠蘿長新蔓，褭褭垂坐隅。", "流水複簷下，丹砂發清渠。養葛為我衣，種芋為我蔬。", "誰是畹與畦，彌漫連野蕪。"]'),
('yuding-26','登雲中','元季川','唐','御定全唐诗','yuding','','[]','灌田東山下，取樂在爾休。清興相引行，日日三四周。',60,'御定全唐詩/json/259.json','["灌田東山下，取樂在爾休。清興相引行，日日三四周。", "白鷗與我心，不厭此中游。窮覽頗有適，不極趣無幽。", "憀然歌采薇，曲盡心悠悠。"]'),
('yuding-27','山中曉興','元季川','唐','御定全唐诗','yuding','','[]','河漢降玄霜，昨來節物殊。愧無神仙姿，豈有陰陽俱。',60,'御定全唐詩/json/259.json','["河漢降玄霜，昨來節物殊。愧無神仙姿，豈有陰陽俱。", "靈鳥望不見，慨然悲高梧。華葉隨風揚，珍條雜榛蕪。", "為君寒穀吟，歎息知何如。"]'),
('yuding-28','古遠行','元季川','唐','御定全唐诗','yuding','','[]','悠悠遠行者，羈獨當時思。道與日月長，人無茅舍期。',60,'御定全唐詩/json/259.json','["悠悠遠行者，羈獨當時思。道與日月長，人無茅舍期。", "出門萬里心，誰不傷別離。縱遠當白髮，歲月悲今時。", "何況異形容，安須與爾悲。"]'),
('yuding-0','晚秋拾遺朱放訪山居','秦系','唐','御定全唐诗','yuding','','[]','不逐時人後，終年獨閉關。家中貧自樂，石上臥常閑。',48,'御定全唐詩/json/260.json','["不逐時人後，終年獨閉關。家中貧自樂，石上臥常閑。", "墜栗添新味，寒花帶老顏。侍臣當獻納，那得到空山。"]'),
('yuding-1','題女道士居','秦系','唐','御定全唐诗','yuding','','[]','不餌住雲溪，休丹罷藥畦。杏花虛結子，石髓任成泥。',48,'御定全唐詩/json/260.json','["不餌住雲溪，休丹罷藥畦。杏花虛結子，石髓任成泥。", "掃地青牛臥，栽松白鶴棲。共知仙女麗，莫是阮郎妻。"]'),
('yuding-2','山中枉張宙員外書期訪衡門','秦系','唐','御定全唐诗','yuding','','[]','常恨相知晚，朝來枉數行。臥雲驚聖代，拂石候仙郎。',48,'御定全唐詩/json/260.json','["常恨相知晚，朝來枉數行。臥雲驚聖代，拂石候仙郎。", "時果連枝熟，春醪滿甕香。貧家仍有趣，山色滿湖光。"]'),
('yuding-3','山中贈張正則評事','秦系','唐','御定全唐诗','yuding','','[]','終年常避喧，師事五千言。流水閑過院，春風與閉門。',48,'御定全唐詩/json/260.json','["終年常避喧，師事五千言。流水閑過院，春風與閉門。", "山茶邀上客，桂實落前軒。莫強教餘起，微官不足論。"]'),
('yuding-4','題鏡湖野老所居','秦系','唐','御定全唐诗','yuding','','[]','湖裏尋君去，樵風往返吹。樹喧巢鳥出，路細葑田移。',48,'御定全唐詩/json/260.json','["湖裏尋君去，樵風往返吹。樹喧巢鳥出，路細葑田移。", "漚苧成魚網，枯根是酒卮。老年唯自適，生事任群兒。"]'),
('yuding-5','早秋宿崔業居處','秦系','唐','御定全唐诗','yuding','','[]','從來席不暖，為爾便淹留。雞黍今相會，雲山昔共遊。',48,'御定全唐詩/json/260.json','["從來席不暖，為爾便淹留。雞黍今相會，雲山昔共遊。", "上簾宜晚景，臥簟覺新秋。身事何須問，餘心正四愁。"]'),
('yuding-6','贈烏程楊蘋明府','秦系','唐','御定全唐诗','yuding','','[]','策杖政成時，清溪弄釣絲。當年潘子貌，避病沈侯詩。',48,'御定全唐詩/json/260.json','["策杖政成時，清溪弄釣絲。當年潘子貌，避病沈侯詩。", "漉酒迎賓急，看花署字遲。楊梅今熟未，與我兩三枝。"]'),
('yuding-7','徐侍郎素未相識時攜酒命饌兼命諸詩客同訪會稽山居','秦系','唐','御定全唐诗','yuding','','[]','忽道仙翁至，幽人學拜迎。華簪窺甕牖，珍味代藜羹。',48,'御定全唐詩/json/260.json','["忽道仙翁至，幽人學拜迎。華簪窺甕牖，珍味代藜羹。", "洗硯魚仍戲，移樽鳥不驚。蘭亭攀敘卻，會此越中營。"]'),
('yuding-8','春日閒居三首','秦系','唐','御定全唐诗','yuding','','[]','一似桃源隱，將令過客迷。礙冠門柳長，驚夢院鶯啼。',144,'御定全唐詩/json/260.json','["一似桃源隱，將令過客迷。礙冠門柳長，驚夢院鶯啼。", "澆藥泉流細，圍棋日影低。舉家無外事，共愛草萋萋。", "長謠朝複暝，幽獨幾人知。老鶴兼雛弄，叢篁帶筍移。", "白雲將袖拂，青鏡出簷窺。邀取漁家叟，花間把酒卮。", "寂寂池亭裏，軒窗間綠苔。遊魚牽荇沒，戲鳥踏花摧。", "小徑僧尋去，高峰鹿下來。中年曾屢辟，多病複遲回。"]'),
('yuding-9','題石室山王甯所居','秦系','唐','御定全唐诗','yuding','','[]','白雲知所好，柏葉幸加餐。石鏡妻將照，仙書我借看。',48,'御定全唐詩/json/260.json','["白雲知所好，柏葉幸加餐。石鏡妻將照，仙書我借看。", "鳥來翻藥碗，猿飲怕魚竿。借問簷前樹，何枝曾掛冠。"]'),
('yuding-10','送王道士','秦系','唐','御定全唐诗','yuding','','[]','真人俄整舄，雙鶴屢飛翔。恐入壺中住，須傳肘後方。',48,'御定全唐詩/json/260.json','["真人俄整舄，雙鶴屢飛翔。恐入壺中住，須傳肘後方。", "霓裳雲氣潤，石徑術苗香。一去何時見，仙家日月長。"]'),
('yuding-11','將移耶溪舊居留贈嚴維秘書','秦系','唐','御定全唐诗','yuding','','[]','雞犬漁舟裏，長謠任興行。那邀落日醉，已被遠山迎。',48,'御定全唐詩/json/260.json','["雞犬漁舟裏，長謠任興行。那邀落日醉，已被遠山迎。", "書篋將非重，荷衣著甚輕。謝安無個事，忽起為蒼生。"]'),
('yuding-12','秋日過僧惟則故院','秦系','唐','御定全唐诗','yuding','','[]','衰草經行處，微燈舊道場。門人失譚柄，野鳥上禪床。',48,'御定全唐詩/json/260.json','["衰草經行處，微燈舊道場。門人失譚柄，野鳥上禪床。", "科鬥書空古，栴檀缽自香。今朝數行淚，卻灑約公房。"]'),
('yuding-13','山中奉寄錢起員外兼簡苗發員外','秦系','唐','御定全唐诗','yuding','','[]','空山歲計是胡麻，窮海無梁泛一槎。稚子唯能覓梨栗，',40,'御定全唐詩/json/260.json','["空山歲計是胡麻，窮海無梁泛一槎。稚子唯能覓梨栗，", "借問省中何水部，今人幾個屬詩家。"]'),
('yuding-14','獻薛僕射','秦系','唐','御定全唐诗','yuding','','[]','由來那敢議輕肥，散發行歌自采薇。逋客未能忘野興，',40,'御定全唐詩/json/260.json','["由來那敢議輕肥，散發行歌自采薇。逋客未能忘野興，", "更乞大賢容小隱，益看愚谷有光輝。"]'),
('yuding-15','鮑防員外見尋因書情呈贈','秦系','唐','御定全唐诗','yuding','','[]','少小為儒不自強，如今懶複見侯王。覽鏡已知身漸老，',40,'御定全唐詩/json/260.json','["少小為儒不自強，如今懶複見侯王。覽鏡已知身漸老，", "猶有郎官來問疾，時人莫道我佯狂。"]'),
('yuding-16','寄浙東皇甫中丞','秦系','唐','御定全唐诗','yuding','','[]','閑閑麋鹿或相隨，一兩年來鬢欲衰。琴硯共依春酒甕，',40,'御定全唐詩/json/260.json','["閑閑麋鹿或相隨，一兩年來鬢欲衰。琴硯共依春酒甕，", "久帶紗巾仍藉草，山中那得見朝儀。"]'),
('yuding-17','題章野人山居','秦系','唐','御定全唐诗','yuding','','[]','帶郭茅亭詩興饒，回看一曲倚危橋。門前山色能深淺，',40,'御定全唐詩/json/260.json','["帶郭茅亭詩興饒，回看一曲倚危橋。門前山色能深淺，", "向此隱來經幾載，如今已是漢家朝。"]'),
('yuding-18','山中枉皇甫溫大夫見招書','秦系','唐','御定全唐诗','yuding','','[]','十年木屐步苔痕，石上松間水自喧。三辟草堂仍被褐，',40,'御定全唐詩/json/260.json','["十年木屐步苔痕，石上松間水自喧。三辟草堂仍被褐，", "亞相已能憐潦倒，山花笑處莫啼猿。"]'),
('yuding-19','題茅山李尊師山居','秦系','唐','御定全唐诗','yuding','','[]','天師百歲少如童，不到山中竟不逢。洗藥每臨新瀑水，',40,'御定全唐詩/json/260.json','["天師百歲少如童，不到山中竟不逢。洗藥每臨新瀑水，", "此去人寰今遠近，回看去壑一重重。"]'),
('yuding-20','耶溪書懷寄劉長卿員外','秦系','唐','御定全唐诗','yuding','','[]','時人多笑樂幽棲，晚起閑行獨杖藜。雲色卷舒前後嶺，',40,'御定全唐詩/json/260.json','["時人多笑樂幽棲，晚起閑行獨杖藜。雲色卷舒前後嶺，", "擬共釣竿長往復，嚴陵灘上勝耶溪。"]'),
('yuding-21','山中崔大夫有書相問','秦系','唐','御定全唐诗','yuding','','[]','客在煙霞裏，閑閑逐狎鷗。終年常裸足，連日半蓬頭。',96,'御定全唐詩/json/260.json','["客在煙霞裏，閑閑逐狎鷗。終年常裸足，連日半蓬頭。", "帶月乘漁艇，迎寒綻鹿裘。已於人事少，多被掛冠留。", "素業堆千卷，清風至一丘。蒼黃倒藜杖，傴僂睹銀鉤。", "跡愧巢由隱，才非管樂儔。從來自多病，不是傲王侯。"]'),
('yuding-22','張建封大夫奏系為校書郎因寄此作','秦系','唐','御定全唐诗','yuding','','[]','久是煙霞客，潭深釣得魚。不知芸閣上，遺校幾多書。',24,'御定全唐詩/json/260.json','["久是煙霞客，潭深釣得魚。不知芸閣上，遺校幾多書。"]'),
('yuding-23','會稽山居寄薛播侍郎袁高給事高參舍人','秦系','唐','御定全唐诗','yuding','','[]','稷契今為相，明君複為堯。寧知買臣困，猶負會稽樵。',24,'御定全唐詩/json/260.json','["稷契今為相，明君複為堯。寧知買臣困，猶負會稽樵。"]'),
('yuding-24','閒居覽史','秦系','唐','御定全唐诗','yuding','','[]','長策胸中不復論，荷衣藍縷閉柴門。',32,'御定全唐詩/json/260.json','["長策胸中不復論，荷衣藍縷閉柴門。", "當時漢祖無三傑，爭得咸陽與子孫。"]'),
('yuding-25','山中贈耿拾遺湋兼兩省故人','秦系','唐','御定全唐诗','yuding','','[]','數片荷衣不蔽身，青山白鳥豈知貧。',32,'御定全唐詩/json/260.json','["數片荷衣不蔽身，青山白鳥豈知貧。", "如今非是秦時世，更隱桃花亦笑人。"]'),
('yuding-26','秋日送僧志幽歸山寺','秦系','唐','御定全唐诗','yuding','','[]','禪室繩床在翠微，松間荷笠一僧歸。',32,'御定全唐詩/json/260.json','["禪室繩床在翠微，松間荷笠一僧歸。", "磬聲寂曆宜秋夜，手冷燈前自衲衣。"]'),
('yuding-27','題僧明惠房','秦系','唐','御定全唐诗','yuding','','[]','簷前朝暮雨添花，八十真僧飯一麻。',32,'御定全唐詩/json/260.json','["簷前朝暮雨添花，八十真僧飯一麻。", "入定幾時將出定，不知巢燕汙袈裟。"]'),
('yuding-28','答泉州薛播使君重陽日贈酒','秦系','唐','御定全唐诗','yuding','','[]','欲強登高無力也，籬邊黃菊為誰開。',32,'御定全唐詩/json/260.json','["欲強登高無力也，籬邊黃菊為誰開。", "共知不是潯陽郡，那得王弘送酒來。"]'),
('yuding-29','題洪道士山院','秦系','唐','御定全唐诗','yuding','','[]','霞外主人門不扃，數株桃樹藥囊青。',32,'御定全唐詩/json/260.json','["霞外主人門不扃，數株桃樹藥囊青。", "閑行池畔隨孤鶴，若問多應道姓丁。"]'),
('yuding-30','期王煉師不至','秦系','唐','御定全唐诗','yuding','','[]','黃精蒸罷洗瓊杯，林下從留石上苔。',32,'御定全唐詩/json/260.json','["黃精蒸罷洗瓊杯，林下從留石上苔。", "昨日圍棋未終局，多乘白鶴下山來。"]'),
('yuding-31','題贈張道士山居','秦系','唐','御定全唐诗','yuding','','[]','磐石垂蘿即是家，回頭猶看五枝花。',32,'御定全唐詩/json/260.json','["磐石垂蘿即是家，回頭猶看五枝花。", "松間寂寂無煙火，應服朝來一片霞。"]'),
('yuding-32','山中書懷寄張建封大夫','秦系','唐','御定全唐诗','yuding','','[]','昨日年催白髮新，身如麋鹿不知貧。',32,'御定全唐詩/json/260.json','["昨日年催白髮新，身如麋鹿不知貧。", "時時亦被群兒笑，賴有南山四老人。"]'),
('yuding-33','山中贈諸暨丹丘明府','秦系','唐','御定全唐诗','yuding','','[]','荷衣半破帶莓苔，笑向陶潛酒甕開。',32,'御定全唐詩/json/260.json','["荷衣半破帶莓苔，笑向陶潛酒甕開。", "縱醉還須上山去，白雲那肯下山來。"]'),
('yuding-34','奉寄晝公','秦系','唐','御定全唐诗','yuding','','[]','蓑笠雙童傍酒船，湖山相引到房前。',32,'御定全唐詩/json/260.json','["蓑笠雙童傍酒船，湖山相引到房前。", "團蕉何事教人見，暫借空床守坐禪。"]'),
('yuding-35','宿雲門上方','秦系','唐','御定全唐诗','yuding','','[]','禪室遙看峰頂頭，白雲東去水長流。',32,'御定全唐詩/json/260.json','["禪室遙看峰頂頭，白雲東去水長流。", "松間倘許幽人住，不更將錢買沃州。"]'),
('yuding-36','即事奉呈郎中韋使君','秦系','唐','御定全唐诗','yuding','','[]','久臥雲間已息機，青袍忽著狎鷗飛。',32,'御定全唐詩/json/260.json','["久臥雲間已息機，青袍忽著狎鷗飛。", "詩興到來無一事，郡中今有謝玄暉。"]'),
('yuding-37','曉雞','秦系','唐','御定全唐诗','yuding','','[]','黯黯嚴城罷鼓鼙，數聲相續出寒棲。',32,'御定全唐詩/json/260.json','["黯黯嚴城罷鼓鼙，數聲相續出寒棲。", "不嫌驚破紗窗夢，卻恐為妖半夜啼。"]'),
('yuding-0','寄李白','任華','唐','御定全唐诗','yuding','','[]','古來文章有能奔逸氣，聳高格，清人心神，驚人魂魄。',265,'御定全唐詩/json/261.json','["古來文章有能奔逸氣，聳高格，清人心神，驚人魂魄。", "我聞當今有李白，大獵賦，鴻猷文；嗤長卿，笑子雲。", "班張所作瑣細不入耳，未知卿雲得在嗤笑限。登廬山，", "登天臺，望渤海，雲垂大鵬飛，山壓巨鼇背，", "中間聞道在長安，及餘戾止，君已江東訪元丹，", "見說往年在翰林，胸中矛戟何森森。新詩傳在宮人口，", "承恩召入凡幾回，待詔歸來仍半醉。權臣妒盛名，", "且向東山為外臣，諸侯交迓馳朱輪。白璧一雙買交者，", "繁花越臺上，細柳吳宮側。綠水青山知有君，", "莊周萬物外，範蠡五湖間。人傳訪道滄海上，", "伊餘每欲乘興往相尋，江湖擁隔勞寸心。", "今朝忽遇東飛翼，寄此一章表胸臆。倘能報我一片言，"]'),
('yuding-1','寄杜拾遺','任華','唐','御定全唐诗','yuding','','[]','杜拾遺，名甫第二才甚奇。任生與君別，別來已多時，',221,'御定全唐詩/json/261.json','["杜拾遺，名甫第二才甚奇。任生與君別，別來已多時，", "昨日有人誦得數篇黃絹詞，吾怪異奇特借問，", "諸人見所作，無不心膽破。郎官叢裏作狂歌，", "積翠扈遊花匼匝，披香寓直月團欒。英才特達承天眷，", "如今避地錦城隅，幕下英僚每日相隨提玉壺。", "半醉起舞捋髭須，乍低乍昂傍若無。", "古人制禮但為防俗士，豈得為君設之乎。", "而我不飛不鳴亦何以，只待朝廷有知己。", "已曾讀卻無限書，拙詩一句兩句在人耳。", "如今看之總無益，又不能崎嶇傍朝市。且當事耕稼，", "閑常把琴弄，悶即攜樽起。鶯啼二月三月時，"]'),
('yuding-2','懷素上人草書歌','任華','唐','御定全唐诗','yuding','','[]','吾嘗好奇，古來草聖無不知。豈不知右軍與獻之，',203,'御定全唐詩/json/261.json','["吾嘗好奇，古來草聖無不知。豈不知右軍與獻之，", "狂僧前日動京華，朝騎王公大人馬，暮宿王公大人家。", "誰不造素屏？誰不塗粉壁？粉壁搖晴光，素屏凝曉霜，", "一顛一狂多意氣，大叫一聲起攘臂。揮毫倏忽千萬字，", "擲華山巨石以為點，掣衡山陣雲以為畫。興不盡，", "又如翰海日暮愁陰濃，忽然躍出千黑龍。夭矯偃蹇，", "狂僧有絕藝，非數仞高牆不足以逞其筆勢。", "或逢花箋與絹素，凝神執筆守恆度。別來筋骨多情趣，", "終恐絆騏驥之足，不得展千里之步。狂僧狂僧，"]'),
('yuding-3','金陵酬李翰林謫仙子','魏萬','唐','御定全唐诗','yuding','','[]','君抱碧海珠，我懷藍田玉。各稱希代寶，萬里遙相燭。',288,'御定全唐詩/json/261.json','["君抱碧海珠，我懷藍田玉。各稱希代寶，萬里遙相燭。", "長卿慕藺久，子猷意已深。平生風雲人，暗合江海心。", "去秋忽乘興，命駕來東土。謫仙游梁園，愛子在鄒魯。", "二處一不見，拂衣向江東。五兩掛海月，扁舟隨長風。", "南游吳越遍，高揖二千石。雪上天臺山，春逢翰林伯。", "宣父敬項橐，林宗重黃生。一長複一少，相看如弟兄。", "惕然意不盡，更逐西南去。同舟入秦淮，建業龍盤處。", "楚歌對吳酒，借問承恩初。宮買長門賦，天迎駟馬車。", "才高世難容，道廢可推命。安石重攜妓，子房空謝病。", "金陵百萬戶，六代帝王都。虎石據西江，鐘山臨北湖。", "二山信為美，王屋人相待。應為歧路多，不知歲寒在。", "君遊早晚還，勿久風塵間。此別未遠別，秋期到仙山。"]'),
('yuding-4','贈李十二白','崔宗之','唐','御定全唐诗','yuding','','[]','涼風八九月，白露滿空庭。耿耿意不暢，捎捎風葉聲。',180,'御定全唐詩/json/261.json','["涼風八九月，白露滿空庭。耿耿意不暢，捎捎風葉聲。", "思見雄俊士，共話今古情。李侯忽來儀，把袂苦不早。", "清論既抵掌，玄談又絕倒。分明楚漢事，歷歷王霸道。", "擔囊無俗物，訪古千里餘。袖有匕首劍，懷中茂陵書。", "雙眸光照人，詞賦淩子虛。酌酒弦素琴，霜氣正凝潔。", "平生心中事，今日為君說。我家有別業，寄在嵩之陽。", "明月出高岑，清溪澄素光。雲散窗戶靜，風吹松桂香。", "子若同斯遊，千載不相忘。"]'),
('yuding-5','贈李十二白','崔成甫','唐','御定全唐诗','yuding','','[]','我是瀟湘放逐臣，君辭明主漢江濱。',32,'御定全唐詩/json/261.json','["我是瀟湘放逐臣，君辭明主漢江濱。", "天外常求太白老，金陵捉得酒仙人。"]'),
('yuding-6','寄題杜拾遺錦江野亭','嚴武','唐','御定全唐诗','yuding','','[]','漫向江頭把釣竿，懶眠沙草愛風湍。莫倚善題鸚鵡賦，',40,'御定全唐詩/json/261.json','["漫向江頭把釣竿，懶眠沙草愛風湍。莫倚善題鸚鵡賦，", "興發會能馳駿馬，應須直到使君灘。"]'),
('yuding-7','酬別杜二','嚴武','唐','御定全唐诗','yuding','','[]','獨逢堯典日，再睹漢官時。未效風霜勁，空慚雨露私。',120,'御定全唐詩/json/261.json','["獨逢堯典日，再睹漢官時。未效風霜勁，空慚雨露私。", "夜鐘清萬戶，曙漏拂千旗。並向殊庭謁，俱承別館追。", "鬥城憐舊路，渦水惜歸期。峰樹還相伴，江雲更對垂。", "試回滄海棹，莫妒敬亭詩。只是書應寄，無忘酒共持。", "但令心事在，未肯鬢毛衰。最悵巴山裏，清猿醒夢思。"]'),
('yuding-8','題巴州光福寺楠木','嚴武','唐','御定全唐诗','yuding','','[]','楚江長流對楚寺，楠木幽生赤崖背。臨溪插石盤老根，',72,'御定全唐詩/json/261.json','["楚江長流對楚寺，楠木幽生赤崖背。臨溪插石盤老根，", "香殿蕭條轉密陰，花龕滴瀝垂清露。聞道偏多越水頭，", "看君幽靄幾千丈，寂寞窮山今遇賞。亦知鐘梵報黃昏，"]'),
('yuding-9','班婕妤','嚴武','唐','御定全唐诗','yuding','','[]','賤妾如桃李，君王若歲時。秋風一已勁，搖落不勝悲。',48,'御定全唐詩/json/261.json','["賤妾如桃李，君王若歲時。秋風一已勁，搖落不勝悲。", "寂寂蒼苔滿，沉沉綠草滋。繁華非此日，指輦競何辭。"]'),
('yuding-10','巴嶺答杜二見憶','嚴武','唐','御定全唐诗','yuding','','[]','臥向巴山落月時，兩鄉千里夢相思。可但步兵偏愛酒，',40,'御定全唐詩/json/261.json','["臥向巴山落月時，兩鄉千里夢相思。可但步兵偏愛酒，", "跂馬望君非一度，冷猿秋雁不勝悲。"]'),
('yuding-11','軍城早秋','嚴武','唐','御定全唐诗','yuding','','[]','昨夜秋風入漢關，朔雲邊月滿西山。',32,'御定全唐詩/json/261.json','["昨夜秋風入漢關，朔雲邊月滿西山。", "更催飛將追驕虜，莫遣沙場匹馬還。"]'),
('yuding-12','潭州留別杜員外院長','韋迢','唐','御定全唐诗','yuding','','[]','江畔長沙驛，相逢纜客船。大名詩獨步，小郡海西偏。',48,'御定全唐詩/json/261.json','["江畔長沙驛，相逢纜客船。大名詩獨步，小郡海西偏。", "地濕愁飛鵩，天炎畏跕鳶。去留俱失意，把臂共潸然。"]'),
('yuding-13','早發湘潭寄杜員外院長','韋迢','唐','御定全唐诗','yuding','','[]','北風昨夜雨，江上早來涼。楚岫千峰翠，湘潭一葉黃。',48,'御定全唐詩/json/261.json','["北風昨夜雨，江上早來涼。楚岫千峰翠，湘潭一葉黃。", "故人湖外客，白首尚為郎。相憶無南雁，何時有報章。"]'),
('yuding-14','寄杜員外','郭受','唐','御定全唐诗','yuding','','[]','新詩海內流傳久，舊德朝中屬望勞。郡邑地卑饒霧雨，',40,'御定全唐詩/json/261.json','["新詩海內流傳久，舊德朝中屬望勞。郡邑地卑饒霧雨，", "春興不知凡幾首，衡陽紙價頓能高。"]'),
('yuding-0','晦日呈諸判官','韓滉','唐','御定全唐诗','yuding','','[]','晦日新晴春色嬌，萬家攀折渡長橋。',32,'御定全唐詩/json/262.json','["晦日新晴春色嬌，萬家攀折渡長橋。", "年年老向江城寺，不覺春風換柳條。"]'),
('yuding-1','聽樂悵然自述','韓滉','唐','御定全唐诗','yuding','','[]','萬事傷心對管弦，一身含淚向春煙。',32,'御定全唐詩/json/262.json','["萬事傷心對管弦，一身含淚向春煙。", "黃金用盡教歌舞，留與他人樂少年。"]'),
('yuding-2','《題弟臮述書賦》後','竇蒙','唐','御定全唐诗','yuding','','[]','受命別家鄉，思歸每斷腸。季江留被在，子敬與琴亡。',72,'御定全唐詩/json/262.json','["受命別家鄉，思歸每斷腸。季江留被在，子敬與琴亡。", "吾弟當平昔，才名荷寵光。作詩通小雅，獻賦掩長楊。", "流轉三千里，悲啼百萬行。庭前紫荊樹，何日再芬芳。"]'),
('yuding-3','迎春東郊','張濯','唐','御定全唐诗','yuding','','[]','顓頊時初謝，句芒令複陳。飛灰將應節，賓日已知春。',96,'御定全唐詩/json/262.json','["顓頊時初謝，句芒令複陳。飛灰將應節，賓日已知春。", "考曆明三統，迎祥受萬人。衣冠宵執玉，壇墠曉清塵。", "肅穆來東道，回環拱北辰。仗前花待發，旗處柳疑新。", "雲斂黃山際，冰開素滻濱。聖朝多慶賞，希為薦沈淪。"]'),
('yuding-4','題舜廟','張濯','唐','御定全唐诗','yuding','','[]','古都遺廟出河濆，萬代千秋仰聖君。蒲阪城邊長逝水，',40,'御定全唐詩/json/262.json','["古都遺廟出河濆，萬代千秋仰聖君。蒲阪城邊長逝水，", "向晚風吹庭下柏，猶疑琴曲韻南熏。"]'),
('yuding-5','迎春東郊','王綽','唐','御定全唐诗','yuding','','[]','玉管潛移律，東郊始報春。鑾輿應寶運，天仗出佳辰。',72,'御定全唐詩/json/262.json','["玉管潛移律，東郊始報春。鑾輿應寶運，天仗出佳辰。", "睿澤光時輩，恩輝及物新。虯螭動旌旆，煙景入城闉。", "禦柳初含色，龍池漸啟津。誰憐在陰者，得與蟄蟲伸。"]'),
('yuding-6','邯鄲少年行','鄭錫','唐','御定全唐诗','yuding','','[]','霞鞍金口騮，豹袖紫貂裘。家住叢台近，門前漳水流。',48,'御定全唐詩/json/262.json','["霞鞍金口騮，豹袖紫貂裘。家住叢台近，門前漳水流。", "喚人呈楚舞，借客試吳鉤。見說秦兵至，甘心赴國仇。"]'),
('yuding-7','隴頭別','鄭錫','唐','御定全唐诗','yuding','','[]','秋盡初移幕，沾裳一送君。據鞍窺古堠，開灶爇寒雲。',48,'御定全唐詩/json/262.json','["秋盡初移幕，沾裳一送君。據鞍窺古堠，開灶爇寒雲。", "登隴人回首，臨關馬顧群。從來斷腸處，皆向此中分。"]'),
('yuding-8','度關山','鄭錫','唐','御定全唐诗','yuding','','[]','象弭插文犀，魚腸瑩鸊鵜。水聲分隴咽，馬色度關迷。',48,'御定全唐詩/json/262.json','["象弭插文犀，魚腸瑩鸊鵜。水聲分隴咽，馬色度關迷。", "曉幕胡沙慘，危烽漢月低。仍聞數騎將，更欲出遼西。"]'),
('yuding-9','出塞','鄭錫','唐','御定全唐诗','yuding','','[]','關山落葉秋，掩淚望營州。遼海雲沙暮，幽燕旌旆愁。',48,'御定全唐詩/json/262.json','["關山落葉秋，掩淚望營州。遼海雲沙暮，幽燕旌旆愁。", "戰餘能送陣，身老未封侯。去國三千里，歸心紅粉樓。"]'),
('yuding-10','玉階怨','鄭錫','唐','御定全唐诗','yuding','','[]','長門寒水流，高殿曉風秋。昨夜鴛鴦夢，還陪豹尾遊。',48,'御定全唐詩/json/262.json','["長門寒水流，高殿曉風秋。昨夜鴛鴦夢，還陪豹尾遊。", "前魚不解泣，共輦豈關羞。那及輕身燕，雙飛上玉樓。"]'),
('yuding-11','千里思','鄭錫','唐','御定全唐诗','yuding','','[]','渭水通胡苑，輪台望漢關。帛書秋海斷，錦字夜機閑。',48,'御定全唐詩/json/262.json','["渭水通胡苑，輪台望漢關。帛書秋海斷，錦字夜機閑。", "旅夢蟲催曉，邊心雁帶還。惟餘兩鄉思，一夕度關山。"]'),
('yuding-12','襄陽樂','鄭錫','唐','御定全唐诗','yuding','','[]','春生峴首東，先暖習池風。拂水初含綠，驚林未吐紅。',48,'御定全唐詩/json/262.json','["春生峴首東，先暖習池風。拂水初含綠，驚林未吐紅。", "渚邊遊漢女，桑下問龐公。磨滅懷中刺，曾將示孔融。"]'),
('yuding-13','送客之江西','鄭錫','唐','御定全唐诗','yuding','','[]','乘軺奉紫泥，澤國渺天涯。九派春潮滿，孤帆暮雨低。',48,'御定全唐詩/json/262.json','["乘軺奉紫泥，澤國渺天涯。九派春潮滿，孤帆暮雨低。", "草深鶯斷續，花落水東西。更有高唐處，知君路不迷。"]'),
('yuding-14','望月','鄭錫','唐','御定全唐诗','yuding','','[]','高堂新月明，虛殿夕風清。素影紗窗霽，浮涼羽扇輕。',48,'御定全唐詩/json/262.json','["高堂新月明，虛殿夕風清。素影紗窗霽，浮涼羽扇輕。", "稍隨微露滴，漸逐曉參橫。遙憶雲中詠，蕭條空複情。"]'),
('yuding-15','出塞曲','鄭錫','唐','御定全唐诗','yuding','','[]','校尉徵兵出塞西，別營分騎過龍溪。沙平虜跡風吹盡，',40,'御定全唐詩/json/262.json','["校尉徵兵出塞西，別營分騎過龍溪。沙平虜跡風吹盡，", "會當系取天驕入，不使軍書夜刺閨。"]'),
('yuding-16','秦人謠','古之奇','唐','御定全唐诗','yuding','','[]','微生祖龍代，卻思堯舜道。何人仕帝庭，拔殺指佞草。',72,'御定全唐詩/json/262.json','["微生祖龍代，卻思堯舜道。何人仕帝庭，拔殺指佞草。", "奸臣弄民柄，天子恣衷抱。上下一相蒙，馬鹿遂顛倒。", "中國既板蕩，骨肉安可保。人生貴年壽，吾恨死不早。"]'),
('yuding-17','阮客舊居','李陽冰','唐','御定全唐诗','yuding','','[]','阮客身何在，仙雲洞口橫。人間不到處，今日此中行。',24,'御定全唐詩/json/262.json','["阮客身何在，仙雲洞口橫。人間不到處，今日此中行。"]'),
('yuding-0','酬耿拾遺題贈','嚴維','唐','御定全唐诗','yuding','','[]','掩扉常自靜，驛吏忽傳呼。水巷驚馴鳥，藜床起病軀。',48,'御定全唐詩/json/263.json','["掩扉常自靜，驛吏忽傳呼。水巷驚馴鳥，藜床起病軀。", "顧身悲欲老，戒子力為儒。明日公西去，煙霞複作徒。"]'),
('yuding-1','酬王侍禦西陵渡見寄','嚴維','唐','御定全唐诗','yuding','','[]','前年萬里別，昨日一封書。郢曲西陵渡，秦官使者車。',48,'御定全唐詩/json/263.json','["前年萬里別，昨日一封書。郢曲西陵渡，秦官使者車。", "柳塘熏晝日，花水溢春渠。若不嫌雞黍，先令掃弊廬。"]'),
('yuding-2','酬劉員外見寄','嚴維','唐','御定全唐诗','yuding','','[]','蘇耽佐郡時，近出白雲司。藥補清羸疾，窗吟絕妙詞。',48,'御定全唐詩/json/263.json','["蘇耽佐郡時，近出白雲司。藥補清羸疾，窗吟絕妙詞。", "柳塘春水慢，花塢夕陽遲。欲識懷君意，明朝訪楫師。"]'),
('yuding-3','同韓員外宿雲門寺','嚴維','唐','御定全唐诗','yuding','','[]','小嶺路難近，仙郎此夕過。潭空觀月定，澗靜見雲多。',48,'御定全唐詩/json/263.json','["小嶺路難近，仙郎此夕過。潭空觀月定，澗靜見雲多。", "竹翠煙深鎖，松聲雨點和。萬緣俱不有，對境自垂蘿。"]'),
('yuding-4','酬諸公宿鏡水宅','嚴維','唐','御定全唐诗','yuding','','[]','倖免低頭向府中，貴將藜藿與君同。陽雁叫霜來枕上，',40,'御定全唐詩/json/263.json','["倖免低頭向府中，貴將藜藿與君同。陽雁叫霜來枕上，", "聞道漢家偏尚少，此身那此訪芝翁。"]'),
('yuding-5','送薛尚書入蜀','嚴維','唐','御定全唐诗','yuding','','[]','卑情不敢論，拜首入轅門。列郡諸侯長，登朝八座尊。',48,'御定全唐詩/json/263.json','["卑情不敢論，拜首入轅門。列郡諸侯長，登朝八座尊。", "凝笳臨水發，行旆向風翻。幾許遺黎泣，同懷父母恩。"]'),
('yuding-6','送李秘書往儋州','嚴維','唐','御定全唐诗','yuding','','[]','魑魅曾為伍，蓬萊近拜郎。臣心瞻北闕，家事在南荒。',48,'御定全唐詩/json/263.json','["魑魅曾為伍，蓬萊近拜郎。臣心瞻北闕，家事在南荒。", "莎草山城小，毛洲海驛長。玄成知必大，寧是泛滄浪。"]'),
('yuding-7','送人入金華','嚴維','唐','御定全唐诗','yuding','','[]','明月雙溪水，清風八詠樓。昔年為客處，今日送君遊。',24,'御定全唐詩/json/263.json','["明月雙溪水，清風八詠樓。昔年為客處，今日送君遊。"]'),
('yuding-8','送崔峒使往睦州兼寄薛司戶','嚴維','唐','御定全唐诗','yuding','','[]','如今相府用英髦，獨往南州肯告勞，冰水近開漁浦出，',40,'御定全唐詩/json/263.json','["如今相府用英髦，獨往南州肯告勞，冰水近開漁浦出，", "使者應須訪廉吏，府中惟有范功曹。"]'),
('yuding-9','送房元直赴北京','嚴維','唐','御定全唐诗','yuding','','[]','猶道樓蘭十萬師，書生匹馬去何之。臨岐未斷歸家目，',40,'御定全唐詩/json/263.json','["猶道樓蘭十萬師，書生匹馬去何之。臨岐未斷歸家目，", "遙知到日逢寒食，彩筆長裾會晉祠。"]'),
('yuding-10','荊溪館呈丘義興','嚴維','唐','御定全唐诗','yuding','','[]','失路荊溪上，依人忽暝投。長橋今夜月，陽羨古時州。',48,'御定全唐詩/json/263.json','["失路荊溪上，依人忽暝投。長橋今夜月，陽羨古時州。", "野燒明山郭，寒更出縣樓。先生能館我，無事五湖遊。"]'),
('yuding-11','一公新泉','嚴維','唐','御定全唐诗','yuding','','[]','山下新泉出，泠泠北去源。落池才有響，噴石未成痕。',48,'御定全唐詩/json/263.json','["山下新泉出，泠泠北去源。落池才有響，噴石未成痕。", "獨映孤松色，殊分眾鳥喧。唯當清夜月，觀此啟禪門。"]'),
('yuding-12','奉試水精環','嚴維','唐','御定全唐诗','yuding','','[]','王室符長慶，環中得水精。任圓循不極，見素質仍貞。',72,'御定全唐詩/json/263.json','["王室符長慶，環中得水精。任圓循不極，見素質仍貞。", "信是天然瑞，非因朴斫成。無瑕勝玉美，至潔過冰清。", "未肯齊瑉價，寧同雜佩聲。能銜任黃雀，亦欲應時明。"]'),
('yuding-13','自雲陽歸晚泊陸澧宅','嚴維','唐','御定全唐诗','yuding','','[]','天陰行易晚，前路故人居。孤棹所思久，寒林相見初。',48,'御定全唐詩/json/263.json','["天陰行易晚，前路故人居。孤棹所思久，寒林相見初。", "閑燈忘夜永，清漏任更疏。明發還須去，離家幾歲除。"]'),
('yuding-14','九日陪崔郎中北山宴','嚴維','唐','御定全唐诗','yuding','','[]','上客南台至，重陽此會文。菊芳寒露洗，杯翠夕陽曛。',48,'御定全唐詩/json/263.json','["上客南台至，重陽此會文。菊芳寒露洗，杯翠夕陽曛。", "務簡人同醉，溪閑鳥自群。府中官最小，唯有孟參軍。"]'),
('yuding-15','留別鄒紹劉長卿','嚴維','唐','御定全唐诗','yuding','','[]','中年從一尉，自笑此身非。道在甘微祿，時難恥息機。',48,'御定全唐詩/json/263.json','["中年從一尉，自笑此身非。道在甘微祿，時難恥息機。", "晨趨本郡府，晝掩故山扉。待見干戈畢，何妨更采薇。"]'),
('yuding-16','書情獻相公','嚴維','唐','御定全唐诗','yuding','','[]','年來白髮欲星星，誤卻生涯是一經。魏闕望中何日見，',40,'御定全唐詩/json/263.json','["年來白髮欲星星，誤卻生涯是一經。魏闕望中何日見，", "今日更須詢哲匠，不應休去老岩扃。"]'),
('yuding-17','贈送朱放','嚴維','唐','御定全唐诗','yuding','','[]','昔年居漢水，日醉習家池。道勝跡常在，名高身不知。',49,'御定全唐詩/json/263.json','["昔年居漢水，日醉習家池。道勝跡常在，名高身不知。", "欲依天目住，新自始寧移。生事曾無長，惟將白接z5。"]'),
('yuding-18','剡中贈張卿侍禦','嚴維','唐','御定全唐诗','yuding','','[]','辟疆年正少，公子貴初還。早列月卿位，新參柱史班。',72,'御定全唐詩/json/263.json','["辟疆年正少，公子貴初還。早列月卿位，新參柱史班。", "千夫馳驛道，駟馬入家山。深巷烏衣盛，高門畫戟閑。", "逶迤天樂下，照耀剡溪間。自賤遊章句，空為衰草顏。"]'),
('yuding-19','贈萬經','嚴維','唐','御定全唐诗','yuding','','[]','萬公長慢世，昨日又隳官。縱酒真彭澤，論詩得建安。',48,'御定全唐詩/json/263.json','["萬公長慢世，昨日又隳官。縱酒真彭澤，論詩得建安。", "家山伯禹穴，別墅小長幹。輒有時人至，窗前白眼看。"]'),
('yuding-20','書情上李蘇州','嚴維','唐','御定全唐诗','yuding','','[]','東土苗人尚有殘，皇皇亞相出朝端。手持國憲群僚畏，',40,'御定全唐詩/json/263.json','["東土苗人尚有殘，皇皇亞相出朝端。手持國憲群僚畏，", "誤著青袍將十載，忍令漁浦卻垂竿。"]'),
('yuding-21','餘姚祗役奉簡鮑參軍','嚴維','唐','御定全唐诗','yuding','','[]','童年獻賦在皇州，方寸思量君與侯。萬事無成新白首，',40,'御定全唐詩/json/263.json','["童年獻賦在皇州，方寸思量君與侯。萬事無成新白首，", "知己欲依何水部，鄉人今正賤東丘。"]'),
('yuding-22','奉和獨孤中丞遊雲門寺','嚴維','唐','御定全唐诗','yuding','','[]','絕壑開花界，耶溪極上源。光輝三獨坐，登陟五雲門。',96,'御定全唐詩/json/263.json','["絕壑開花界，耶溪極上源。光輝三獨坐，登陟五雲門。", "深木鳴騶馭，晴山曜武賁。亂泉觀坐臥，疏磬發朝昏。", "蒼翠新秋色，莓苔積雨痕。上方看度鳥，後夜聽吟猿。", "異跡焚香對，新詩酌茗論。歸來還撫俗，諸老莫攀轅。"]'),
('yuding-23','奉和皇甫大夫夏日游花嚴寺','嚴維','唐','御定全唐诗','yuding','','[]','初第華嚴會，王家少長行。到宮龍節駐，禮塔雁行成。',48,'御定全唐詩/json/263.json','["初第華嚴會，王家少長行。到宮龍節駐，禮塔雁行成。", "蓮界千峰靜，梅天一雨清。禪庭未可戀，聖主寄蒼生。"]'),
('yuding-24','宿法華寺','嚴維','唐','御定全唐诗','yuding','','[]','一夕雨沉沉，哀猿萬木陰。天龍來護法，長老密看心。',48,'御定全唐詩/json/263.json','["一夕雨沉沉，哀猿萬木陰。天龍來護法，長老密看心。", "魚梵空山靜，紗燈古殿深。無生久已學，白髮浪相侵。"]'),
('yuding-25','題茅山李尊師所居','嚴維','唐','御定全唐诗','yuding','','[]','天師百歲少如童，不到山中更不逢。洗藥每臨新瀑水，',40,'御定全唐詩/json/263.json','["天師百歲少如童，不到山中更不逢。洗藥每臨新瀑水，", "此去人寰知近遠，回看路隔一重重。"]'),
('yuding-26','送薛居士和州讀書','嚴維','唐','御定全唐诗','yuding','','[]','孤雲獨鶴共悠悠，萬卷經書一葉舟，楚地巢城民舍少，',40,'御定全唐詩/json/263.json','["孤雲獨鶴共悠悠，萬卷經書一葉舟，楚地巢城民舍少，", "年少不應辭苦節，諸生若遇亦封侯。"]'),
('yuding-27','送李端','嚴維','唐','御定全唐诗','yuding','','[]','故關衰草遍，離別正堪悲。路出寒雲外，人歸暮雪時。',48,'御定全唐詩/json/263.json','["故關衰草遍，離別正堪悲。路出寒雲外，人歸暮雪時。", "少孤為客早，多難識君遲。掩泣空相向，風塵何所期。"]'),
('yuding-28','宿天竺寺','嚴維','唐','御定全唐诗','yuding','','[]','方外主人名道林，怕將水月淨身心。',32,'御定全唐詩/json/263.json','["方外主人名道林，怕將水月淨身心。", "居然對我說無我，寂曆山深將夜深。"]'),
('yuding-29','丹陽送韋參軍','嚴維','唐','御定全唐诗','yuding','','[]','丹陽郭裏送行舟，一別心知兩地秋。',32,'御定全唐詩/json/263.json','["丹陽郭裏送行舟，一別心知兩地秋。", "日晚江南望江北，寒鴉飛盡水悠悠。"]'),
('yuding-30','入唐溪','嚴維','唐','御定全唐诗','yuding','','[]','嘯終萬籟起，吹去當溪雲。環嶼或明昧，遠峰尚氛氳。',48,'御定全唐詩/json/263.json','["嘯終萬籟起，吹去當溪雲。環嶼或明昧，遠峰尚氛氳。", "雨新翠葉發，夜早玄象分。金澗流不盡，入山深更聞。"]'),
('yuding-31','送桃岩成上人歸本寺','嚴維','唐','御定全唐诗','yuding','','[]','長老歸緣起，桃花憶舊岩。清晨雲抱石，深夜月籠杉。',48,'御定全唐詩/json/263.json','["長老歸緣起，桃花憶舊岩。清晨雲抱石，深夜月籠杉。", "道具門人捧，齋糧穀鳥銜。餘生願依止，文字欲三緘。"]'),
('yuding-32','酬普選二上人期相會見寄','嚴維','唐','御定全唐诗','yuding','','[]','本意宿東林，因聽子賤琴。遙知大小朗，已斷去來心。',48,'御定全唐詩/json/263.json','["本意宿東林，因聽子賤琴。遙知大小朗，已斷去來心。", "夜靜溪聲近，庭寒月色深。寧知塵外意，定後便成吟。"]'),
('yuding-33','相裏使君宅聽澄上人吹小管','嚴維','唐','御定全唐诗','yuding','','[]','秦僧吹竹閉秋城，早在梨園稱主情。',32,'御定全唐詩/json/263.json','["秦僧吹竹閉秋城，早在梨園稱主情。", "今夕襄陽山太守，座中流淚聽商聲。"]'),
('yuding-34','贈別至弘上人','嚴維','唐','御定全唐诗','yuding','','[]','最稱弘偃少，早歲草茅居。年老從僧律，生知解佛書。',48,'御定全唐詩/json/263.json','["最稱弘偃少，早歲草茅居。年老從僧律，生知解佛書。", "衲衣求壞帛，野飯拾春蔬。章句無求斷，時中學有餘。"]'),
('yuding-35','奉和劉祭酒傷白馬','嚴維','唐','御定全唐诗','yuding','','[]','沛艾如龍馬，來從上苑中。棣華恩見賜，伯舅禮仍崇。',96,'御定全唐詩/json/263.json','["沛艾如龍馬，來從上苑中。棣華恩見賜，伯舅禮仍崇。", "鏡點黃金眼，花開白雪鬃。性柔君子德，足逸大王風。", "色照鳴珂靜，聲連噴玉雄。食場恩未盡，過隙命旋終。", "練影依雲沒，銀鞍向月空。仍聞樂府唱，猶念代勞功。"]'),
('yuding-36','哭靈一上人','嚴維','唐','御定全唐诗','yuding','','[]','一公何不住，空有遠公名。共說岑山路，今時不可行。',72,'御定全唐詩/json/263.json','["一公何不住，空有遠公名。共說岑山路，今時不可行。", "舊房松更老，新塔草初生。經論傳緇侶，文章遍墨卿。", "禪林枝幹折，法宇棟樑傾。誰複修僧史，應知傳已成。"]'),
('yuding-37','題鮑行軍小閣','嚴維','唐','御定全唐诗','yuding','','[]','宇下無留事，經營意獨新。文房已得地，相閣是推輪。',72,'御定全唐詩/json/263.json','["宇下無留事，經營意獨新。文房已得地，相閣是推輪。", "席上招賢急，山陰對雪頻。虛明先旦暮，啟閉異冬春。", "談笑兵家法，逢迎幕府賓。還將負暄處，時借在陰人。"]'),
('yuding-38','陪皇甫大夫謁禹廟','嚴維','唐','御定全唐诗','yuding','','[]','竹使羞殷薦，松龕拜夏祠。為魚歌德後，舞羽降神時。',48,'御定全唐詩/json/263.json','["竹使羞殷薦，松龕拜夏祠。為魚歌德後，舞羽降神時。", "文衛瞻如在，精靈信有期。夕陽陪醉止，塘上鳥咸遲。"]'),
('yuding-39','同王征君湘中有懷','嚴維','唐','御定全唐诗','yuding','','[]','八月洞庭秋，瀟湘水北流。還家萬里夢，為客五更愁。',48,'御定全唐詩/json/263.json','["八月洞庭秋，瀟湘水北流。還家萬里夢，為客五更愁。", "不用看書帙，偏宜上酒樓。故人京洛滿，何日複同遊。"]'),
('yuding-40','奉和皇甫大夫祈雨應時雨降','嚴維','唐','御定全唐诗','yuding','','[]','致和知必感，歲旱未書災。伯禹明靈降，元戎禱請來。',72,'御定全唐詩/json/263.json','["致和知必感，歲旱未書災。伯禹明靈降，元戎禱請來。", "九成陳夏樂，三獻奉殷罍。掣曳旗交電，鏗鏘鼓應雷。", "行雲依蓋轉，飛雨逐車回。欲識皇天意，為霖貺在哉。"]'),
('yuding-41','贈別劉長卿時赴河南嚴中丞幕府','嚴維','唐','御定全唐诗','yuding','','[]','早見登郎署，同時跡下僚。幾年江路永，今去國門遙。',72,'御定全唐詩/json/263.json','["早見登郎署，同時跡下僚。幾年江路永，今去國門遙。", "文變騷人體，官移漢帝朝。望山吟度日，接枕話通宵。", "萬里趨公府，孤帆恨信潮。匡時知已老，聖代恥逃堯。"]'),
('yuding-42','晦日宴游','嚴維','唐','御定全唐诗','yuding','','[]','晦日湔裾俗，春樓致酒時。出山還已醉，謝客舊能詩。',48,'御定全唐詩/json/263.json','["晦日湔裾俗，春樓致酒時。出山還已醉，謝客舊能詩。", "溪柳熏晴淺，岩花待閏遲。為邦久無事，比屋自熙熙。"]'),
('yuding-43','夏日納涼','嚴維','唐','御定全唐诗','yuding','','[]','山陰過野客，鏡裏接仙郎。盥漱臨寒水，褰闈入夏堂。',48,'御定全唐詩/json/263.json','["山陰過野客，鏡裏接仙郎。盥漱臨寒水，褰闈入夏堂。", "杉松交日影，枕簟上湖光。袞袞承嘉話，清風納晚涼。"]'),
('yuding-44','僧房避暑','嚴維','唐','御定全唐诗','yuding','','[]','支公好閑寂，庭宇愛林篁。幽曠無煩暑，恬和不可量。',48,'御定全唐詩/json/263.json','["支公好閑寂，庭宇愛林篁。幽曠無煩暑，恬和不可量。", "蕙風清水殿，荷氣雜天香。明月談空坐，怡然道術忘。"]'),
('yuding-45','九日登高','嚴維','唐','御定全唐诗','yuding','','[]','詩家九日憐芳菊，遲客高齋瞰浙江。漢浦浪花搖素壁，',40,'御定全唐詩/json/263.json','["詩家九日憐芳菊，遲客高齋瞰浙江。漢浦浪花搖素壁，", "四子醉時爭講德，笑論黃霸屈為邦。"]'),
('yuding-46','九月十日即事','嚴維','唐','御定全唐诗','yuding','','[]','家貧惟種竹，時幸故人看。菊度重陽少，林經閏月寒。',48,'御定全唐詩/json/263.json','["家貧惟種竹，時幸故人看。菊度重陽少，林經閏月寒。", "宿酲猶落帽，華髮強扶冠。美景良難得，今朝更盡歡。"]'),
('yuding-47','送丘為下第歸蘇州','嚴維','唐','御定全唐诗','yuding','','[]','滄江一身客，獻賦空十年。明主豈能好，今人誰舉賢。',60,'御定全唐詩/json/263.json','["滄江一身客，獻賦空十年。明主豈能好，今人誰舉賢。", "國門稅征駕，旅食謀歸旋。皦日媚春水，綠蘋香客船。", "無媒既不達，餘亦思歸田。"]'),
('yuding-48','送少微上人東南游','嚴維','唐','御定全唐诗','yuding','','[]','舊遊多不見，師在翟公門。瘴海空山熱，雷州白日昏。',48,'御定全唐詩/json/263.json','["舊遊多不見，師在翟公門。瘴海空山熱，雷州白日昏。", "片心應為法，萬里獨無言。人盡酬恩去，平生未感恩。"]'),
('yuding-49','贈送崔子向','嚴維','唐','御定全唐诗','yuding','','[]','旅食來江上，求名赴洛陽。新詩蹤謝守，內學似支郎。',48,'御定全唐詩/json/263.json','["旅食來江上，求名赴洛陽。新詩蹤謝守，內學似支郎。", "行怯秦為客，心依越是鄉。何人作知己，送爾淚浪浪。"]'),
('yuding-50','答劉長卿七裏瀨重送','嚴維','唐','御定全唐诗','yuding','','[]','新安非欲枉帆過，海內如君有幾何。',32,'御定全唐詩/json/263.json','["新安非欲枉帆過，海內如君有幾何。", "醉裏別時秋水色，老人南望一狂歌。"]'),
('yuding-51','歲初喜皇甫侍禦至','嚴維','唐','御定全唐诗','yuding','','[]','湖上新正逢故人，情深應不笑家貧。',32,'御定全唐詩/json/263.json','["湖上新正逢故人，情深應不笑家貧。", "明朝別後門還掩，修竹千竿一老身。"]'),
('yuding-52','送舍弟','嚴維','唐','御定全唐诗','yuding','','[]','疏懶吾成性，才華爾自強。早稱眉最白，何事綬仍黃。',48,'御定全唐詩/json/263.json','["疏懶吾成性，才華爾自強。早稱眉最白，何事綬仍黃。", "時暑嗟於邁，家貧念聚糧。只應宵夢裏，詩興屬池塘。"]'),
('yuding-53','示外生','嚴維','唐','御定全唐诗','yuding','','[]','牽役非吾好，寬情爾在傍。經過悲井邑，起坐倦舟航。',48,'御定全唐詩/json/263.json','["牽役非吾好，寬情爾在傍。經過悲井邑，起坐倦舟航。", "相宅生應貴，逢時學可強。無輕吾未用，世事有行藏。"]'),
('yuding-54','詠孩子','嚴維','唐','御定全唐诗','yuding','','[]','嘉客會初筵，宜時魄再圓。眾皆含笑戲，誰不點頤憐。',48,'御定全唐詩/json/263.json','["嘉客會初筵，宜時魄再圓。眾皆含笑戲，誰不點頤憐。", "繡被花堪摘，羅繃色欲妍。將雛有舊曲，還入武城弦。"]'),
('yuding-55','酬謝侍禦喜王宇及第見賀不遇之作','嚴維','唐','御定全唐诗','yuding','','[]','寂寞柴門掩，經過柱史榮。老夫甯有力，半子自成名。',48,'御定全唐詩/json/263.json','["寂寞柴門掩，經過柱史榮。老夫甯有力，半子自成名。", "柳映三橋發，花連上道明。緘書到別墅，郢曲果先成。"]'),
('yuding-56','秋日與諸公文會天□寺','嚴維','唐','御定全唐诗','yuding','','[]','相訪從吾道，因緣會爾時。龍盤餘帝宅，花界古人祠。',48,'御定全唐詩/json/263.json','["相訪從吾道，因緣會爾時。龍盤餘帝宅，花界古人祠。", "明月虛空色，青林大小枝。還將經濟學，來問道安師。"]'),
('yuding-57','答劉長卿蛇浦橋月下重送','嚴維','唐','御定全唐诗','yuding','','[]','月色今宵最明，庭閑夜久天清。寂寞多年老宦，',35,'御定全唐詩/json/263.json','["月色今宵最明，庭閑夜久天清。寂寞多年老宦，", "耿耿相看不寐，遙聞曉柝山城。"]'),
('yuding-58','發桐戶寄劉員外','嚴維','唐','御定全唐诗','yuding','','[]','處處雲山無盡時，桐廬南望轉參差。',32,'御定全唐詩/json/263.json','["處處雲山無盡時，桐廬南望轉參差。", "舟人莫道新安近，欲上潺湲行自遲。"]'),
('yuding-59','秋夜船行','嚴維','唐','御定全唐诗','yuding','','[]','扁舟時屬暝，月上有餘輝。海燕秋還去，漁人夜不歸。',48,'御定全唐詩/json/263.json','["扁舟時屬暝，月上有餘輝。海燕秋還去，漁人夜不歸。", "中流何寂寂，孤棹也依依。一點前村火，誰家未掩扉。"]'),
('yuding-60','遊灞陵山','嚴維','唐','御定全唐诗','yuding','','[]','入山未盡意，勝跡聊獨尋。方士去在昔，藥堂留至今。',72,'御定全唐詩/json/263.json','["入山未盡意，勝跡聊獨尋。方士去在昔，藥堂留至今。", "四隅白雲閑，一路清溪深。芳秀愜春目，高閑宜遠心。", "潭分化丹水，路繞升仙林。此道人不悟，坐鳴松下琴。"]'),
('yuding-61','重送新安劉員外','嚴維','唐','御定全唐诗','yuding','','[]','秋江渺渺水空波，越客孤舟欲榜歌。',32,'御定全唐詩/json/263.json','["秋江渺渺水空波，越客孤舟欲榜歌。", "手折衰楊悲老大，故人零落已無多。"]'),
('yuding-62','憶長安：五月','嚴維','唐','御定全唐诗','yuding','','[]','憶長安，五月時，君王避暑華池。進膳甘瓜朱李，',22,'御定全唐詩/json/263.json','["憶長安，五月時，君王避暑華池。進膳甘瓜朱李，"]'),
('yuding-63','狀江南：季春','嚴維','唐','御定全唐诗','yuding','','[]','江南季春天，蓴葉細如弦。池邊草作徑，湖上葉如船。',24,'御定全唐詩/json/263.json','["江南季春天，蓴葉細如弦。池邊草作徑，湖上葉如船。"]'),
('yuding-64','句','嚴維','唐','御定全唐诗','yuding','','[]','五色驚彩鳳，千里象驄威。。',43,'御定全唐詩/json/263.json','["五色驚彩鳳，千里象驄威。。", "三伏軒車動，堯心急諫官。名通內籍貴，", "波從少海息，雲自大風開。"]'),
('yuding-0','琴歌','顧況','唐','御定全唐诗','yuding','','[]','琴調秋些，胡風繞雪，峽泉聲咽，佳人愁些。',20,'御定全唐詩/json/264.json','["琴調秋些，胡風繞雪，峽泉聲咽，佳人愁些。"]'),
('yuding-1','上古之什補亡訓傳十三章：上古一章','顧況','唐','御定全唐诗','yuding','','[]','遐哉上古，生棄與柱。句龍是生，乃有甫田。惟彼甫田，',50,'御定全唐詩/json/264.json','["遐哉上古，生棄與柱。句龍是生，乃有甫田。惟彼甫田，", "我姑自思，胡不奮飛。東人利百，西人利百。有匪我心，"]'),
('yuding-2','上古之什補亡訓傳十三章：左車二章','顧況','唐','御定全唐诗','yuding','','[]','（左車，憑險也。震為雷，兄長之。左，東方之師也。',100,'御定全唐詩/json/264.json','["（左車，憑險也。震為雷，兄長之。左，東方之師也。", "憑險不已，君子憂心，而作是詩。）", "左車有慶，萬人猶病。曷可去之，于党孔盛。", "敏爾之生，胡為波迸。", "左車有赫，萬人毒螫。曷可去之，于党孔碩。", "敏爾之生，胡為草戚。"]'),
('yuding-3','上古之什補亡訓傳十三章：築城二章','顧況','唐','御定全唐诗','yuding','','[]','築城登登，於以作固。咨爾寺兮，發郊外塚墓。',84,'御定全唐詩/json/264.json','["築城登登，於以作固。咨爾寺兮，發郊外塚墓。", "死而無知，猶或不可；若其有知，惟上帝是愬。", "築城奕奕，於以固敵。咨爾寺兮，發郊外塚甓。", "死而無知，猶或不可。若其有知，惟上帝是謫。"]'),
('yuding-4','上古之什補亡訓傳十三章：持斧一章','顧況','唐','御定全唐诗','yuding','','[]','（持斧，啟戎士也。戎士伐松柏為蒸薪。',40,'御定全唐詩/json/264.json','["（持斧，啟戎士也。戎士伐松柏為蒸薪。", "孝子徘徊而作是詩。）", "持斧持斧，無剪我松柏兮。"]'),
('yuding-5','上古之什補亡訓傳十三章：十月之郊一章','顧況','唐','御定全唐诗','yuding','','[]','十月之郊，群木肇生。陽潛地中，舒達句萌。曀其蔚兮，',125,'御定全唐詩/json/264.json','["十月之郊，群木肇生。陽潛地中，舒達句萌。曀其蔚兮，", "生混茫際，呼吸群籟。萬人揮斤，坎坎有厲。陸遷水濟，", "琴瑟在堂，莫不靜謐。周環掩辟，仰不漏日。冬日嚴凝。", "言納其陽，和風載升。夏日郁蒸，言用於陰，涼風颯興。", "有匪君子，自賢不已，乃夢乘舟，乃夢乘車。夢人占之，"]'),
('yuding-6','上古之什補亡訓傳十三章：燕于巢一章','顧況','唐','御定全唐诗','yuding','','[]','燕燕於巢，綴葺維戊。甲兮乙兮，不宜有謬。飛龍在天，',50,'御定全唐詩/json/264.json','["燕燕於巢，綴葺維戊。甲兮乙兮，不宜有謬。飛龍在天，", "昔在羲和，湎淫不修。我筮我龜，莫我告繇。胤乃征之，"]'),
('yuding-7','上古之什補亡訓傳十三章：蘇方一章','顧況','唐','御定全唐诗','yuding','','[]','蘇方之赤，在胡之舶，其利乃博。我土曠兮，我居闐兮，',25,'御定全唐詩/json/264.json','["蘇方之赤，在胡之舶，其利乃博。我土曠兮，我居闐兮，"]'),
('yuding-8','上古之什補亡訓傳十三章：陵霜之華一章','顧況','唐','御定全唐诗','yuding','','[]','陵霜之華，我心憂嗟。陰之勝矣，而陽不加。坱軋陶鈞，',60,'御定全唐詩/json/264.json','["陵霜之華，我心憂嗟。陰之勝矣，而陽不加。坱軋陶鈞，", "今華髮非其辰，辰屬東方之仁，遐想三五。黃帝登雲，", "陵霜之華兮，何不妄敷。"]'),
('yuding-9','上古之什補亡訓傳十三章：囝一章','顧況','唐','御定全唐诗','yuding','','[]','囝生閩方，閩吏得之，乃絕其陽。為臧為獲，致金滿屋。',100,'御定全唐詩/json/264.json','["囝生閩方，閩吏得之，乃絕其陽。為臧為獲，致金滿屋。", "為髡為鉗，如視草木。天道無知，我罹其毒。神道無知。", "彼受其福。郎罷別囝，吾悔生汝。及汝既生，人勸不舉。", "不從人言，果獲是苦，囝別郎罷，心摧血下。隔地絕天，"]'),
('yuding-10','上古之什補亡訓傳十三章：我行自東一章','顧況','唐','御定全唐诗','yuding','','[]','我行自東，山海其空，旅棘有叢；我行自西，壘與雲齊，',51,'御定全唐詩/json/264.json','["我行自東，山海其空，旅棘有叢；我行自西，壘與雲齊，", "我行自北，燭龍寡色，何枉不直。我憂京京，何道不行兮？"]'),
('yuding-11','上古之什補亡訓傳十三章：采蠟一章','顧況','唐','御定全唐诗','yuding','','[]','（采蠟，怨奢也。荒岩之間，有以纊蒙其身。腰藤造險，',66,'御定全唐詩/json/264.json','["（采蠟，怨奢也。荒岩之間，有以纊蒙其身。腰藤造險，", "采采者蠟，于泉穀兮。煌煌中堂，烈華燭兮。", "新歌善舞，弦柱促兮；荒岩之人，自取其毒兮。"]'),
('yuding-12','棄婦詞','顧況','唐','御定全唐诗','yuding','','[]','古人雖棄婦，棄婦有歸處。今日妾辭君，辭君欲何去。',204,'御定全唐詩/json/264.json','["古人雖棄婦，棄婦有歸處。今日妾辭君，辭君欲何去。", "本家零落盡，慟哭來時路。憶昔未嫁君，聞君甚周旋。", "及與同結髮，值君適幽燕。孤魂托飛鳥，兩眼如流泉。", "流泉咽不燥，萬里關山道。及至見君歸，君歸妾已老。", "物情棄衰歇，新寵方妍好。拭淚出故房，傷心劇秋草。", "妾以憔悴捐，羞將舊物還。餘生欲有寄，誰肯相留連。", "空床對虛牖，不覺塵埃厚。寒水芙蓉花，秋風墮楊柳。", "記得初嫁君，小姑始扶床。今日君棄妾，小姑如妾長。", "回頭語小姑，莫嫁如兄夫。"]'),
('yuding-13','遊子吟','顧況','唐','御定全唐诗','yuding','','[]','故櫪思疲馬，故窠思迷禽。浮雲蔽我鄉，躑躅遊子吟。',396,'御定全唐詩/json/264.json','["故櫪思疲馬，故窠思迷禽。浮雲蔽我鄉，躑躅遊子吟。", "遊子悲久滯，浮雲郁東岑。客堂無絲桐，落葉如秋霖。", "艱哉遠遊子，所以悲滯淫。一為浮雲詞，憤塞誰能禁。", "馳歸百年內，唯願展所欽。胡為不歸歟，坐使年病侵。", "未老霜繞鬢，非狂火燒心。太行何難哉，北斗不可斟。", "夜靜星河出，耿耿辰與參。佳人夐青天，尺素重于金。", "泬寥群動異，眇默諸境森。苔衣上閑階，蟋蟀催寒砧。", "立身計幾誤，道險無容針。三年不還家，萬里遺錦衾。", "夢魂無重阻，離憂罔古今。胡為不歸歟，辜負匣中琴。", "腰下是何物，牽纏曠登尋。朝與名山期，夕宿楚水陰。", "楚水殊演漾，名山窅嶇嶔。客從洞庭來，婉孌瀟湘深。", "橘柚在南國，鴻雁遺秋音。下有碧草洲，上有青橘林。", "引燭窺洞穴，淩波睥天琛。蒲荷影參差，鳧鶴雛淋涔。", "浩歌惜芳杜，散發輕華簪。胡為不歸歟，淚下沾衣襟。", "鳶飛戾霄漢，螻蟻制鱣鱏。赫赫大聖朝，日月光照臨。", "聖主雖啟迪，奇人分湮沈。層城登雲韶，王府鏘球琳。", "鹿鳴志豐草，況複虞人箴。"]'),
('yuding-14','擬古三首','顧況','唐','御定全唐诗','yuding','','[]','龍劍昔藏影，送雄留其雌。人生阻歡會，神物亦別離。',168,'御定全唐詩/json/264.json','["龍劍昔藏影，送雄留其雌。人生阻歡會，神物亦別離。", "碧樹感秋落，佳人無還期。夜琴為君咽，浮雲為君滋。", "愛而傷不見，星漢徒參差。", "幽居盼天造，胡息運行機。春葩妍既榮，秋葉瘁以飛。", "滔滔川之逝，日沒月光輝。所貴法幹健，於道悟入微。", "任彼聲勢徒，得志方誇毗。", "浮生果何慕，老去羨介推。陶令何足錄，彭澤歸已遲。", "空負漉酒巾，乞食形諸詩。吾惟抱貞素，悠悠白雲期。"]'),
('yuding-15','傷子','顧況','唐','御定全唐诗','yuding','','[]','老夫哭愛子，日暮千行血。聲逐斷猿悲，跡隨飛鳥滅。',36,'御定全唐詩/json/264.json','["老夫哭愛子，日暮千行血。聲逐斷猿悲，跡隨飛鳥滅。", "老夫已七十，不作多時別。"]'),
('yuding-16','春遊曲二首','顧況','唐','御定全唐诗','yuding','','[]','游童蘇合帶，倡女蒲葵扇。初日映城時，相思忽相見。',96,'御定全唐詩/json/264.json','["游童蘇合帶，倡女蒲葵扇。初日映城時，相思忽相見。", "褰裳踏露草，理鬢回花面。薄暮不同歸，留情此芳甸。", "柘彈連錢馬，銀鉤妥墮鬟。采桑春陌上，踏草夕陽間。", "意合詞先露，心誠貌卻閑。明朝若相憶，雲雨出巫山。"]'),
('yuding-17','從軍行二首','顧況','唐','御定全唐诗','yuding','','[]','弭節結徒侶，速征赴龍城。單于近突圍，烽燧屢夜驚。',168,'御定全唐詩/json/264.json','["弭節結徒侶，速征赴龍城。單于近突圍，烽燧屢夜驚。", "長弓挽滿月，劍華霜雪明。遠道百草殞，峭覺寒風生。", "風寒欲砭肌，爭奈裘襖輕。回首家不見，候雁空中鳴。", "笳奏遝以哀，肅肅趣嚴程。寄語塞外胡，擁騎休橫行。", "少年膽氣粗，好勇萬人敵。仗劍出門去，三邊正艱厄。", "怒目時一呼，萬騎皆辟易。殺人蓬麻輕，走馬汗血滴。", "醜虜何足清，天山坐寧謐。不有封侯相，徒負幽並客。"]'),
('yuding-18','塞上曲','顧況','唐','御定全唐诗','yuding','','[]','黠虜初南下，塵飛塞北境。漢將懷不平，讎擾當遠屏。',60,'御定全唐詩/json/264.json','["黠虜初南下，塵飛塞北境。漢將懷不平，讎擾當遠屏。", "金革臥不暖，起舞霜月冷。點軍三十千，部伍嚴以整。", "酣戰祈成功，于焉罷邊釁。"]'),
('yuding-19','弋陽溪中望仙人城','顧況','唐','御定全唐诗','yuding','','[]','何草乏靈姿，無山不孤絕。我行雖雲蹇，偶勝聊換節。',60,'御定全唐詩/json/264.json','["何草乏靈姿，無山不孤絕。我行雖雲蹇，偶勝聊換節。", "上界浮中流，光響洞明滅。晚禽曝霜羽，寒魚依石發。", "自有無還心，隔波望松雪。"]'),
('yuding-20','嚴公釣台作','顧況','唐','御定全唐诗','yuding','','[]','靈芝產遐方，威鳳家重霄。嚴生何耿潔，托志肩夷巢。',72,'御定全唐詩/json/264.json','["靈芝產遐方，威鳳家重霄。嚴生何耿潔，托志肩夷巢。", "漢後雖則貴，子陵不知高。糠秕當世道，長揖夔龍朝。", "掃門彼何人，升降不同朝。舍舟遂長往，山谷多清飆。"]'),
('yuding-21','蕭寺偃松','顧況','唐','御定全唐诗','yuding','','[]','淒淒百卉病，亭亭雙松迥。直上古寺深，橫拂秋殿冷。',48,'御定全唐詩/json/264.json','["淒淒百卉病，亭亭雙松迥。直上古寺深，橫拂秋殿冷。", "輕響入龜目，片陰棲鶴頂。山中多好樹，可憐無比並。"]'),
('yuding-22','獨遊青龍寺','顧況','唐','御定全唐诗','yuding','','[]','春風入香刹，暇日獨遊衍。曠然蓮花台，作禮月光面。',108,'御定全唐詩/json/264.json','["春風入香刹，暇日獨遊衍。曠然蓮花台，作禮月光面。", "乘茲第八識，出彼超二見。擺落區中緣，無邊廣弘願。", "長廊朝雨畢，古木時禽囀。積翠曖遙原，雜英紛似霰。", "鳳城騰日窟，龍首橫天堰。蟻步避危階，蠅飛響深殿。", "大通智勝佛，幾劫道場現。"]'),
('yuding-23','初秋蓮塘歸','顧況','唐','御定全唐诗','yuding','','[]','秋光淨無跡，蓮消錦雲紅。只有溪上山，還識揚舲翁。',36,'御定全唐詩/json/264.json','["秋光淨無跡，蓮消錦雲紅。只有溪上山，還識揚舲翁。", "如何白蘋花，幽渚笑涼風。"]'),
('yuding-24','從江西至彭蠡入浙西淮南界道中寄齊相公','顧況','唐','御定全唐诗','yuding','','[]','大賢舊丞相，作鎮江山雄。自鎮江山來，何人得如公。',276,'御定全唐詩/json/264.json','["大賢舊丞相，作鎮江山雄。自鎮江山來，何人得如公。", "處士待徐孺，仙人期葛洪。一身控上游，八郡趨下風。", "比屋除畏溺，林塘曳煙虹。生人罷虔劉，井稅均且充。", "大府肅無事，歡然接悲翁。心清百丈泉，目送孤飛鴻。", "數年鄱陽掾，抱責棲微躬。首陽及汨羅，無乃褊其衷。", "楊朱並阮籍，未免哀途窮。四賢雖得仁，此怨何匆匆。", "老氏齊寵辱，於陵一窮通。本師留度門，平等冤親同。", "能依二諦法，了達三輪空。真境靡方所，出離內外中。", "無邊盡未來，定惠雙修功。蹇步慚寸進，飾裝隨轉蓬。", "朝行楚水陰，夕宿吳洲東。吳洲複白雲，楚水飄丹楓。", "晚霞燒回潮，千里光曈曈。蓂開海上影，桂吐淮南叢。", "何當翼明庭，草木生春融。"]'),
('yuding-25','寄上兵部韓侍郎奉呈李戶部、盧刑部、杜三侍郎','顧況','唐','御定全唐诗','yuding','','[]','道路五千里，門闌三十年。當時攜手人，今日無半全。',181,'御定全唐詩/json/264.json','["道路五千里，門闌三十年。當時攜手人，今日無半全。", "詠題官舍內，賦韻僧房前。公登略彴橋，況榜龍fp船。", "遠寺吐朱閣，春潮浮綠煙。鵷鴻翔鄧林，沙鴇飛吳田。", "諸子紛出祖，中宵久留連。坐客三千人，皆稱主人賢。", "國士分如此，家臣亦依然。身在薜蘿中，頭刺文案邊。", "故吏已重疊，門生從聯翩。得罪為何名，無階問皇天。", "出門多岐路，命駕無由緣。伏承諸侍郎，顧念猶迍邅。", "聖代逢三宥，營魂空九遷。"]'),
('yuding-26','長安竇明府後亭','顧況','唐','御定全唐诗','yuding','','[]','君為長安令，我美長安政。五日一朝天，南山對明鏡。',72,'御定全唐詩/json/264.json','["君為長安令，我美長安政。五日一朝天，南山對明鏡。", "鳥飛青苔院，水木相輝映。客至南雲鄉，絲桐展歌詠。", "吏人何蕭蕭，終歲無喧競。欲識明府賢，邑中多百姓。"]'),
('yuding-27','謝王郎中見贈琴鶴','顧況','唐','御定全唐诗','yuding','','[]','此琴等焦尾，此鶴方胎生。赴節何徘徊，理感物自並。',96,'御定全唐詩/json/264.json','["此琴等焦尾，此鶴方胎生。赴節何徘徊，理感物自並。", "獨立江海上，一彈天地清。朱弦動瑤華，白羽飄玉京。", "因想羨門輩，眇然四體輕。子喬翔鄧林，王母遊層城。", "忽如啟靈署，鸞鳳相和鳴。何由玉女床，去食琅玕英。"]'),
('yuding-28','和翰林吳舍人兄弟西齋','顧況','唐','御定全唐诗','yuding','','[]','君家誠易知，易知複難同。新裁尺一詔，早入明光宮。',96,'御定全唐詩/json/264.json','["君家誠易知，易知複難同。新裁尺一詔，早入明光宮。", "西齋何其高，上與星漢通。永懷洞庭石，春色相玲瓏。", "久懷巴峽泉，夜落君絲桐。信是怡神所，迢迢蔑華嵩。", "鳥飛晴雲滅，疊嶂盤虛空。君家誠易知，易知意難窮。"]'),
('yuding-29','望初月簡於吏部','顧況','唐','御定全唐诗','yuding','','[]','泬寥中秋夜，坐見如鉤月。始從西南升，又欲西南沒。',48,'御定全唐詩/json/264.json','["泬寥中秋夜，坐見如鉤月。始從西南升，又欲西南沒。", "全移河上影，暫透林間缺。縱待三五時，終為千里別。"]'),
('yuding-30','上湖至破山贈文周蕭元植','顧況','唐','御定全唐诗','yuding','','[]','一別二十年，依依過故轍。湖上非往態，夢想頻虛結。',60,'御定全唐詩/json/264.json','["一別二十年，依依過故轍。湖上非往態，夢想頻虛結。", "二子伴我行，我行感徂節。後人應不識，前事寒泉咽。", "一別二十年，人堪幾回別。"]'),
('yuding-31','酬信州劉侍郎兄','顧況','唐','御定全唐诗','yuding','','[]','劉兄本知命，屈伸不介懷。南州管靈山，可惜曠土棲。',84,'御定全唐詩/json/264.json','["劉兄本知命，屈伸不介懷。南州管靈山，可惜曠土棲。", "樵隱同一徑，竹樹薄西齋。鳥陵嶂合杳，月配波徘徊。", "薄宦修禮數，長景謝譚諧。願為南州民，輸稅事鉏犁。", "胡為走不止，風雨驚邅回。"]'),
('yuding-32','奉酬劉侍郎','顧況','唐','御定全唐诗','yuding','','[]','幾回新秋影，璧滿蟾又缺。鏡破似傾台，輪斜同覆轍。',48,'御定全唐詩/json/264.json','["幾回新秋影，璧滿蟾又缺。鏡破似傾台，輪斜同覆轍。", "雖分上林桂，還照滄洲雪。暫伴憔悴人，歸華耿不滅。"]'),
('yuding-33','酬本部韋左司','顧況','唐','御定全唐诗','yuding','','[]','好鳥依佳樹，飛雨灑高城。況與二三子，列坐分兩楹。',96,'御定全唐詩/json/264.json','["好鳥依佳樹，飛雨灑高城。況與二三子，列坐分兩楹。", "文雅一何盛，林塘含餘清。府君未歸朝，遊子不待晴。", "白雲帝城遠，滄江楓葉鳴。卻略欲一言，零淚和酒傾。", "寸心久摧折，別離重骨驚。安得淩風翰，肅肅賓天京。"]'),
('yuding-34','酬房杭州','顧況','唐','御定全唐诗','yuding','','[]','郡樓何其曠，亭亭廣而深。故人牧餘杭，留我披胸衿。',96,'御定全唐詩/json/264.json','["郡樓何其曠，亭亭廣而深。故人牧餘杭，留我披胸衿。", "滿篋閱新作，璧玉誕清音。流水入洞天，窅豁欲淩臨。", "辟險延北阜，薙道陟南岑。朝從山寺還，醒醉動笑吟。", "荷花十餘裏，月色攢湖林。父老惜使君，卻欲速華簪。"]'),
('yuding-35','酬漳州張九使君','顧況','唐','御定全唐诗','yuding','','[]','故人窮越徼，狂生起悲愁。山海萬里別，草木十年秋。',120,'御定全唐詩/json/264.json','["故人窮越徼，狂生起悲愁。山海萬里別，草木十年秋。", "鞭馬廣陵橋，出祖張漳州。促膝墮簪珥，辟幌戛琳球。", "短題自茲簡，華篇詎能酬。無階承明庭，高步相追遊。", "南方榮桂枝，淩冬舍溫裘。猿吟郡齋中，龍靜檀欒流。", "薜鹿莫徭洞，網魚盧亭洲。心安處處安，處處思遐陬。"]'),
('yuding-36','在滁苦雨歸桃花崦傷親友略盡','顧況','唐','御定全唐诗','yuding','','[]','廢棄忝殘生，後來亦先夭。詩人感風雨，長夜何時曉。',72,'御定全唐詩/json/264.json','["廢棄忝殘生，後來亦先夭。詩人感風雨，長夜何時曉。", "去國宦情無，近鄉歸夢少。庇身絕中授，甘靜忘外擾。", "麗景變重陰，洞山空木表。靈潮若可通，寄謝西飛鳥。"]'),
('yuding-37','苦雨','顧況','唐','御定全唐诗','yuding','','[]','朝與佳人期，碧樹生紅萼。暮與佳人期，飛雨灑清閣。',72,'御定全唐詩/json/264.json','["朝與佳人期，碧樹生紅萼。暮與佳人期，飛雨灑清閣。", "佳人窅何許，中夜心寂寞。試憶花正開，複驚葉初落。", "行騎飛泉鹿，臥聽雙海鶴。嘉願有所從，安得處其薄。"]'),
('yuding-38','贈別崔十三長官','顧況','唐','御定全唐诗','yuding','','[]','真玉燒不熱，寶劍拗不折。欲別崔俠心，崔俠心如鐵。',108,'御定全唐詩/json/264.json','["真玉燒不熱，寶劍拗不折。欲別崔俠心，崔俠心如鐵。", "複如金剛鎖，無有功不徹。仍於直道中，行事不詆訐。", "崔俠兩兄弟，垂范繼芳烈。相識三十年，致書字不滅。", "我來宣城郡，飲水仰清潔。藹藹北阜松，峨峨南山雪。", "顧生歸山去，知作幾年別。"]'),
('yuding-39','哭從兄萇','顧況','唐','御定全唐诗','yuding','','[]','洞庭違鄂渚，嫋嫋秋風時。何人不客遊，獨與帝子期。',180,'御定全唐詩/json/264.json','["洞庭違鄂渚，嫋嫋秋風時。何人不客遊，獨與帝子期。", "黃鵠鎩飛翅，青雲歎沈姿。身終一騎曹，高蓋者為誰。", "從駕至梁漢，金根複京師。皇恩溢九垠，不記屠沽兒。", "立身有高節，滿卷多好詩。赫赫承明庭，群公默無詞。", "草木正搖落，哭兄鄱水湄。共居雲陽裏，轗軻多別離。", "人生倏忽間，旅襯飄若遺。稚子新學拜，枯楊生一枝。", "人生倏忽間，精爽無不之。舊國數千里，家人由未知。", "人生倏忽間，安用才士為。"]'),
('yuding-40','華山西岡游贈隱玄叟','顧況','唐','御定全唐诗','yuding','','[]','群峰郁初霽，潑黛若鬟沐。失風鼓唅呀，搖撼千灌木。',84,'御定全唐詩/json/264.json','["群峰郁初霽，潑黛若鬟沐。失風鼓唅呀，搖撼千灌木。", "木葉微墮黃，石泉淨停綠。危磴蘿薜牽，迥步入幽谷。", "我心寄青霞，世事慚蒼鹿。遂令巢許輩，于焉謝塵俗。", "想是悠悠雲，可契去留躅。"]'),
('yuding-41','歸陽蕭寺有丁行者能修無生忍擔水施僧況歸命稽首作詩','顧況','唐','御定全唐诗','yuding','','[]','化佛示持帚，仲尼稱執鞭。列生禦風歸，飼豕如人焉。',468,'御定全唐詩/json/264.json','["化佛示持帚，仲尼稱執鞭。列生禦風歸，飼豕如人焉。", "曹溪第六祖，踏碓逾三年。伊人自何方，長綬趨遙泉。", "開士行何苦，雙瓶胝兩肩。蕭寺百餘僧，東廚正揚煙。", "露足沙石裂，外形巾褐穿。若其有此身，豈得安穩眠。", "獨出違順境，不為寒暑還。大聖於其中，領我心之虔。", "萬法常空滅，無生因忍全。一國一釋迦，一燈分百千。", "永願遺世知，現身彌勒前。潛容偏虛空，靈響不可傳。", "智慧舍利佛，神通自干連。阿若憍陳如，迦葉迦旃延。", "左右二菩薩，文殊並普賢。身披六銖衣，億劫為大仙。", "寶塔寶樓閣，重簷交梵天。譬如一明珠，共贊光白圓。", "天魔波旬等，降伏金剛堅。野叉羅刹鬼，亦赦塵垢纏。", "乃致金翅鳥，吞龍護洪淵。一十一眾中，身意皆快然。", "八河注大海，中有楞伽船。佛法付國王，平等無頗偏。", "天子事端拱，大臣行其權。玉堂無蠅飛，五月冰凜筵。", "盡力答明主，猶自招罪愆。九族無白身，百花動嬋娟。", "神聖惡如此，物華不能妍。祿山一微胡，驅馬來自燕。", "宛彼宮闕麗，如何犬羊膻。苦哉千萬人，流血成丹川。", "此輩之死後，鑊湯所熬煎。業風吹其魂，猛火燒其煙。", "獨有丁行者，無憂樹枝邊。市頭盲老人，長者乞一錢。", "韜照多密用，為君吟此篇。"]'),
('yuding-42','大茅嶺東新居憶亡子從真','顧況','唐','御定全唐诗','yuding','','[]','谷鳥猶呼兒，山人夕沾襟。懷哉隔生死，悵矣徒登臨。',180,'御定全唐詩/json/264.json','["谷鳥猶呼兒，山人夕沾襟。懷哉隔生死，悵矣徒登臨。", "東門憂不入，西河遇亦深。古來失中道，偶向經中尋。", "大象無停輪，倏忽成古今。其夭非不幸，煉形由太陰。", "凡欲攀雲階，譬如火鑄金。虛室留舊劄，洞房掩閑琴。", "泉源登方諸，上有空青林。仿佛通寤寐，蕭寥邈微音。", "軟草被汀洲，鮮雲略浮沈。赬景宣疊麗，紺波響飄淋。", "石窟含雲巢，迢迢耿南岑。悲恨自茲斷，情塵詎能侵。", "真靜一時變，坐起唯從心。"]'),
('yuding-0','烏啼曲二首','顧況','唐','御定全唐诗','yuding','','[]','玉房掣鎖聲翻葉，銀箭添泉繞霜堞。畢逋撥剌月銜城，',70,'御定全唐詩/json/265.json','["玉房掣鎖聲翻葉，銀箭添泉繞霜堞。畢逋撥剌月銜城，", "搖風雜佩耿華燭，夜聽羽人彈此曲。東方曈曈赤日旭。", "月出江林西，江林寂寂城鴉啼。昔人何處為此曲，"]'),
('yuding-1','幽居弄','顧況','唐','御定全唐诗','yuding','','[]','苔衣生，花露滴，月入西林蕩東壁。扣商占角兩三聲，',40,'御定全唐詩/json/265.json','["苔衣生，花露滴，月入西林蕩東壁。扣商占角兩三聲，", "關情命曲寄惆悵，久別山南山裏人。"]'),
('yuding-2','公子行','顧況','唐','御定全唐诗','yuding','','[]','輕薄兒，面如玉，紫陌春風纏馬足。雙鐙懸金縷鶻飛，',48,'御定全唐詩/json/265.json','["輕薄兒，面如玉，紫陌春風纏馬足。雙鐙懸金縷鶻飛，", "紅肌拂拂酒光獰，當街背拉金吾行。朝遊冬冬鼓聲發，"]'),
('yuding-3','古離別','顧況','唐','御定全唐诗','yuding','','[]','西江上，風動麻姑嫁時浪。西山為水水為塵，',20,'御定全唐詩/json/265.json','["西江上，風動麻姑嫁時浪。西山為水水為塵，"]'),
('yuding-4','長安道','顧況','唐','御定全唐诗','yuding','','[]','長安道，人無衣，馬無草，何不歸來山中老。',20,'御定全唐詩/json/265.json','["長安道，人無衣，馬無草，何不歸來山中老。"]'),
('yuding-5','龍宮操','顧況','唐','御定全唐诗','yuding','','[]','龍宮月明光參差，精衛銜石東飛時。鮫人織綃采藕絲，',24,'御定全唐詩/json/265.json','["龍宮月明光參差，精衛銜石東飛時。鮫人織綃采藕絲，"]'),
('yuding-6','梁廣畫花歌','顧況','唐','御定全唐诗','yuding','','[]','王母欲過劉徹家，飛瓊夜入雲輧車。紫書分付與青鳥，',44,'御定全唐詩/json/265.json','["王母欲過劉徹家，飛瓊夜入雲輧車。紫書分付與青鳥，", "手把梁生畫花看，凝嚬掩笑心相許。心相許，"]'),
('yuding-7','送別日晚歌','顧況','唐','御定全唐诗','yuding','','[]','日窅窅兮下山，望佳人兮不還。花落兮屋上，',34,'御定全唐詩/json/265.json','["日窅窅兮下山，望佳人兮不還。花落兮屋上，", "老不可兮更少，君何為兮輕別。"]'),
('yuding-8','行路難三首','顧況','唐','御定全唐诗','yuding','','[]','君不見擔雪塞井空用力，炊砂作飯豈堪食。',181,'御定全唐詩/json/265.json','["君不見擔雪塞井空用力，炊砂作飯豈堪食。", "一生肝膽向人盡，相識不如不相識。冬青樹上掛淩霄，", "行路難，行路難，何處是平道。中心無事當富貴，", "君不見少年頭上如雲發，少壯如雲老如雪。", "豈知灌頂有醍醐，能使清涼頭不熱。呂梁之水掛飛流，", "行路難，行路難。昔少年，今已老。前朝竹帛事皆空，", "君不見古人燒水銀，變作北邙山上塵。藕絲掛在虛空中，", "淮王身死桂樹折，徐福一去音書絕。行路難，行路難，"]'),
('yuding-9','悲歌一','顧況','唐','御定全唐诗','yuding','','[]','邊城路，今人犁田昔人墓。岸上沙，昔日江水今人家。',48,'御定全唐詩/json/265.json','["邊城路，今人犁田昔人墓。岸上沙，昔日江水今人家。", "今人昔人共長歎，四氣相催節回換。明月皎皎入華池，"]'),
('yuding-10','《悲歌二','顧況','唐','御定全唐诗','yuding','','[]','我欲升天天隔霄，我欲渡水水無橋。我欲上山山路險，',40,'御定全唐詩/json/265.json','["我欲升天天隔霄，我欲渡水水無橋。我欲上山山路險，", "紫燕西飛欲寄書，白雲何處逢來客。"]'),
('yuding-11','《悲歌三','顧況','唐','御定全唐诗','yuding','','[]','新系青絲百尺繩，心在君家轆轤上。',32,'御定全唐詩/json/265.json','["新系青絲百尺繩，心在君家轆轤上。", "我心皎潔君不知，轆轤一轉一惆悵。"]'),
('yuding-12','悲歌四','顧況','唐','御定全唐诗','yuding','','[]','何處春風吹曉幕，江南淥水通朱閣。',32,'御定全唐詩/json/265.json','["何處春風吹曉幕，江南淥水通朱閣。", "美人二八面如花，泣向春風畏花落。"]'),
('yuding-13','悲歌五','顧況','唐','御定全唐诗','yuding','','[]','臨春風，聽春鳥；別時多，見時少。愁人夜永不得眠，',24,'御定全唐詩/json/265.json','["臨春風，聽春鳥；別時多，見時少。愁人夜永不得眠，"]'),
('yuding-14','悲歌六','顧況','唐','御定全唐诗','yuding','','[]','軒轅黃帝初得仙，鼎湖一去三千年。周流三十六洞天，',32,'御定全唐詩/json/265.json','["軒轅黃帝初得仙，鼎湖一去三千年。周流三十六洞天，", "東海青童寄消息。"]'),
('yuding-15','春草謠','顧況','唐','御定全唐诗','yuding','','[]','春草不解行，隨人上東城。正月二月色綿綿，',20,'御定全唐詩/json/265.json','["春草不解行，隨人上東城。正月二月色綿綿，"]'),
('yuding-16','苔蘚山歌','顧況','唐','御定全唐诗','yuding','','[]','野人夜夢江南山，江南山深松桂閑。野人覺後長歎息，',48,'御定全唐詩/json/265.json','["野人夜夢江南山，江南山深松桂閑。野人覺後長歎息，", "一如白雲飛出壁，二如飛雨岩前滴，三如騰虎欲咆哮，"]'),
('yuding-17','同裴觀察東湖望山歌','顧況','唐','御定全唐诗','yuding','','[]','浴鮮積翠棲靈異，石洞花宮橫半空。夜光潭上明星啟，',40,'御定全唐詩/json/265.json','["浴鮮積翠棲靈異，石洞花宮橫半空。夜光潭上明星啟，", "主人載酒東湖陰，遙望西山三四岑。"]'),
('yuding-18','八月五日歌','顧況','唐','御定全唐诗','yuding','','[]','四月八日明星出，摩耶夫人降前佛。八月五日佳氣新，',88,'御定全唐詩/json/265.json','["四月八日明星出，摩耶夫人降前佛。八月五日佳氣新，", "丹青廟裏貯姚宋，花萼樓中宴岐薛。清樂靈香幾處聞，", "率土普天無不樂，河清海晏窮寥廓。梨園弟子傳法曲，", "雲韶九奏杳然遠，唯有五陵松柏聲。"]'),
('yuding-19','露青竹杖歌','顧況','唐','御定全唐诗','yuding','','[]','鮮于仲通正當年，章仇兼瓊在蜀川。約束蜀兒采馬鞭，',184,'御定全唐詩/json/265.json','["鮮于仲通正當年，章仇兼瓊在蜀川。約束蜀兒采馬鞭，", "頭插白雲跨飛泉，采得馬鞭長且堅。浮漚丁子珠聯聯，", "飛龍閑廄馬數千，朝飲吳江夕秣燕。紅塵撲轡汗濕韉，", "蛟龍稽顙河伯虔，拓羯胡雛腳手鮮。陳閎韓幹丹青妍，", "十二樓中奏管弦，樓中美人奪神仙。爭愛大家把此鞭，", "亭亭筆直無皴節，磨捋形相一條鐵。市頭格是無人別，", "家童拾薪幾拗折，玉潤猶沾玉壘雪。碧鮮似染萇弘血，", "聖人不貴難得貨，金玉珊瑚誰買恩。"]'),
('yuding-20','金璫玉佩歌','顧況','唐','御定全唐诗','yuding','','[]','贈君金璫太霄之玉佩，金鎖禹步之流珠，五嶽真君之秘籙，',42,'御定全唐詩/json/265.json','["贈君金璫太霄之玉佩，金鎖禹步之流珠，五嶽真君之秘籙，", "借問君欲何處來，黃姑織女機邊出。"]'),
('yuding-21','瑤草春','顧況','唐','御定全唐诗','yuding','','[]','瑤草春，杳容與，江南豔歌京西舞。執心輕子都，',62,'御定全唐詩/json/265.json','["瑤草春，杳容與，江南豔歌京西舞。執心輕子都，", "月中桂樹落一枝，池上鵁鶄唳孤影。露桃穠李自成溪，", "瑤草春，丹井遠，別後相思意深淺。"]'),
('yuding-22','蕭鄲草書歌','顧況','唐','御定全唐诗','yuding','','[]','蕭子草書人不及，洞庭葉落秋風急。上林花開春露濕，',40,'御定全唐詩/json/265.json','["蕭子草書人不及，洞庭葉落秋風急。上林花開春露濕，", "若把君書比仲將，不知誰在淩雲閣。"]'),
('yuding-23','範山人畫山水歌','顧況','唐','御定全唐诗','yuding','','[]','山崢嶸，水泓澄。漫漫汗汗一筆耕，一草一木棲神明。',44,'御定全唐詩/json/265.json','["山崢嶸，水泓澄。漫漫汗汗一筆耕，一草一木棲神明。", "忽如空中有物，物中有聲。複如遠道望鄉客，"]'),
('yuding-24','嵇山道芬上人畫山水歌','顧況','唐','御定全唐诗','yuding','','[]','鏡中真僧白道芬，不服朱審李將軍。淥汗平鋪洞庭水，',24,'御定全唐詩/json/265.json','["鏡中真僧白道芬，不服朱審李將軍。淥汗平鋪洞庭水，"]'),
('yuding-25','杜秀才畫立走水牛歌','顧況','唐','御定全唐诗','yuding','','[]','昆侖兒，騎白象，時時鎖著師子項。奚奴跨馬不搭鞍，',48,'御定全唐詩/json/265.json','["昆侖兒，騎白象，時時鎖著師子項。奚奴跨馬不搭鞍，", "淺草平田攃過時，大蟲著鈍幾落井。杜生知我戀滄洲，"]'),
('yuding-26','梁司馬畫馬歌','顧況','唐','御定全唐诗','yuding','','[]','畫精神，畫筋骨，一團旋風瞥滅沒。仰秣如上賀蘭山，',48,'御定全唐詩/json/265.json','["畫精神，畫筋骨，一團旋風瞥滅沒。仰秣如上賀蘭山，", "黃沙枯磧無寸草，一日行過千里道。展處把筆欲描時，"]'),
('yuding-27','丘小府小鼓歌','顧況','唐','御定全唐诗','yuding','','[]','地盤山雞猶可像，坎坎砰砰隨手長。',32,'御定全唐詩/json/265.json','["地盤山雞猶可像，坎坎砰砰隨手長。", "夜半高樓沈醉時，萬里踏橋亂山響。"]'),
('yuding-28','宜城放琴客歌','顧況','唐','御定全唐诗','yuding','','[]','佳人玉立生此方，家住邯鄲不是倡。頭髻pE鬌手爪長，',89,'御定全唐詩/json/265.json','["佳人玉立生此方，家住邯鄲不是倡。頭髻pE鬌手爪長，", "忽聞鬥酒初決絕，日暮浮雲古離別。巴猿啾啾峽泉咽，", "南山闌幹千丈雪，七十非人不暖熱。人情厭薄古共然，", "服藥不如獨自眠，從他更嫁一少年。"]'),
('yuding-29','李供奉彈箜篌歌','顧況','唐','御定全唐诗','yuding','','[]','國府樂手彈箜篌，赤黃絛索金鎝頭。早晨有敕鴛鴦殿，',204,'御定全唐詩/json/265.json','["國府樂手彈箜篌，赤黃絛索金鎝頭。早晨有敕鴛鴦殿，", "腕頭花落舞制裂，手下鳥驚飛撥剌。珊瑚席，", "小弦似春燕，喃喃向人語。手頭疾，腕頭軟，", "美女爭窺玳瑁簾，聖人卷上真珠箔。大弦長，小弦短，", "指剝蔥，腕削玉，饒鹽饒醬五味足。弄調人間不識名，", "往往從空入戶來，瞥瞥隨風落春草。草頭只覺風吹入，", "爇玉燭，點銀燈；光照手，實可憎。只照箜篌弦上手，", "王侯將相立馬迎，巧聲一日一回變。實可重，", "此州好手非一國，一國東西盡南北。除卻天上化下來，"]'),
('yuding-30','劉禪奴彈琵琶歌','顧況','唐','御定全唐诗','yuding','','[]','樂府只傳橫吹好，琵琶寫出關山道。羈雁出塞繞黃雲，',48,'御定全唐詩/json/265.json','["樂府只傳橫吹好，琵琶寫出關山道。羈雁出塞繞黃雲，", "鬼神知妙欲收響，陰風切切四面來。李陵寄書別蘇武，"]'),
('yuding-31','李湖州孺人彈箏歌','顧況','唐','御定全唐诗','yuding','','[]','武帝升天留法曲，淒情掩抑弦柱促。上陽宮人怨青苔，',48,'御定全唐詩/json/265.json','["武帝升天留法曲，淒情掩抑弦柱促。上陽宮人怨青苔，", "寸心十指有長短，妙入神處無人知。獨把梁州凡幾拍，"]'),
('yuding-32','鄭女彈箏歌','顧況','唐','御定全唐诗','yuding','','[]','鄭女八歲能彈箏，春風吹落天上聲。一聲雍門淚承睫，',24,'御定全唐詩/json/265.json','["鄭女八歲能彈箏，春風吹落天上聲。一聲雍門淚承睫，"]'),
('yuding-33','諒公洞庭孤橘歌','顧況','唐','御定全唐诗','yuding','','[]','不種自生一株橘，誰教渠向階前出，不羨江陵千木奴。',60,'御定全唐詩/json/265.json','["不種自生一株橘，誰教渠向階前出，不羨江陵千木奴。", "下生白蟻子，上生青雀雛。飛花簷蔔旃檀香，", "待取天公放恩赦，儂家定作湖中客。"]'),
('yuding-34','送行歌','顧況','唐','御定全唐诗','yuding','','[]','送行人，歌一曲，何者為泥何者玉。年華已向秋草裏，',24,'御定全唐詩/json/265.json','["送行人，歌一曲，何者為泥何者玉。年華已向秋草裏，"]'),
('yuding-35','險竿歌','顧況','唐','御定全唐诗','yuding','','[]','宛陵女兒擘飛手，長竿橫空上下走。已能輕險若平地，',96,'御定全唐詩/json/265.json','["宛陵女兒擘飛手，長竿橫空上下走。已能輕險若平地，", "翻身掛影恣騰蹋，反綰頭髻盤旋風。盤旋風，撇飛鳥；", "驚猿繞，樹枝褭。頭上打鼓不聞時，手蹉腳跌蜘蛛絲。", "忽雷掣斷流星尾，矐睒劃破蚩尤旗。若不隨仙作仙女，"]'),
('yuding-36','洛陽行送洛陽韋七明府','顧況','唐','御定全唐诗','yuding','','[]','始上龍門望洛川，洛陽桃李豔陽天。最好當年二三月，',24,'御定全唐詩/json/265.json','["始上龍門望洛川，洛陽桃李豔陽天。最好當年二三月，"]'),
('yuding-37','黃鵠樓歌送獨孤助','顧況','唐','御定全唐诗','yuding','','[]','故人西去黃鵠樓，西江之水上天流，黃鵠杳杳江悠悠。',46,'御定全唐詩/json/265.json','["故人西去黃鵠樓，西江之水上天流，黃鵠杳杳江悠悠。", "黃鵠徘徊故人別，離壺酒盡清絲絕。綠嶼沒餘煙，"]'),
('yuding-38','廬山瀑布歌送李顧','顧況','唐','御定全唐诗','yuding','','[]','飄白霓，掛丹梯。應從織女機邊落，不遣潯陽湖向西。',48,'御定全唐詩/json/265.json','["飄白霓，掛丹梯。應從織女機邊落，不遣潯陽湖向西。", "火雷劈山珠噴日，五老峰前九江溢。九江悠悠萬古情，"]'),
('yuding-39','朝上清歌','顧況','唐','御定全唐诗','yuding','','[]','潔眼朝上清，綠景開紫霞。皇皇紫微君，左右皆靈娥。',109,'御定全唐詩/json/265.json','["潔眼朝上清，綠景開紫霞。皇皇紫微君，左右皆靈娥。", "曼聲流睇，和清歌些；至陽無諼，其樂多些；旌蓋颯遝，", "瓊田瑤草，壽無涯些；君著玉衣，升玉車些；欲降瓊宮，", "啟天和兮洞靈心，和為丹兮雲為馬。", "君乘之觴於瑤池之上兮，三光羅列而在下。"]'),
('yuding-40','剡紙歌','顧況','唐','御定全唐诗','yuding','','[]','雲門路上山陰雪，中有玉人持玉節。宛委山裏禹餘糧，',48,'御定全唐詩/json/265.json','["雲門路上山陰雪，中有玉人持玉節。宛委山裏禹餘糧，", "欲寫金人金口經，寄與山陰山裏僧。手把山中紫羅筆，"]'),
('yuding-0','洛陽早春','顧況','唐','御定全唐诗','yuding','','[]','何地避春愁，終年憶舊遊。一家千裏外，百舌五更頭。',48,'御定全唐詩/json/266.json','["何地避春愁，終年憶舊遊。一家千裏外，百舌五更頭。", "客路偏逢雨，鄉山不入樓。故園桃李月，伊水向東流。"]'),
('yuding-1','步虛詞','顧況','唐','御定全唐诗','yuding','','[]','迥步遊三洞，清心禮七真。飛符超羽翼，焚火醮星辰。',48,'御定全唐詩/json/266.json','["迥步遊三洞，清心禮七真。飛符超羽翼，焚火醮星辰。", "殘藥沾雞犬，靈香出鳳麟。壺中無窄處，願得一容身。"]'),
('yuding-2','鄱陽大雲寺一公房','顧況','唐','御定全唐诗','yuding','','[]','盡日陪遊處，斜陽竹院清。定中觀有漏，言外證無生。',48,'御定全唐詩/json/266.json','["盡日陪遊處，斜陽竹院清。定中觀有漏，言外證無生。", "色界聊傳法，空門不用情。欲知相去近，鐘鼓兩聞聲。"]'),
('yuding-3','送友失意南歸','顧況','唐','御定全唐诗','yuding','','[]','衣揮京洛塵，完璞伴歸人。故國青山遍，滄江白髮新。',48,'御定全唐詩/json/266.json','["衣揮京洛塵，完璞伴歸人。故國青山遍，滄江白髮新。", "鄰荒收酒幔，屋古布苔茵。不用通名姓，漁樵共主賓。"]'),
('yuding-4','南歸','顧況','唐','御定全唐诗','yuding','','[]','老病力難任，猶多鏡雪侵。鱸魚消宦況，鷗鳥識歸心。',48,'御定全唐詩/json/266.json','["老病力難任，猶多鏡雪侵。鱸魚消宦況，鷗鳥識歸心。", "急雨江帆重，殘更驛樹深。鄉關殊可望，漸漸入吳音。"]'),
('yuding-5','閒居自述','顧況','唐','御定全唐诗','yuding','','[]','榮辱不關身，誰為疏與親。有山堪結屋，無地可容塵。',48,'御定全唐詩/json/266.json','["榮辱不關身，誰為疏與親。有山堪結屋，無地可容塵。", "白髮偏添壽，黃花不笑貧。一樽朝暮醉，陶令果何人。"]'),
('yuding-6','題歙山棲霞寺','顧況','唐','御定全唐诗','yuding','','[]','明征君舊宅，陳後主題詩。跡在人亡處，山空月滿時。',48,'御定全唐詩/json/266.json','["明征君舊宅，陳後主題詩。跡在人亡處，山空月滿時。", "寶瓶無破響，道樹有低枝。已是傷離客，仍逢靳尚祠。"]'),
('yuding-7','經廢寺','顧況','唐','御定全唐诗','yuding','','[]','不知何世界，有處似南朝。石路無人掃，松門被火燒。',48,'御定全唐詩/json/266.json','["不知何世界，有處似南朝。石路無人掃，松門被火燒。", "斷幡猶掛刹，故板尚支橋。數卷殘經在，多年字欲銷。"]'),
('yuding-8','送李道士','顧況','唐','御定全唐诗','yuding','','[]','人境年虛擲，仙源日未斜。羨君乘竹杖，辭我隱桃花。',48,'御定全唐詩/json/266.json','["人境年虛擲，仙源日未斜。羨君乘竹杖，辭我隱桃花。", "鳥去甯知路，雲飛似憶家。莫愁客鬢改，自有紫河車。"]'),
('yuding-9','酬唐起居前後見寄二首','顧況','唐','御定全唐诗','yuding','','[]','愁人空望國，驚鳥不歸林。莫話彈冠事，誰知結襪心。',96,'御定全唐詩/json/266.json','["愁人空望國，驚鳥不歸林。莫話彈冠事，誰知結襪心。", "霜凋樹吹斷，土蝕劍痕深。欲作懷沙賦，明時恥自沉。", "何處吊靈均，江邊一老人。漢儀君已接，楚奏我空頻。", "直道其如命，平生不負神。自傷庚子日，鵩鳥上承塵。"]'),
('yuding-10','奉酬茅山贈賜並簡綦毋正字','顧況','唐','御定全唐诗','yuding','','[]','玉帝居金闕，靈山幾處朝。簡書猶有畏，神理詎能超。',48,'御定全唐詩/json/266.json','["玉帝居金闕，靈山幾處朝。簡書猶有畏，神理詎能超。", "鶴廟新家近，龍門舊國遙。離懷結不斷，玉洞一吹簫。"]'),
('yuding-11','白蘋洲送客','顧況','唐','御定全唐诗','yuding','','[]','莫信梅花發，由來謾報春。不才充野客，扶病送朝臣。',48,'御定全唐詩/json/266.json','["莫信梅花發，由來謾報春。不才充野客，扶病送朝臣。", "闕下搖青佩，洲邊采白蘋。臨流不痛飲，鷗鳥也欺人。"]'),
('yuding-12','春鳥詞送元秀才入京','顧況','唐','御定全唐诗','yuding','','[]','春來繡羽齊，暮向竹林棲。禁苑銜花出，河橋隔樹啼。',48,'御定全唐詩/json/266.json','["春來繡羽齊，暮向竹林棲。禁苑銜花出，河橋隔樹啼。", "尋聲知去遠，顧影念飛低。別有無巢燕，猶窺幕上泥。"]'),
('yuding-13','別江南','顧況','唐','御定全唐诗','yuding','','[]','江城吹曉角，愁殺遠行人。漢將猶防虜，吳官欲向秦。',48,'御定全唐詩/json/266.json','["江城吹曉角，愁殺遠行人。漢將猶防虜，吳官欲向秦。", "布帆輕白浪，錦帶入紅塵。將底求名宦，平生但任真。"]'),
('yuding-14','空梁落燕泥','顧況','唐','御定全唐诗','yuding','','[]','卷幕參差燕，常銜濁水泥。為黏珠履跡，未等畫梁齊。',48,'御定全唐詩/json/266.json','["卷幕參差燕，常銜濁水泥。為黏珠履跡，未等畫梁齊。", "舊點痕猶淺，新巢緝尚低。不緣頻上落，那得此飛棲。"]'),
('yuding-15','上元夜憶長安','顧況','唐','御定全唐诗','yuding','','[]','滄州老一年，老去憶秦川。處處逢珠翠，家家聽管弦。',48,'御定全唐詩/json/266.json','["滄州老一年，老去憶秦川。處處逢珠翠，家家聽管弦。", "雲車龍闕下，火樹鳳樓前。今夜滄州夜，滄州夜月圓。"]'),
('yuding-16','酬揚州白塔寺永上人','顧況','唐','御定全唐诗','yuding','','[]','塔上是何緣，香燈續細煙。松枝當麈尾，柳絮替蠶綿。',48,'御定全唐詩/json/266.json','["塔上是何緣，香燈續細煙。松枝當麈尾，柳絮替蠶綿。", "浮草經行遍，空花義趣圓。我來雖為法，暫借一床眠。"]'),
('yuding-17','送韋秀才赴舉','顧況','唐','御定全唐诗','yuding','','[]','鄱陽中酒地，楚老獨醒年。芳桂君應折，沈灰我不然。',48,'御定全唐詩/json/266.json','["鄱陽中酒地，楚老獨醒年。芳桂君應折，沈灰我不然。", "洛橋浮逆水，關樹接非煙。唯有殘生夢，猶能到日邊。"]'),
('yuding-18','送使君','顧況','唐','御定全唐诗','yuding','','[]','天中洛陽道，海上使君歸。拂霧趨金殿，焚香入瑣闈。',48,'御定全唐詩/json/266.json','["天中洛陽道，海上使君歸。拂霧趨金殿，焚香入瑣闈。", "山亭傾別酒，野服間朝衣。他日思朱鷺，知從小苑飛。"]'),
('yuding-19','曆陽苦雨','顧況','唐','御定全唐诗','yuding','','[]','襄城秋雨晦，楚客不歸心。亥市風煙接，隋宮草路深。',48,'御定全唐詩/json/266.json','["襄城秋雨晦，楚客不歸心。亥市風煙接，隋宮草路深。", "離憂翻獨笑，用事感浮陰。夜夜空階響，唯餘蚯蚓吟。"]'),
('yuding-20','傷大理謝少卿','顧況','唐','御定全唐诗','yuding','','[]','舊館絕逢迎，新詩何處呈。空留封禪草，已作岱宗行。',48,'御定全唐詩/json/266.json','["舊館絕逢迎，新詩何處呈。空留封禪草，已作岱宗行。", "柳蠹風吹析，階崩雪繞平。無因重來此，剩哭兩三聲。"]'),
('yuding-21','經徐侍郎墓作','顧況','唐','御定全唐诗','yuding','','[]','不知山吏部，墓作石橋東。宅兆鄉關異，平生翰墨空。',48,'御定全唐詩/json/266.json','["不知山吏部，墓作石橋東。宅兆鄉關異，平生翰墨空。", "夜泉無曉日，枯樹足悲風。更想幽冥事，唯應有夢同。"]'),
('yuding-22','酅公合祔挽歌','顧況','唐','御定全唐诗','yuding','','[]','草露前朝事，荊茅聖主封。空傳餘竹帛，永絕舊歌鐘。',48,'御定全唐詩/json/266.json','["草露前朝事，荊茅聖主封。空傳餘竹帛，永絕舊歌鐘。", "清鏡無雙影，窮泉有幾重。笳簫最悲處，風入九原松。"]'),
('yuding-23','相國晉公挽歌二首','顧況','唐','御定全唐诗','yuding','','[]','玉節朝天罷，洪爐造化新。中和方作聖，太素忽收神。',96,'御定全唐詩/json/266.json','["玉節朝天罷，洪爐造化新。中和方作聖，太素忽收神。", "盛德橫千古，高標出四鄰。欲知言不盡，處處有遺塵。", "凝笳催曉奠，丹旐向青山。夕照新塋近，秋風故吏還。", "本朝光漢代，從此掃胡關。今日天難問，浮雲滿世間。"]'),
('yuding-24','晉公魏國夫人柳氏挽歌','顧況','唐','御定全唐诗','yuding','','[]','魚軒海上遙，鸞影月中銷。雙劍來時合，孤桐去日凋。',48,'御定全唐詩/json/266.json','["魚軒海上遙，鸞影月中銷。雙劍來時合，孤桐去日凋。", "夕陽迷隴隧，秋雨咽笳簫。畫翣無留影，銘旌已度橋。"]'),
('yuding-25','義川公主挽詞','顧況','唐','御定全唐诗','yuding','','[]','弄玉吹簫後，湘靈鼓瑟時。月邊丹桂落，風底白楊悲。',48,'御定全唐詩/json/266.json','["弄玉吹簫後，湘靈鼓瑟時。月邊丹桂落，風底白楊悲。", "雜佩分泉戶，餘香出繐帷。夜台飛鏡匣，偏共掩蛾眉。"]'),
('yuding-26','憶山中','顧況','唐','御定全唐诗','yuding','','[]','春還不得還，家在最深山。蕙圃泉澆濕，松窗月映閑。',48,'御定全唐詩/json/266.json','["春還不得還，家在最深山。蕙圃泉澆濕，松窗月映閑。", "薄田臨穀口，小職向人間。去處但無事，重門深閉關。"]'),
('yuding-27','送大理張卿','顧況','唐','御定全唐诗','yuding','','[]','春色依依惜解攜，月卿今夜泊隋堤。白沙洲上江蘺長，',40,'御定全唐詩/json/266.json','["春色依依惜解攜，月卿今夜泊隋堤。白沙洲上江蘺長，", "越禽唯有南枝分，目送孤鴻飛向西。"]'),
('yuding-28','宿湖邊山寺','顧況','唐','御定全唐诗','yuding','','[]','群峰過雨澗淙淙，松下扉扃白鶴雙。香透經窗籠檜柏，',40,'御定全唐詩/json/266.json','["群峰過雨澗淙淙，松下扉扃白鶴雙。香透經窗籠檜柏，", "誰悟此生同寂滅，老禪慧力得心降。"]'),
('yuding-29','湖南客中春望','顧況','唐','御定全唐诗','yuding','','[]','鳴雁嘹嘹北向頻，淥波何處是通津。風塵海內憐雙鬢，',40,'御定全唐詩/json/266.json','["鳴雁嘹嘹北向頻，淥波何處是通津。風塵海內憐雙鬢，", "便拋印綬從歸隱，吳渚香蓴漫吐春。"]'),
('yuding-30','閒居懷舊','顧況','唐','御定全唐诗','yuding','','[]','日長鼓腹愛吾廬，洗竹澆花興有餘。騷客空傳成相賦，',40,'御定全唐詩/json/266.json','["日長鼓腹愛吾廬，洗竹澆花興有餘。騷客空傳成相賦，", "今日思來總皆罔，汗青功業又何如。"]'),
('yuding-31','寄江南鶴林寺石冰上人','顧況','唐','御定全唐诗','yuding','','[]','山川重複出，心地暗相逢。忽憶秋江月，如聞古寺鐘。',72,'御定全唐詩/json/266.json','["山川重複出，心地暗相逢。忽憶秋江月，如聞古寺鐘。", "湖平南北岸，雲抱兩三峰。定力超香象，真言攝毒龍。", "風中何處鶴，石上幾年松。為報煙霞道，人間共不容。"]'),
('yuding-32','樂府','顧況','唐','御定全唐诗','yuding','','[]','暖谷春光至，宸游近甸榮。雲隨天仗轉，風入禦簾輕。',144,'御定全唐詩/json/266.json','["暖谷春光至，宸游近甸榮。雲隨天仗轉，風入禦簾輕。", "翠蓋浮佳氣，朱樓倚太清。朝臣冠劍退，宮女管弦迎。", "細草承雕輦，繁花入幔城。文房開聖藻，武衛宿天營。", "玉醴隨觴至，銅壺逐漏行。五星含土德，萬姓徹中聲。", "親祀先崇典，躬推示勸耕。國風新正樂，農器近消兵。", "道德關河固，刑章日月明。野人同鳥獸，率舞感升平。"]'),
('yuding-33','送從兄使新羅','顧況','唐','御定全唐诗','yuding','','[]','六氣銅渾轉，三光玉律調。河宮清奉贐，海岳晏來朝。',288,'御定全唐詩/json/266.json','["六氣銅渾轉，三光玉律調。河宮清奉贐，海岳晏來朝。", "地絕提封入，天平賜貢饒。揚威輕破虜，柔服恥征遼。", "曙色黃金闕，寒聲白鷺潮。樓船非習戰，驄馬是嘉招。", "帝女飛銜石，鮫人賣淚綃。管甯雖不偶，徐市倘相邀。", "獨島緣空翠，孤霞上泬寥。蟾蜍同漢月，螮蝀異秦橋。", "水豹橫吹浪，花鷹迥拂霄。晨裝淩莽渺，夜泊記招搖。", "幾路通員嶠，何山是沃焦。颶風晴汩起，陰火暝潛燒。", "鬢髮成新髻，人參長舊苗。扶桑銜日近，析木帶津遙。", "夢向愁中積，魂當別處銷。臨川思結網，見彈欲求鴞。", "共散羲和曆，誰差甲子朝。滄波伏忠信，譯語辨謳謠。", "疊鼓鯨鱗隱，陰帆鷁首飄。南溟垂大翼，西海飲文鰩。", "指景尋靈草，排雲聽洞簫。封侯萬里外，未肯後班超。"]'),
('yuding-34','山居即事','顧況','唐','御定全唐诗','yuding','','[]','下泊降茅仙，蕭閑隱洞天。楊君閑上法，司命駐流年。',72,'御定全唐詩/json/266.json','["下泊降茅仙，蕭閑隱洞天。楊君閑上法，司命駐流年。", "崦合桃花水，窗分柳穀煙。抱孫堪種樹，倚杖問耘田。", "世事休相擾，浮名任一邊。由來謝安石，不解飲靈泉。"]'),
('yuding-35','題盧道士房','顧況','唐','御定全唐诗','yuding','','[]','秋砧響落木，共坐茅君家。唯見兩童子，門外汲井花。',72,'御定全唐詩/json/266.json','["秋砧響落木，共坐茅君家。唯見兩童子，門外汲井花。", "空壇靜白日，神鼎飛丹砂。麈尾拂霜草，金鈴搖霽霞。", "上章塵世隔，看弈桐陰斜。稽首問仙要，黃精堪餌花。"]'),
('yuding-0','夢後吟','顧況','唐','御定全唐诗','yuding','','[]','醉中還有夢，身外已無心。明鏡唯知老，青山何處深。',24,'御定全唐詩/json/267.json','["醉中還有夢，身外已無心。明鏡唯知老，青山何處深。"]'),
('yuding-1','題靈山寺','顧況','唐','御定全唐诗','yuding','','[]','覺地本隨身，靈山重結因。如何戰鳥佛，不化捕魚人。',24,'御定全唐詩/json/267.json','["覺地本隨身，靈山重結因。如何戰鳥佛，不化捕魚人。"]'),
('yuding-2','題元陽觀舊讀書房贈李范','顧況','唐','御定全唐诗','yuding','','[]','此觀十年游，此房千里宿。還來舊窗下，更取君書讀。',24,'御定全唐詩/json/267.json','["此觀十年游，此房千里宿。還來舊窗下，更取君書讀。"]'),
('yuding-3','永嘉','顧況','唐','御定全唐诗','yuding','','[]','東甌傳舊俗，風日江邊好。何處樂神聲，夷歌出煙島。',24,'御定全唐詩/json/267.json','["東甌傳舊俗，風日江邊好。何處樂神聲，夷歌出煙島。"]'),
('yuding-4','青弋江','顧況','唐','御定全唐诗','yuding','','[]','淒清回泊夜，淪波激石響。村邊草市橋，月下罟師網。',24,'御定全唐詩/json/267.json','["淒清回泊夜，淪波激石響。村邊草市橋，月下罟師網。"]'),
('yuding-5','聽山鷓鴣','顧況','唐','御定全唐诗','yuding','','[]','誰家無春酒，何處無春鳥。夜宿桃花村，踏歌接天曉。',24,'御定全唐詩/json/267.json','["誰家無春酒，何處無春鳥。夜宿桃花村，踏歌接天曉。"]'),
('yuding-6','山徑柳','顧況','唐','御定全唐诗','yuding','','[]','宛轉若遊絲，淺深栽綠崦。年年立春後，即被啼鶯占。',24,'御定全唐詩/json/267.json','["宛轉若遊絲，淺深栽綠崦。年年立春後，即被啼鶯占。"]'),
('yuding-7','石上藤','顧況','唐','御定全唐诗','yuding','','[]','空山無鳥跡，何物如人意。委曲結繩文，離披草書字。',24,'御定全唐詩/json/267.json','["空山無鳥跡，何物如人意。委曲結繩文，離披草書字。"]'),
('yuding-8','薜荔庵','顧況','唐','御定全唐诗','yuding','','[]','薜荔作禪庵，重疊庵邊樹。空山徑欲絕，也有人知處。',24,'御定全唐詩/json/267.json','["薜荔作禪庵，重疊庵邊樹。空山徑欲絕，也有人知處。"]'),
('yuding-9','芙蓉榭','顧況','唐','御定全唐诗','yuding','','[]','風擺蓮衣幹，月背鳥巢寒。文魚翻亂葉，翠羽上危欄。',24,'御定全唐詩/json/267.json','["風擺蓮衣幹，月背鳥巢寒。文魚翻亂葉，翠羽上危欄。"]'),
('yuding-10','欹松漪','顧況','唐','御定全唐诗','yuding','','[]','湛湛碧漣漪，老松欹側臥。悠揚綠蘿影，下拂波紋破。',24,'御定全唐詩/json/267.json','["湛湛碧漣漪，老松欹側臥。悠揚綠蘿影，下拂波紋破。"]'),
('yuding-11','焙茶塢','顧況','唐','御定全唐诗','yuding','','[]','新茶已上焙，舊架憂生醭。旋旋續新煙，呼兒劈寒木。',24,'御定全唐詩/json/267.json','["新茶已上焙，舊架憂生醭。旋旋續新煙，呼兒劈寒木。"]'),
('yuding-12','彈琴谷','顧況','唐','御定全唐诗','yuding','','[]','穀中誰彈琴，琴響穀冥寂。因君扣商調，草蟲驚暗壁。',24,'御定全唐詩/json/267.json','["穀中誰彈琴，琴響穀冥寂。因君扣商調，草蟲驚暗壁。"]'),
('yuding-13','白鷺汀','顧況','唐','御定全唐诗','yuding','','[]','靃靡汀草碧，淋森鷺毛白。夜起沙月中，思量捕魚策。',24,'御定全唐詩/json/267.json','["靃靡汀草碧，淋森鷺毛白。夜起沙月中，思量捕魚策。"]'),
('yuding-14','千松嶺','顧況','唐','御定全唐诗','yuding','','[]','終日吟天風，有時天籟止。問渠何旨意，恐落凡人耳。',24,'御定全唐詩/json/267.json','["終日吟天風，有時天籟止。問渠何旨意，恐落凡人耳。"]'),
('yuding-15','黃菊灣','顧況','唐','御定全唐诗','yuding','','[]','時菊凝曉露，露華滴秋灣。仙人釀酒熟，醉裏飛空山。',24,'御定全唐詩/json/267.json','["時菊凝曉露，露華滴秋灣。仙人釀酒熟，醉裏飛空山。"]'),
('yuding-16','臨平湖','顧況','唐','御定全唐诗','yuding','','[]','采藕平湖上，藕泥封藕節。船影入荷香，莫沖蓮柄折。',24,'御定全唐詩/json/267.json','["采藕平湖上，藕泥封藕節。船影入荷香，莫沖蓮柄折。"]'),
('yuding-17','山春洞','顧況','唐','御定全唐诗','yuding','','[]','引燭踏仙泥，時時亂乳燕。不知何道士，手把靈書卷。',24,'御定全唐詩/json/267.json','["引燭踏仙泥，時時亂乳燕。不知何道士，手把靈書卷。"]'),
('yuding-18','石竇泉','顧況','唐','御定全唐诗','yuding','','[]','吹沙複噴石，曲折仍圓旋。野客漱流時，杯粘落花片。',24,'御定全唐詩/json/267.json','["吹沙複噴石，曲折仍圓旋。野客漱流時，杯粘落花片。"]'),
('yuding-19','古仙壇','顧況','唐','御定全唐诗','yuding','','[]','遠山誰放燒，疑是壇邊醮。仙人錯下山，拍手壇邊笑。',24,'御定全唐詩/json/267.json','["遠山誰放燒，疑是壇邊醮。仙人錯下山，拍手壇邊笑。"]'),
('yuding-20','題山頂寺','顧況','唐','御定全唐诗','yuding','','[]','遙聞林下語，知是經行所。日暮香風時，諸天散花雨。',24,'御定全唐詩/json/267.json','["遙聞林下語，知是經行所。日暮香風時，諸天散花雨。"]'),
('yuding-21','天寶題壁','顧況','唐','御定全唐诗','yuding','','[]','五十餘年別，伶俜道不行。卻來書處在，惆悵似前生。',24,'御定全唐詩/json/267.json','["五十餘年別，伶俜道不行。卻來書處在，惆悵似前生。"]'),
('yuding-22','哭李別駕','顧況','唐','御定全唐诗','yuding','','[]','故人行跡滅，秋草向南悲。不欲頻回步，孀妻正哭時。',24,'御定全唐詩/json/267.json','["故人行跡滅，秋草向南悲。不欲頻回步，孀妻正哭時。"]'),
('yuding-23','春雨不聞百舌','顧況','唐','御定全唐诗','yuding','','[]','百舌春來啞，愁人共待晴。不關秋水事，飲恨亦無聲。',24,'御定全唐詩/json/267.json','["百舌春來啞，愁人共待晴。不關秋水事，飲恨亦無聲。"]'),
('yuding-24','憶鄱陽舊游','顧況','唐','御定全唐诗','yuding','','[]','悠悠南國思，夜向江南泊。楚客斷腸時，月明楓子落。',24,'御定全唐詩/json/267.json','["悠悠南國思，夜向江南泊。楚客斷腸時，月明楓子落。"]'),
('yuding-25','春懷','顧況','唐','御定全唐诗','yuding','','[]','園鶯啼已倦，樹樹隕香紅。不是春相背，當由己自翁。',24,'御定全唐詩/json/267.json','["園鶯啼已倦，樹樹隕香紅。不是春相背，當由己自翁。"]'),
('yuding-26','洛陽陌二首','顧況','唐','御定全唐诗','yuding','','[]','鶯聲滿禦堤，堤柳拂絲齊。風送名花落，香紅襯馬蹄。',48,'御定全唐詩/json/267.json','["鶯聲滿禦堤，堤柳拂絲齊。風送名花落，香紅襯馬蹄。", "珂佩逐鳴騶，王孫結伴游。金丸落飛鳥，乘興醉青樓。"]'),
('yuding-27','寄淮上柳十三','顧況','唐','御定全唐诗','yuding','','[]','葦蕭中辟戶，相映綠淮流。莫訝春潮闊，鷗邊可泊舟。',24,'御定全唐詩/json/267.json','["葦蕭中辟戶，相映綠淮流。莫訝春潮闊，鷗邊可泊舟。"]'),
('yuding-28','送李泌','顧況','唐','御定全唐诗','yuding','','[]','昔別吳堤雨，春帆去較遲。江波千里綠，□□□□□。',24,'御定全唐詩/json/267.json','["昔別吳堤雨，春帆去較遲。江波千里綠，□□□□□。"]'),
('yuding-29','山中夜宿','顧況','唐','御定全唐诗','yuding','','[]','涼月掛層峰，蘿林落葉重。掩關深畏虎，風起撼長松。',24,'御定全唐詩/json/267.json','["涼月掛層峰，蘿林落葉重。掩關深畏虎，風起撼長松。"]'),
('yuding-30','登樓','顧況','唐','御定全唐诗','yuding','','[]','高閣成長望，江流雁叫哀。淒涼故吳事，麋鹿走荒台。',24,'御定全唐詩/json/267.json','["高閣成長望，江流雁叫哀。淒涼故吳事，麋鹿走荒台。"]'),
('yuding-31','江上','顧況','唐','御定全唐诗','yuding','','[]','江清白鳥斜，蕩槳罥蘋花。聽唱菱歌晚，回塘月照沙。',24,'御定全唐詩/json/267.json','["江清白鳥斜，蕩槳罥蘋花。聽唱菱歌晚，回塘月照沙。"]'),
('yuding-32','溪上','顧況','唐','御定全唐诗','yuding','','[]','採蓮溪上女，舟小怯搖風。驚起鴛鴦宿，水雲撩亂紅。',24,'御定全唐詩/json/267.json','["採蓮溪上女，舟小怯搖風。驚起鴛鴦宿，水雲撩亂紅。"]'),
('yuding-33','田家','顧況','唐','御定全唐诗','yuding','','[]','帶水摘禾穗，夜搗具晨炊。縣帖取社長，嗔怪見官遲。',24,'御定全唐詩/json/267.json','["帶水摘禾穗，夜搗具晨炊。縣帖取社長，嗔怪見官遲。"]'),
('yuding-34','宿山中僧','顧況','唐','御定全唐诗','yuding','','[]','不爇香爐煙，蒲團坐如鐵。嘗想同夜禪，風墮松頂雪。',24,'御定全唐詩/json/267.json','["不爇香爐煙，蒲團坐如鐵。嘗想同夜禪，風墮松頂雪。"]'),
('yuding-35','梅灣','顧況','唐','御定全唐诗','yuding','','[]','白石盤盤磴，清香樹樹梅。山深不吟賞，辜負委蒼苔。',24,'御定全唐詩/json/267.json','["白石盤盤磴，清香樹樹梅。山深不吟賞，辜負委蒼苔。"]'),
('yuding-36','思歸','顧況','唐','御定全唐诗','yuding','','[]','不能經綸大經，甘作草莽閑臣。',28,'御定全唐詩/json/267.json','["不能經綸大經，甘作草莽閑臣。", "青瑣應須長別，白雲漫與相親。"]'),
('yuding-37','歸山作','顧況','唐','御定全唐诗','yuding','','[]','心事數莖白髮，生涯一片青山。',28,'御定全唐詩/json/267.json','["心事數莖白髮，生涯一片青山。", "空林有雪相待，古道無人獨還。"]'),
('yuding-38','過山農家','顧況','唐','御定全唐诗','yuding','','[]','板橋人渡泉聲，茅簷日午雞鳴。',28,'御定全唐詩/json/267.json','["板橋人渡泉聲，茅簷日午雞鳴。", "莫嗔焙茶煙暗，卻喜曬穀天晴。"]'),
('yuding-39','代佳人贈別','顧況','唐','御定全唐诗','yuding','','[]','萬里行人欲渡溪，千行珠淚滴為泥。',32,'御定全唐詩/json/267.json','["萬里行人欲渡溪，千行珠淚滴為泥。", "已成殘夢隨君去，猶有驚烏半夜啼。"]'),
('yuding-40','憶故園','顧況','唐','御定全唐诗','yuding','','[]','惆悵多山人複稀，杜鵑啼處淚沾衣。',32,'御定全唐詩/json/267.json','["惆悵多山人複稀，杜鵑啼處淚沾衣。", "故園此去千餘裏，春夢猶能夜夜歸。"]'),
('yuding-41','題葉道士山房','顧況','唐','御定全唐诗','yuding','','[]','水邊垂柳赤欄橋，洞裏仙人碧玉簫。',32,'御定全唐詩/json/267.json','["水邊垂柳赤欄橋，洞裏仙人碧玉簫。", "近得麻姑音信否，潯陽江上不通潮。"]'),
('yuding-42','送李秀才入京','顧況','唐','御定全唐诗','yuding','','[]','五湖秋葉滿行船，八月靈槎欲上天。',32,'御定全唐詩/json/267.json','["五湖秋葉滿行船，八月靈槎欲上天。", "君向長安餘適越，獨登秦望望秦川。"]'),
('yuding-43','越中席上看弄老人','顧況','唐','御定全唐诗','yuding','','[]','不到山陰十二春，鏡中相見白頭新。',32,'御定全唐詩/json/267.json','["不到山陰十二春，鏡中相見白頭新。", "此生不復為年少，今日從他弄老人。"]'),
('yuding-44','聽劉安唱歌','顧況','唐','御定全唐诗','yuding','','[]','子夜新聲何處傳，悲翁更憶太平年。',32,'御定全唐詩/json/267.json','["子夜新聲何處傳，悲翁更憶太平年。", "即今法曲無人唱，已逐霓裳飛上天。"]'),
('yuding-45','櫻桃曲','顧況','唐','御定全唐诗','yuding','','[]','百舌猶來上苑花，遊人獨自憶京華。',32,'御定全唐詩/json/267.json','["百舌猶來上苑花，遊人獨自憶京華。", "遙知寢廟嘗新後，敕賜櫻桃向幾家。"]'),
('yuding-46','山中','顧況','唐','御定全唐诗','yuding','','[]','野人愛向山中宿，況在葛洪丹井西。',32,'御定全唐詩/json/267.json','["野人愛向山中宿，況在葛洪丹井西。", "庭前有個長松樹，夜半子規來上啼。"]'),
('yuding-47','贈朱放','顧況','唐','御定全唐诗','yuding','','[]','野客歸時無四鄰，黔婁別久案常貧。',32,'御定全唐詩/json/267.json','["野客歸時無四鄰，黔婁別久案常貧。", "漁樵舊路不堪入，何處空山猶有人。"]'),
('yuding-48','江村亂後','顧況','唐','御定全唐诗','yuding','','[]','江村日暮尋遺老，江水東流橫浩浩。',32,'御定全唐詩/json/267.json','["江村日暮尋遺老，江水東流橫浩浩。", "竹裏閑窗不見人，門前舊路生青草。"]'),
('yuding-49','望簡寂觀','顧況','唐','御定全唐诗','yuding','','[]','青嶂青溪直複斜，白雞白犬到人家。',32,'御定全唐詩/json/267.json','["青嶂青溪直複斜，白雞白犬到人家。", "仙人住在最高處，向晚春泉流白花。"]'),
('yuding-50','五兩歌送張夏','顧況','唐','御定全唐诗','yuding','','[]','竿頭五兩風褭褭，水上雲帆逐飛鳥。',32,'御定全唐詩/json/267.json','["竿頭五兩風褭褭，水上雲帆逐飛鳥。", "送君初出揚州時，靄靄曈曈江溢曉。"]'),
('yuding-51','臨海所居三首','顧況','唐','御定全唐诗','yuding','','[]','此是昔年征戰處，曾經永日絕人行。',96,'御定全唐詩/json/267.json','["此是昔年征戰處，曾經永日絕人行。", "千家寂寂對流水，唯有汀洲春草生。", "此去臨溪不是遙，樓中望見赤城標。", "不知疊嶂重霞裏，更有何人度石橋。", "家在雙峰蘭若邊，一聲秋磬發孤煙。", "山連極浦鳥飛盡，月上青林人未眠。"]'),
('yuding-52','聽角思歸','顧況','唐','御定全唐诗','yuding','','[]','故園黃葉滿青苔，夢後城頭曉角哀。',32,'御定全唐詩/json/267.json','["故園黃葉滿青苔，夢後城頭曉角哀。", "此夜斷腸人不見，起行殘日影徘徊。"]'),
('yuding-53','酬柳相公','顧況','唐','御定全唐诗','yuding','','[]','天下如今已太平，相公何事喚狂生。',32,'御定全唐詩/json/267.json','["天下如今已太平，相公何事喚狂生。", "個身恰似籠中鶴，東望滄溟叫數聲。"]'),
('yuding-54','題明霞台','顧況','唐','御定全唐诗','yuding','','[]','野人本自不求名，欲向山中過一生。',32,'御定全唐詩/json/267.json','["野人本自不求名，欲向山中過一生。", "莫嫌憔悴無知己，別有煙霞似弟兄。"]'),
('yuding-55','哭絢法師','顧況','唐','御定全唐诗','yuding','','[]','楚客停橈欲問誰，白沙江草麹塵絲。',32,'御定全唐詩/json/267.json','["楚客停橈欲問誰，白沙江草麹塵絲。", "生公手種殿前樹，唯有花開鶗鴂悲。"]'),
('yuding-56','送柳宜城葬','顧況','唐','御定全唐诗','yuding','','[]','鳴笳已逐春風咽，匹馬猶依舊路嘶。',32,'御定全唐詩/json/267.json','["鳴笳已逐春風咽，匹馬猶依舊路嘶。", "遙望柳家門外樹，恐聞黃鳥向人啼。"]'),
('yuding-57','宮詞五首','顧況','唐','御定全唐诗','yuding','','[]','禁柳煙中聞曉烏，風吹玉漏盡銅壺。',160,'御定全唐詩/json/267.json','["禁柳煙中聞曉烏，風吹玉漏盡銅壺。", "內官先向蓬萊殿，金合開香瀉禦爐。", "玉樓天半起笙歌，風送宮嬪笑語和。", "月殿影開聞夜漏，水精簾卷近銀河。", "玉階容衛宿千官，風獵青旗曉仗寒。", "侍女先來薦瓊蕊，露漿新下九霄盤。", "九重天樂降神仙，步舞分行踏錦筵。", "嘈囋一聲鐘鼓歇，萬人樓下拾金錢。", "金吾持戟護新簷，天樂聲傳萬姓瞻。", "樓上美人相倚看，紅妝透出水精簾。"]'),
('yuding-58','尋桃花嶺潘三姑台','顧況','唐','御定全唐诗','yuding','','[]','桃花嶺上覺天低，人上青山馬隔溪。',32,'御定全唐詩/json/267.json','["桃花嶺上覺天低，人上青山馬隔溪。", "行到三姑學仙處，還如劉阮二郎迷。"]'),
('yuding-59','夜中望仙觀','顧況','唐','御定全唐诗','yuding','','[]','日暮銜花飛鳥還，月明溪上見青山。',32,'御定全唐詩/json/267.json','["日暮銜花飛鳥還，月明溪上見青山。", "遙知玉女窗前樹，不是仙人不得攀。"]'),
('yuding-60','送李侍禦往吳興','顧況','唐','御定全唐诗','yuding','','[]','世間只有情難說，今夜應無不醉人。',32,'御定全唐詩/json/267.json','["世間只有情難說，今夜應無不醉人。", "若向洞庭山下過，暗知澆瀝聖姑神。"]'),
('yuding-61','奉和韓晉公晦日呈諸判官','顧況','唐','御定全唐诗','yuding','','[]','江南無處不聞歌，晦日中軍樂更多。',32,'御定全唐詩/json/267.json','["江南無處不聞歌，晦日中軍樂更多。", "不是風光催柳色，卻緣威令動陽和。"]'),
('yuding-62','子規','顧況','唐','御定全唐诗','yuding','','[]','杜宇冤亡積有時，年年啼血動人悲。',32,'御定全唐詩/json/267.json','["杜宇冤亡積有時，年年啼血動人悲。", "若教恨魄皆能化，何樹何山著子規。"]'),
('yuding-63','海鷗詠','顧況','唐','御定全唐诗','yuding','','[]','萬里飛來為客鳥，曾蒙丹鳳借枝柯。',32,'御定全唐詩/json/267.json','["萬里飛來為客鳥，曾蒙丹鳳借枝柯。", "一朝鳳去梧桐死，滿目鴟鳶奈爾何。"]'),
('yuding-64','贈韋清將軍','顧況','唐','御定全唐诗','yuding','','[]','身執金吾主禁兵，腰間寶劍重橫行。',32,'御定全唐詩/json/267.json','["身執金吾主禁兵，腰間寶劍重橫行。", "接輿亦是狂歌者，更就將軍乞一聲。"]'),
('yuding-65','贈僧二首','顧況','唐','御定全唐诗','yuding','','[]','家住義興東舍溪，溪邊莎草雨無泥。',64,'御定全唐詩/json/267.json','["家住義興東舍溪，溪邊莎草雨無泥。", "上人一向心入定，春鳥年年空自啼。", "出頭皆是新年少，何處能容老病翁。", "更把浮榮喻生滅，世間無事不虛空。"]'),
('yuding-66','登樓望水','顧況','唐','御定全唐诗','yuding','','[]','鳥啼花發柳含煙，擲卻風光憶少年。',32,'御定全唐詩/json/267.json','["鳥啼花發柳含煙，擲卻風光憶少年。", "更上高樓望江水，故鄉何處一歸船。"]'),
('yuding-67','湖中','顧況','唐','御定全唐诗','yuding','','[]','青草湖邊日色低，黃茅嶂裏鷓鴣啼。',32,'御定全唐詩/json/267.json','["青草湖邊日色低，黃茅嶂裏鷓鴣啼。", "丈夫飄蕩今如此，一曲長歌楚水西。"]'),
('yuding-68','歲日作','顧況','唐','御定全唐诗','yuding','','[]','不覺老將春共至，更悲攜手幾人全。',32,'御定全唐詩/json/267.json','["不覺老將春共至，更悲攜手幾人全。", "還丹寂寞羞明鏡，手把屠蘇讓少年。"]'),
('yuding-69','山中贈客','顧況','唐','御定全唐诗','yuding','','[]','山中好處無人別，澗梅偽作山中雪。',32,'御定全唐詩/json/267.json','["山中好處無人別，澗梅偽作山中雪。", "野客相逢夜不眠，山中童子燒松節。"]'),
('yuding-70','王郎中妓席五詠：箜篌','顧況','唐','御定全唐诗','yuding','','[]','玉作搔頭金步搖，高張苦調響連宵。',32,'御定全唐詩/json/267.json','["玉作搔頭金步搖，高張苦調響連宵。", "欲知寫盡相思夢，度水尋雲不用橋。"]'),
('yuding-71','王郎中妓席五詠：舞','顧況','唐','御定全唐诗','yuding','','[]','汗浥新裝畫不成，絲催急節舞衣輕。',32,'御定全唐詩/json/267.json','["汗浥新裝畫不成，絲催急節舞衣輕。", "落花繞樹疑無影，回雪從風暗有情。"]'),
('yuding-72','王郎中妓席五詠：歌','顧況','唐','御定全唐诗','yuding','','[]','柳拂青樓花滿衣，能歌宛轉世應稀。',32,'御定全唐詩/json/267.json','["柳拂青樓花滿衣，能歌宛轉世應稀。", "空中幾處聞清響，欲繞行雲不遣飛。"]'),
('yuding-73','王郎中妓席五詠：箏','顧況','唐','御定全唐诗','yuding','','[]','秦聲楚調怨無窮，隴水胡笳咽複通。',32,'御定全唐詩/json/267.json','["秦聲楚調怨無窮，隴水胡笳咽複通。", "莫遣黃鶯花裏囀，參差撩亂妒春風。"]'),
('yuding-74','王郎中妓席五詠：笙','顧況','唐','御定全唐诗','yuding','','[]','欲寫人間離別心，須聽鳴鳳似龍吟。',32,'御定全唐詩/json/267.json','["欲寫人間離別心，須聽鳴鳳似龍吟。", "江南曲盡歸何處，洞水山雲知淺深。"]'),
('yuding-75','送李山人還玉溪','顧況','唐','御定全唐诗','yuding','','[]','好鳥共鳴臨水樹，幽人獨欠買山錢。',32,'御定全唐詩/json/267.json','["好鳥共鳴臨水樹，幽人獨欠買山錢。", "若為種得千竿竹，引取君家一眼泉。"]'),
('yuding-76','送少微上人還鹿門','顧況','唐','御定全唐诗','yuding','','[]','少微不向吳中隱，為個生緣在鹿門。',32,'御定全唐詩/json/267.json','["少微不向吳中隱，為個生緣在鹿門。", "行入漢江秋月色，襄陽耆舊幾人存。"]'),
('yuding-77','宿昭應','顧況','唐','御定全唐诗','yuding','','[]','武帝祈靈太乙壇，新豐樹色繞千官。',32,'御定全唐詩/json/267.json','["武帝祈靈太乙壇，新豐樹色繞千官。", "那知今夜長生殿，獨閉山門月影寒。"]'),
('yuding-78','題琅邪上方','顧況','唐','御定全唐诗','yuding','','[]','東晉王家在此溪，南朝樹色隔窗低。',32,'御定全唐詩/json/267.json','["東晉王家在此溪，南朝樹色隔窗低。", "碑沈字滅昔人遠，谷鳥猶向寒花啼。"]'),
('yuding-79','安仁港口望仙人城','顧況','唐','御定全唐诗','yuding','','[]','樓臺采翠遠分明，聞說仙家在此城。',32,'御定全唐詩/json/267.json','["樓臺采翠遠分明，聞說仙家在此城。", "欲上仙城無路上，水邊花裏有人聲。"]'),
('yuding-80','寄秘書包監','顧況','唐','御定全唐诗','yuding','','[]','一別長安路幾千，遙知舊日主人憐。',32,'御定全唐詩/json/267.json','["一別長安路幾千，遙知舊日主人憐。", "賈生只是三年謫，獨自無才已四年。"]'),
('yuding-81','小孤山','顧況','唐','御定全唐诗','yuding','','[]','古廟楓林江水邊，寒鴉接飯雁橫天。',32,'御定全唐詩/json/267.json','["古廟楓林江水邊，寒鴉接飯雁橫天。", "大孤山遠小孤出，月照洞庭歸客船。"]'),
('yuding-82','送李秀才游嵩山','顧況','唐','御定全唐诗','yuding','','[]','嵩山石壁掛飛流，無限神仙在上頭。',32,'御定全唐詩/json/267.json','["嵩山石壁掛飛流，無限神仙在上頭。", "采得新詩題石壁，老人惆悵不同游。"]'),
('yuding-83','從剡溪至赤城','顧況','唐','御定全唐诗','yuding','','[]','靈溪宿處接靈山，窈映高樓向月閑。',32,'御定全唐詩/json/267.json','["靈溪宿處接靈山，窈映高樓向月閑。", "夜半鶴聲殘夢裏，猶疑琴曲洞房間。"]'),
('yuding-84','葉上題詩從苑中流出','顧況','唐','御定全唐诗','yuding','','[]','花落深宮鶯亦悲，上陽宮女斷腸時。',32,'御定全唐詩/json/267.json','["花落深宮鶯亦悲，上陽宮女斷腸時。", "君恩不閉東流水，葉上題詩寄與誰。"]'),
('yuding-85','崦裏桃花','顧況','唐','御定全唐诗','yuding','','[]','崦裏桃花逢女冠，林間杏葉落仙壇。',32,'御定全唐詩/json/267.json','["崦裏桃花逢女冠，林間杏葉落仙壇。", "老人方授上清籙，夜聽步虛山月寒。"]'),
('yuding-86','聽子規','顧況','唐','御定全唐诗','yuding','','[]','棲霞山中子規鳥，口邊血出啼不了。',32,'御定全唐詩/json/267.json','["棲霞山中子規鳥，口邊血出啼不了。", "山僧後夜初出定，聞似不聞山月曉。"]'),
('yuding-87','竹枝曲','顧況','唐','御定全唐诗','yuding','','[]','帝子蒼梧不復歸，洞庭葉下荊雲飛。',32,'御定全唐詩/json/267.json','["帝子蒼梧不復歸，洞庭葉下荊雲飛。", "巴人夜唱竹枝後，腸斷曉猿聲漸稀。"]'),
('yuding-88','尋僧二首','顧況','唐','御定全唐诗','yuding','','[]','方丈玲瓏花竹閑，已將心印出人間。',64,'御定全唐詩/json/267.json','["方丈玲瓏花竹閑，已將心印出人間。", "家家門外長安道，何處相逢是寶山。", "彌天釋子本高情，往往山中獨自行。", "莫怪狂人游楚國，蓮花只在淤泥生。"]'),
('yuding-89','桃花曲','顧況','唐','御定全唐诗','yuding','','[]','魏帝宮人舞鳳樓，隋家天子泛龍舟。',32,'御定全唐詩/json/267.json','["魏帝宮人舞鳳樓，隋家天子泛龍舟。", "君王夜醉春眠晏，不覺桃花逐水流。"]'),
('yuding-90','贈遠','顧況','唐','御定全唐诗','yuding','','[]','暫出河邊思遠道，卻來窗下聽新鶯。',32,'御定全唐詩/json/267.json','["暫出河邊思遠道，卻來窗下聽新鶯。", "故人一別幾時見，春草還從舊處生。"]'),
('yuding-91','早春思歸有唱竹枝歌者坐中下淚','顧況','唐','御定全唐诗','yuding','','[]','渺渺春生楚水波，楚人齊唱竹枝歌。',32,'御定全唐詩/json/267.json','["渺渺春生楚水波，楚人齊唱竹枝歌。", "與君皆是思歸客，拭淚看花奈老何。"]'),
('yuding-92','送郭秀才','顧況','唐','御定全唐诗','yuding','','[]','故人曾任丹徒令，買得青山擬獨耕。',32,'御定全唐詩/json/267.json','["故人曾任丹徒令，買得青山擬獨耕。", "不作草堂招遠客，卻將垂柳借啼鶯。"]'),
('yuding-93','宮詞','顧況','唐','御定全唐诗','yuding','','[]','長樂宮連上苑春，玉樓金殿豔歌新。',32,'御定全唐詩/json/267.json','["長樂宮連上苑春，玉樓金殿豔歌新。", "君門一入無由出，唯有宮鶯得見人。"]'),
('yuding-94','悼稚','顧況','唐','御定全唐诗','yuding','','[]','稚子比來騎竹馬，猶疑只在屋東西。',32,'御定全唐詩/json/267.json','["稚子比來騎竹馬，猶疑只在屋東西。", "莫言道者無悲事，曾聽巴猿向月啼。"]'),
('yuding-95','山僧蘭若','顧況','唐','御定全唐诗','yuding','','[]','絕頂茅庵老此生，寒雲孤木伴經行。',32,'御定全唐詩/json/267.json','["絕頂茅庵老此生，寒雲孤木伴經行。", "世人那得知幽徑，遙向青峰禮磬聲。"]'),
('yuding-96','句','顧況','唐','御定全唐诗','yuding','','[]','崦合桃花水，窗鳴柳穀泉。',86,'御定全唐詩/json/267.json','["崦合桃花水，窗鳴柳穀泉。", "頹垣化為陂，陸地堪乘舟。", "汀洲渺渺江籬短，疑是疑非兩斷腸。", "巫峽朝雲暮不歸，洞庭春水晴空滿。", "龍吟四澤欲興雨，鳳引九雛警宿烏。", "新婦磯邊月明，女兒浦口潮平。"]'),
('yuding-0','發南康夜泊灨石中','耿湋','唐','御定全唐诗','yuding','','[]','倦客乘歸舟，春溪杳將暮。群林結暝色，孤泊有佳趣。',96,'御定全唐詩/json/268.json','["倦客乘歸舟，春溪杳將暮。群林結暝色，孤泊有佳趣。", "夜山轉長江，赤月吐深樹。颯颯松上吹，泛泛花間露。", "險石俯潭渦，跳湍礙沿溯。豈唯垂堂戒，兼以臨深懼。", "稍出回雁峰，明登斬蛟柱。連雲向重山，杳未見鐘路。"]'),
('yuding-1','過王山人舊居','耿湋','唐','御定全唐诗','yuding','','[]','故宅春山中，來逢夕陽入。汲少井味變，開稀戶樞澀。',48,'御定全唐詩/json/268.json','["故宅春山中，來逢夕陽入。汲少井味變，開稀戶樞澀。", "樹朽鳥不棲，階閑雲自濕。先生何處去，惆悵空獨立。"]'),
('yuding-2','晚次昭應','耿湋','唐','御定全唐诗','yuding','','[]','落日向林路，東風吹麥隴。藤草蔓古渠，牛羊下荒塚。',48,'御定全唐詩/json/268.json','["落日向林路，東風吹麥隴。藤草蔓古渠，牛羊下荒塚。", "驪宮戶久閉，溫穀泉長湧。為問全盛時，何人最榮寵。"]'),
('yuding-3','聽早蟬歌','耿湋','唐','御定全唐诗','yuding','','[]','蟬鳴兮夕曛，聲和兮夏雲。白日兮將短，秋意兮已滿。',69,'御定全唐詩/json/268.json','["蟬鳴兮夕曛，聲和兮夏雲。白日兮將短，秋意兮已滿。", "乍悲鳴兮欲長。猶嘶澀兮多斷。風蕭蕭兮轉清，", "閑院支頤，深林倚策，猶惆悵而無語，鬢星星而已白。"]'),
('yuding-4','蘆花動','耿湋','唐','御定全唐诗','yuding','','[]','連素穗，翻秋氣，細節疏莖任長吹。共作月中聲，',22,'御定全唐詩/json/268.json','["連素穗，翻秋氣，細節疏莖任長吹。共作月中聲，"]'),
('yuding-5','賦得寒蛩','耿湋','唐','御定全唐诗','yuding','','[]','爾誰造，鳴何早，趯趯連聲遍階草。複與夜雨和，',22,'御定全唐詩/json/268.json','["爾誰造，鳴何早，趯趯連聲遍階草。複與夜雨和，"]'),
('yuding-6','宣城逢張二南史','耿湋','唐','御定全唐诗','yuding','','[]','全家宛陵客，文雅世難逢。寄食年將老，幹時計未從。',48,'御定全唐詩/json/268.json','["全家宛陵客，文雅世難逢。寄食年將老，幹時計未從。", "秋來句曲水，雨後敬亭峰。西北長安遠，登臨恨幾重。"]'),
('yuding-7','題童子寺','耿湋','唐','御定全唐诗','yuding','','[]','半偈留何處，全身棄此中。雨餘沙塔壞，月滿雪山空。',48,'御定全唐詩/json/268.json','["半偈留何處，全身棄此中。雨餘沙塔壞，月滿雪山空。", "聳刹臨回磴，朱樓間碧叢。朝朝日將暮，長對晉陽宮。"]'),
('yuding-8','夏日寄東溪隱者','耿湋','唐','御定全唐诗','yuding','','[]','日華浮野水，草色合遙空。處處山依舊，年年事不同。',48,'御定全唐詩/json/268.json','["日華浮野水，草色合遙空。處處山依舊，年年事不同。", "閒田孤壘外，暑雨片雲中。惆悵多塵累，無由訪釣翁。"]'),
('yuding-9','之江淮留別京中親故','耿湋','唐','御定全唐诗','yuding','','[]','長雲迷一雁，漸遠向南聲。已帶千霜鬢，初為萬里行。',48,'御定全唐詩/json/268.json','["長雲迷一雁，漸遠向南聲。已帶千霜鬢，初為萬里行。", "繁蟲滿夜草，連雨暗秋城。前路諸侯貴，何人重客卿。"]'),
('yuding-10','太原送許侍禦出幕歸東都','耿湋','唐','御定全唐诗','yuding','','[]','昔隨劉越石，今日獨歸時。汾水風煙冷，並州花木遲。',48,'御定全唐詩/json/268.json','["昔隨劉越石，今日獨歸時。汾水風煙冷，並州花木遲。", "荒庭增別夢，野雨失行期。莫向山陽過，鄰人夜笛悲。"]'),
('yuding-11','華州客舍奉和崔端公春城曉望','耿湋','唐','御定全唐诗','yuding','','[]','不語看芳徑，悲春懶獨行。向人微月在，報雨早霞生。',48,'御定全唐詩/json/268.json','["不語看芳徑，悲春懶獨行。向人微月在，報雨早霞生。", "貧病催年齒，風塵掩姓名。賴逢驄馬客，郢曲緩羈情。"]'),
('yuding-12','題清蘿翁雙泉','耿湋','唐','御定全唐诗','yuding','','[]','側弁向清漪，門中夕照移。異源生暗石，疊響落秋池。',48,'御定全唐詩/json/268.json','["側弁向清漪，門中夕照移。異源生暗石，疊響落秋池。", "葉擁沙痕沒，流回草蔓隨。泠泠無限意，不獨遠公知。"]'),
('yuding-13','酬李文','耿湋','唐','御定全唐诗','yuding','','[]','落照長楊苑，秋天渭水濱。初飛萬木葉，又長一年人。',48,'御定全唐詩/json/268.json','["落照長楊苑，秋天渭水濱。初飛萬木葉，又長一年人。", "貧病仍為客，艱虞更問津。多慚惠然意，今日肯相親。"]'),
('yuding-14','贈嚴維','耿湋','唐','御定全唐诗','yuding','','[]','許詢清論重，寂寞住山陰。野路接寒寺，閑門當古林。',48,'御定全唐詩/json/268.json','["許詢清論重，寂寞住山陰。野路接寒寺，閑門當古林。", "海田秋熟早，湖水夜漁深。世上窮通理，誰人奈此心。"]'),
('yuding-15','春日題苗發竹亭','耿湋','唐','御定全唐诗','yuding','','[]','春亭及策上，郎吏謝玄暉。閑詠疏篁近，高眠遠岫微。',48,'御定全唐詩/json/268.json','["春亭及策上，郎吏謝玄暉。閑詠疏篁近，高眠遠岫微。", "偏宜留野客，暫得解朝衣。猶憶東溪裏，雷雲掩故扉。"]'),
('yuding-16','題孝子陵','耿湋','唐','御定全唐诗','yuding','','[]','荒墳秋陌上，霜露正霏霏。松柏自成拱，苫廬長不歸。',48,'御定全唐詩/json/268.json','["荒墳秋陌上，霜露正霏霏。松柏自成拱，苫廬長不歸。", "浮埃積蓬鬢，流血在麻衣。何必曾參傳，千年至行稀。"]'),
('yuding-17','題莊上人房','耿湋','唐','御定全唐诗','yuding','','[]','不語焚香坐，心知道已成。流年衰此世，定力見他生。',48,'御定全唐詩/json/268.json','["不語焚香坐，心知道已成。流年衰此世，定力見他生。", "暮雪餘春冷，寒燈續晝明。尋常五侯至，敢望下階迎。"]'),
('yuding-18','宋中','耿湋','唐','御定全唐诗','yuding','','[]','日暮黃雲合，年深白骨稀。舊村喬木在，秋草遠人歸。',48,'御定全唐詩/json/268.json','["日暮黃雲合，年深白骨稀。舊村喬木在，秋草遠人歸。", "廢井莓苔厚，荒田路徑微。唯餘近山色，相對似依依。"]'),
('yuding-19','秋夜思歸','耿湋','唐','御定全唐诗','yuding','','[]','來時猶暑服，今已露漫漫。多雨逢初霽，深秋生夜寒。',48,'御定全唐詩/json/268.json','["來時猶暑服，今已露漫漫。多雨逢初霽，深秋生夜寒。", "投人心似切，為客事皆難。何處無留滯，誰能暫問看。"]'),
('yuding-20','送李端','耿湋','唐','御定全唐诗','yuding','','[]','世上許劉楨，洋洋風雅聲。客來空改歲，歸去未成名。',48,'御定全唐詩/json/268.json','["世上許劉楨，洋洋風雅聲。客來空改歲，歸去未成名。", "遠近天初暮，關河雪半晴。空懷諫書在，回首戀承明。"]'),
('yuding-21','送崔明府赴青城','耿湋','唐','御定全唐诗','yuding','','[]','清冬賓禦出，蜀道翠微間。遠霧開群壑，初陽照近關。',48,'御定全唐詩/json/268.json','["清冬賓禦出，蜀道翠微間。遠霧開群壑，初陽照近關。", "霜潭浮紫菜，雪棧繞青山。當似遺民去，柴桑政自閑。"]'),
('yuding-22','送王將軍出塞','耿湋','唐','御定全唐诗','yuding','','[]','漢家邊事重，竇憲出臨戎。絕漠秋山在，陽關舊路通。',48,'御定全唐詩/json/268.json','["漢家邊事重，竇憲出臨戎。絕漠秋山在，陽關舊路通。", "列營依茂草，吹角向高風。更就燕然石，行看奏虜功。"]'),
('yuding-23','雨中留別','耿湋','唐','御定全唐诗','yuding','','[]','東西無定客，風雨未休時。憫默此中別，飄零何處期。',48,'御定全唐詩/json/268.json','["東西無定客，風雨未休時。憫默此中別，飄零何處期。", "青山違舊隱，白髮入新詩。歲歲迷津路，生涯漸可悲。"]'),
('yuding-24','送楊將軍','耿湋','唐','御定全唐诗','yuding','','[]','一身良將後，萬里討烏孫。落日邊陲靜，秋風鼓角喧。',48,'御定全唐詩/json/268.json','["一身良將後，萬里討烏孫。落日邊陲靜，秋風鼓角喧。", "遠山當磧路，茂草向營門。生死酬恩寵，功名豈敢論。"]'),
('yuding-25','送夏侯審游蜀','耿湋','唐','御定全唐诗','yuding','','[]','暮峰和玉壘，回望不通秦。更問蜀城路，但逢巴語人。',48,'御定全唐詩/json/268.json','["暮峰和玉壘，回望不通秦。更問蜀城路，但逢巴語人。", "石林鶯囀曉，板屋月明春。若訪嚴夫子，無嫌蔔肆貧。"]'),
('yuding-26','送張侍禦赴郴州別駕','耿湋','唐','御定全唐诗','yuding','','[]','佐郡人難料，分襟日複斜。一帆隨遠水，百口過長沙。',48,'御定全唐詩/json/268.json','["佐郡人難料，分襟日複斜。一帆隨遠水，百口過長沙。", "明月江邊夜，平陵夢裏家。王孫對芳草，愁思杳無涯。"]'),
('yuding-27','送苗贇赴陽翟丞','耿湋','唐','御定全唐诗','yuding','','[]','夕陽秋草上，去馬弟兄看。年少初辭闕，時危遠效官。',48,'御定全唐詩/json/268.json','["夕陽秋草上，去馬弟兄看。年少初辭闕，時危遠效官。", "山行獨夜雨，旅宿二陵寒。詩興生何處，嵩陽羽客壇。"]'),
('yuding-28','送絳州郭參軍','耿湋','唐','御定全唐诗','yuding','','[]','遠事諸侯出，青山古晉城。連行麹水閣，獨入議中兵。',48,'御定全唐詩/json/268.json','["遠事諸侯出，青山古晉城。連行麹水閣，獨入議中兵。", "夜雨新田濕，春風曙角鳴。人傳府公政，記室有參卿。"]'),
('yuding-29','常州留別','耿湋','唐','御定全唐诗','yuding','','[]','萬里南天外，求書禹穴間。往來成白首，旦暮見青山。',48,'御定全唐詩/json/268.json','["萬里南天外，求書禹穴間。往來成白首，旦暮見青山。", "夜浦涼雲過，秋塘好月閑。殷勤陽羨桂，別此幾時攀。"]'),
('yuding-30','關山月','耿湋','唐','御定全唐诗','yuding','','[]','月明邊徼靜，戍客望鄉時。塞古柳衰盡，關寒榆發遲。',48,'御定全唐詩/json/268.json','["月明邊徼靜，戍客望鄉時。塞古柳衰盡，關寒榆發遲。", "蒼蒼萬里道，戚戚十年悲。今夜青樓上，還應照所思。"]'),
('yuding-31','代宋州將淮上乞師','耿湋','唐','御定全唐诗','yuding','','[]','唇齒幸相依，危亡故遠歸。身輕百戰出，家在數重圍。',48,'御定全唐詩/json/268.json','["唇齒幸相依，危亡故遠歸。身輕百戰出，家在數重圍。", "上將堅深壘，殘兵鬥落暉。常聞鐵劍利，早晚借餘威。"]'),
('yuding-32','秋晚臥疾寄司空拾遺曙盧少府綸','耿湋','唐','御定全唐诗','yuding','','[]','寒幾坐空堂，疏髯似積霜。老醫迷舊疾，朽藥誤新方。',48,'御定全唐詩/json/268.json','["寒幾坐空堂，疏髯似積霜。老醫迷舊疾，朽藥誤新方。", "晚果紅低樹，秋苔綠遍牆。慚非蔣生徑，不敢望求羊。"]'),
('yuding-33','贈海明上人','耿湋','唐','御定全唐诗','yuding','','[]','來自西天竺，持經奉紫微。年深梵語變，行苦俗流歸。',48,'御定全唐詩/json/268.json','["來自西天竺，持經奉紫微。年深梵語變，行苦俗流歸。", "月上安禪久，苔生出院稀。梁間有馴鴿，不去複何依。"]'),
('yuding-34','津亭有懷','耿湋','唐','御定全唐诗','yuding','','[]','津亭一望鄉，淮海晚茫茫。草沒棲洲鷺，天連映浦檣。',48,'御定全唐詩/json/268.json','["津亭一望鄉，淮海晚茫茫。草沒棲洲鷺，天連映浦檣。", "往來通楚越，旦暮易漁商。惆悵緘書畢，何人向洛陽。"]'),
('yuding-35','晚投江澤浦即事呈柳兵曹泥','耿湋','唐','御定全唐诗','yuding','','[]','落日過重霞，輕煙上遠沙。移舟沖荇蔓，轉浦入蘆花。',48,'御定全唐詩/json/268.json','["落日過重霞，輕煙上遠沙。移舟沖荇蔓，轉浦入蘆花。", "斷岸迂來客，連波漾去槎。故鄉何處在，更道向天涯。"]'),
('yuding-36','東郊別業','耿湋','唐','御定全唐诗','yuding','','[]','東皋占薄田，耕種過餘年。護藥栽山刺，澆蔬引竹泉。',48,'御定全唐詩/json/268.json','["東皋占薄田，耕種過餘年。護藥栽山刺，澆蔬引竹泉。", "晚雷期稔歲，重霧報晴天。若問幽人意，思齊沮溺賢。"]'),
('yuding-37','早朝','耿湋','唐','御定全唐诗','yuding','','[]','鐘鼓餘聲裏，千官向紫微。冒寒人語少，乘月燭來稀。',48,'御定全唐詩/json/268.json','["鐘鼓餘聲裏，千官向紫微。冒寒人語少，乘月燭來稀。", "清漏聞馳道，輕霞映瑣闈。猶看嘶馬處，未啟掖垣扉。"]'),
('yuding-38','屏居盩厔','耿湋','唐','御定全唐诗','yuding','','[]','百年心不料，一卷日相知。乘興偏難改，憂家是強為。',48,'御定全唐詩/json/268.json','["百年心不料，一卷日相知。乘興偏難改，憂家是強為。", "縣城寒寂寞，峰樹遠參差。自笑無謀者，只應道在斯。"]'),
('yuding-39','進秋隼','耿湋','唐','御定全唐诗','yuding','','[]','豈悟因羅者，迎霜獻紫微。夕陽分素臆，秋色上花衣。',48,'御定全唐詩/json/268.json','["豈悟因羅者，迎霜獻紫微。夕陽分素臆，秋色上花衣。", "舉翅雲天近，回眸燕雀稀。應隨明主意，百中有光輝。"]'),
('yuding-40','詠宣州筆','耿湋','唐','御定全唐诗','yuding','','[]','寒竹慚虛受，纖毫任幾重。影端緣守直，心勁懶藏鋒。',48,'御定全唐詩/json/268.json','["寒竹慚虛受，纖毫任幾重。影端緣守直，心勁懶藏鋒。", "落紙驚風起，搖空見露濃。丹青與文事，舍此複何從。"]'),
('yuding-41','春日洪州即事','耿湋','唐','御定全唐诗','yuding','','[]','鐘陵春日好，春水滿南塘。竹宇分朱閣，桐花間綠楊。',48,'御定全唐詩/json/268.json','["鐘陵春日好，春水滿南塘。竹宇分朱閣，桐花間綠楊。", "蹉跎看鬢色，留滯惜年芳。欲問羈愁發，秦關道路長。"]'),
('yuding-42','雪後宿王純池州草堂','耿湋','唐','御定全唐诗','yuding','','[]','宿君湖上宅，琴韻靜參差。夜雪入秋浦，孤城連貴池。',48,'御定全唐詩/json/268.json','["宿君湖上宅，琴韻靜參差。夜雪入秋浦，孤城連貴池。", "流年看共老，銜酒發中悲。良會應難再，晨雞自有期。"]'),
('yuding-43','旅次漢故畤','耿湋','唐','御定全唐诗','yuding','','[]','我行過漢畤，寥落見孤城。邑裏經多難，兒童識五兵。',48,'御定全唐詩/json/268.json','["我行過漢畤，寥落見孤城。邑裏經多難，兒童識五兵。", "廣川桑遍綠，叢薄雉連鳴。惆悵蕭關道，終軍願請纓。"]'),
('yuding-44','過三郊驛卻寄楊評事時此子郭令公欲有表薦','耿湋','唐','御定全唐诗','yuding','','[]','冉冉青衫客，悠悠白髮人。亂山孤驛暮，長路百花新。',48,'御定全唐詩/json/268.json','["冉冉青衫客，悠悠白髮人。亂山孤驛暮，長路百花新。", "終歲行他縣，全家望此身。更思君去就，早晚問平津。"]'),
('yuding-45','隴西行','耿湋','唐','御定全唐诗','yuding','','[]','雪下陽關路，人稀隴戍頭。封狐猶未剪，邊將豈無羞。',48,'御定全唐詩/json/268.json','["雪下陽關路，人稀隴戍頭。封狐猶未剪，邊將豈無羞。", "白草三冬色，黃雲萬里愁。因思李都尉，畢竟不封侯。"]'),
('yuding-46','巴陵逢洛陽鄰舍','耿湋','唐','御定全唐诗','yuding','','[]','因君知北事，流浪已忘機。客久多人識，年高眾病歸。',48,'御定全唐詩/json/268.json','["因君知北事，流浪已忘機。客久多人識，年高眾病歸。", "連雲湖色遠，度雪雁聲稀。又說家林盡，淒傷淚滿衣。"]'),
('yuding-47','哭張融','耿湋','唐','御定全唐诗','yuding','','[]','早歲能文客，中年與世違。有家孀婦少，無子吊人稀。',48,'御定全唐詩/json/268.json','["早歲能文客，中年與世違。有家孀婦少，無子吊人稀。", "繐帳塵空暗，銘旌雨不飛。依然舊鄉路，寂寞幾回歸。"]'),
('yuding-48','送友貶嶺南','耿湋','唐','御定全唐诗','yuding','','[]','暮年從遠謫，落日別交親。湖上北飛雁，天涯南去人。',48,'御定全唐詩/json/268.json','["暮年從遠謫，落日別交親。湖上北飛雁，天涯南去人。", "夢成湘浦夜，淚盡桂陽春。歲月茫茫意，何時雨露新。"]'),
('yuding-49','春日即事二首','耿湋','唐','御定全唐诗','yuding','','[]','詩書成志業，懶慢致蹉跎。聖代丹霄遠，明時白髮多。',96,'御定全唐詩/json/268.json','["詩書成志業，懶慢致蹉跎。聖代丹霄遠，明時白髮多。", "淺謀堪自笑，窮巷憶誰過。寂寞前山暮，歸人樵采歌。", "數畝東皋宅，青春獨屏居。家貧僮僕慢，官罷友朋疏。", "強飲沽來酒，羞看讀了書。閑花開滿地，惆悵複何如。"]'),
('yuding-50','贈田家翁','耿湋','唐','御定全唐诗','yuding','','[]','老人迎客處，籬落稻畦間。蠶屋朝寒閉，田家晝雨閑。',48,'御定全唐詩/json/268.json','["老人迎客處，籬落稻畦間。蠶屋朝寒閉，田家晝雨閑。", "門閭新薙草，蹊徑舊諳山。自道誰相及，邀予試往還。"]'),
('yuding-51','贈韋山人','耿湋','唐','御定全唐诗','yuding','','[]','失意成逋客，終年獨掩扉。無機狎鷗慣，多病見人稀。',48,'御定全唐詩/json/268.json','["失意成逋客，終年獨掩扉。無機狎鷗慣，多病見人稀。", "流水知行藥，孤雲伴采薇。空齋莫閑笑，心事與時違。"]'),
('yuding-52','浚公院懷舊','耿湋','唐','御定全唐诗','yuding','','[]','遠公傳教畢，身沒向他方。吊客來何見，門人閉影堂。',48,'御定全唐詩/json/268.json','["遠公傳教畢，身沒向他方。吊客來何見，門人閉影堂。", "紗燈臨古砌，塵劄在空床。寂寞疏鐘後，秋天有夕陽。"]'),
('yuding-53','雨中宿義興寺','耿湋','唐','御定全唐诗','yuding','','[]','遙夜宿東林，蟲聲階草深。高風初落葉，多雨未歸心。',48,'御定全唐詩/json/268.json','["遙夜宿東林，蟲聲階草深。高風初落葉，多雨未歸心。", "家國身猶負，星霜鬢已侵。滄洲縱不去，何處有知音。"]'),
('yuding-54','送王秘書歸江東','耿湋','唐','御定全唐诗','yuding','','[]','回首望知音，逶迤桑柘林。人歸海郡遠，路入雨天深。',48,'御定全唐詩/json/268.json','["回首望知音，逶迤桑柘林。人歸海郡遠，路入雨天深。", "萬木經秋葉，孤舟向暮心。唯餘江畔草，應見白頭吟。"]'),
('yuding-55','渭上送李藏器移家東都','耿湋','唐','御定全唐诗','yuding','','[]','求名雖有據，學稼又無田。故國三千里，新春五十年。',48,'御定全唐詩/json/268.json','["求名雖有據，學稼又無田。故國三千里，新春五十年。", "移家還作客，避地莫知賢。洛浦今何處，風帆去渺然。"]'),
('yuding-56','春尋柳先生','耿湋','唐','御定全唐诗','yuding','','[]','言是商山老，塵心莫問年。白髯垂策短，烏帽據梧偏。',48,'御定全唐詩/json/268.json','["言是商山老，塵心莫問年。白髯垂策短，烏帽據梧偏。", "酒熟飛巴雨，丹成見海田。疏雲披遠水，景動石床前。"]'),
('yuding-57','題藏公院','耿湋','唐','御定全唐诗','yuding','','[]','古院林公住，疏篁近井桃。俗年人見少，禪地自知高。',48,'御定全唐詩/json/268.json','["古院林公住，疏篁近井桃。俗年人見少，禪地自知高。", "藥草誠多喻，滄溟在一毫。仍悲次宗輩，塵事日為勞。"]'),
('yuding-58','夏夜西亭即事寄錢員外','耿湋','唐','御定全唐诗','yuding','','[]','高亭賓客散，暑夜醉相和。細汗迎衣集，微涼待扇過。',48,'御定全唐詩/json/268.json','["高亭賓客散，暑夜醉相和。細汗迎衣集，微涼待扇過。", "風還池色定，月晚樹陰多。遙想隨行者，珊珊動曉珂。"]'),
('yuding-59','與清江上人及諸公宿李八昆季宅','耿湋','唐','御定全唐诗','yuding','','[]','湯公多外友，洛社自相依。遠客還登會，秋懷欲忘歸。',48,'御定全唐詩/json/268.json','["湯公多外友，洛社自相依。遠客還登會，秋懷欲忘歸。", "驚風林果少，驟雨砌蟲稀。更過三張價，東游愧陸機。"]'),
('yuding-60','春日即事','耿湋','唐','御定全唐诗','yuding','','[]','鄰里朝光遍，披衣夜醉醒。庖廚非舊火，林木發新青。',48,'御定全唐詩/json/268.json','["鄰里朝光遍，披衣夜醉醒。庖廚非舊火，林木發新青。", "接果移天性，疏泉逐地形。清明來幾日，戴勝已堪聽。"]'),
('yuding-61','秋夜會宿李永宅憶江南舊游','耿湋','唐','御定全唐诗','yuding','','[]','偶宿俱南客，相看喜盡歸。湖山話不極，歲月念空違。',48,'御定全唐詩/json/268.json','["偶宿俱南客，相看喜盡歸。湖山話不極，歲月念空違。", "子夜高梧冷，秋陰遠漏微。那無此良會，惜在謝家稀。"]'),
('yuding-62','冬夜尋李永因書事贈之','耿湋','唐','御定全唐诗','yuding','','[]','棲遑偏降志，疵賤倍修身。近覺多衰鬢，深知獨故人。',48,'御定全唐詩/json/268.json','["棲遑偏降志，疵賤倍修身。近覺多衰鬢，深知獨故人。", "天垂五夜月，霜覆九衢塵。不待逢沮溺，而今惡問津。"]'),
('yuding-63','立春日宴高陵任明府宅','耿湋','唐','御定全唐诗','yuding','','[]','春灰今變候，密雪又霏霏。坐客同心滿，流年此會稀。',48,'御定全唐詩/json/268.json','["春灰今變候，密雪又霏霏。坐客同心滿，流年此會稀。", "風成空處亂，素積夜來飛。且共銜杯酒，陶潛不得歸。"]'),
('yuding-64','春日遊慈恩寺寄暢當','耿湋','唐','御定全唐诗','yuding','','[]','浮世今何事，空門此諦真。死生俱是夢，哀樂詎關身。',48,'御定全唐詩/json/268.json','["浮世今何事，空門此諦真。死生俱是夢，哀樂詎關身。", "遠草光連水，春篁色離塵。當從庾中庶，詩客更何人。"]'),
('yuding-65','晚秋過蘇少府','耿湋','唐','御定全唐诗','yuding','','[]','九江迷去住，群吏且因依。高木秋垂露，寒城暮掩扉。',48,'御定全唐詩/json/268.json','["九江迷去住，群吏且因依。高木秋垂露，寒城暮掩扉。", "隨雲心自遠，看草伴應稀。肯信同年友，相望青瑣闈。"]'),
('yuding-66','登鸛雀樓','耿湋','唐','御定全唐诗','yuding','','[]','久客心常醉，高樓日漸低。黃河經海內，華岳鎮關西。',48,'御定全唐詩/json/268.json','["久客心常醉，高樓日漸低。黃河經海內，華岳鎮關西。", "去遠千帆小，來遲獨鳥迷。終年不得意，空覺負東溪。"]'),
('yuding-67','賦得沙上雁','耿湋','唐','御定全唐诗','yuding','','[]','衡陽多道裏，弱羽複哀音。還塞知何日，驚弦亂此心。',48,'御定全唐詩/json/268.json','["衡陽多道裏，弱羽複哀音。還塞知何日，驚弦亂此心。", "夜陰前侶遠，秋冷後湖深。獨立汀洲意，寧知霜霰侵。"]'),
('yuding-68','夜尋盧處士','耿湋','唐','御定全唐诗','yuding','','[]','月高雞犬靜，門掩向寒塘。夜竹深茅宇，秋庭冷石床。',48,'御定全唐詩/json/268.json','["月高雞犬靜，門掩向寒塘。夜竹深茅宇，秋庭冷石床。", "住山年已遠，服藥壽偏長。虛棄如吾者，逢君益自傷。"]'),
('yuding-69','邠州留別','耿湋','唐','御定全唐诗','yuding','','[]','終歲山川路，生涯總幾何。艱難為客慣，貧賤受恩多。',48,'御定全唐詩/json/268.json','["終歲山川路，生涯總幾何。艱難為客慣，貧賤受恩多。", "暮角寒山色，秋風遠水波。無人見惆悵，垂鞚入煙蘿。"]'),
('yuding-70','贈張將軍','耿湋','唐','御定全唐诗','yuding','','[]','寥落軍城暮，重門返照間。鼓鼙經雨暗，士馬過秋閑。',48,'御定全唐詩/json/268.json','["寥落軍城暮，重門返照間。鼓鼙經雨暗，士馬過秋閑。", "慣守臨邊郡，曾營近海山。關西舊業在，夜夜夢中還。"]'),
('yuding-71','贈隱公','耿湋','唐','御定全唐诗','yuding','','[]','世間無近遠，定裏遍曾過。東海經長在，南朝寺最多。',48,'御定全唐詩/json/268.json','["世間無近遠，定裏遍曾過。東海經長在，南朝寺最多。", "暮年聊化俗，初地即摧魔。今日忘塵慮，看心義若何。"]'),
('yuding-72','贈別安邑韓少府','耿湋','唐','御定全唐诗','yuding','','[]','子真能自在，江海意何如。門掩疏塵吏，心閑閱道書。',48,'御定全唐詩/json/268.json','["子真能自在，江海意何如。門掩疏塵吏，心閑閱道書。", "古城寒欲雪，遠客暮無車。杳杳思前路，誰堪千里餘。"]'),
('yuding-73','送胡校書秩滿歸河中','耿湋','唐','御定全唐诗','yuding','','[]','古樹汾陰道，悠悠東去長。位卑仍解印，身老又還鄉。',48,'御定全唐詩/json/268.json','["古樹汾陰道，悠悠東去長。位卑仍解印，身老又還鄉。", "河水平秋岸，關門向夕陽。音書須數附，莫學晉嵇康。"]'),
('yuding-74','送河中張胄曹往太原計會回','耿湋','唐','御定全唐诗','yuding','','[]','北風長至遠，四牡向幽並。衰木新田路，寒蕪故絳城。',48,'御定全唐詩/json/268.json','["北風長至遠，四牡向幽並。衰木新田路，寒蕪故絳城。", "遙聽邊上信，遠計朔南程。料變當臨事，遙知外國情。"]'),
('yuding-75','送郭正字歸郢上','耿湋','唐','御定全唐诗','yuding','','[]','濟江篇已出，書府俸猶貧。積雪商山道，全家楚塞人。',48,'御定全唐詩/json/268.json','["濟江篇已出，書府俸猶貧。積雪商山道，全家楚塞人。", "大堤逢落日，廣漢望通津。卻別漁潭下，驚鷗那可親。"]'),
('yuding-76','題李孝廉書房','耿湋','唐','御定全唐诗','yuding','','[]','野情專易外，一室向青山。業就三編絕，心通萬事閑。',48,'御定全唐詩/json/268.json','["野情專易外，一室向青山。業就三編絕，心通萬事閑。", "鶯稀春木上，草遍暮階間。莫道歸繻在，來時棄故關。"]'),
('yuding-77','酬暢當','耿湋','唐','御定全唐诗','yuding','','[]','同遊漆沮後，已是十年餘。幾度曾相夢，何時定得書。',48,'御定全唐詩/json/268.json','["同遊漆沮後，已是十年餘。幾度曾相夢，何時定得書。", "月高城影盡，霜重柳條疏。且對尊中酒，千般想未如。"]'),
('yuding-78','留別解縣韓明府','耿湋','唐','御定全唐诗','yuding','','[]','閒人州縣厭，賤士友朋譏。朔雪逢初下，秦關獨暮歸。',48,'御定全唐詩/json/268.json','["閒人州縣厭，賤士友朋譏。朔雪逢初下，秦關獨暮歸。", "寒茅下原淺，殘雪過風微。一路何相慰，唯君能政稀。"]'),
('yuding-79','游鐘山紫芝觀','耿湋','唐','御定全唐诗','yuding','','[]','系舟仙宅下，清磬落春風。雨數芝田長，雲開石路重。',48,'御定全唐詩/json/268.json','["系舟仙宅下，清磬落春風。雨數芝田長，雲開石路重。", "古房清磴接，深殿紫煙濃。鶴駕何時去，遊人自不逢。"]'),
('yuding-80','晚秋宿裴員外寺院','耿湋','唐','御定全唐诗','yuding','','[]','仲言多麗藻，晚水獨芙蓉。梁苑仍秋過，仁祠又夜逢。',48,'御定全唐詩/json/268.json','["仲言多麗藻，晚水獨芙蓉。梁苑仍秋過，仁祠又夜逢。", "回林通暗竹，去雨帶寒鐘。原向空門裏，修持比晝龍。"]'),
('yuding-81','秋夜喜盧司直嚴少府訪宿','耿湋','唐','御定全唐诗','yuding','','[]','寂寂閉層城，悠悠此夜情。早涼過鬢髮，秋思入柴荊。',48,'御定全唐詩/json/268.json','["寂寂閉層城，悠悠此夜情。早涼過鬢髮，秋思入柴荊。", "嚴子多高趣，盧公有盛名。還如杜陵下，暫拂蔣元卿。"]'),
('yuding-82','下邽客舍喜叔孫主簿鄭少府見過','耿湋','唐','御定全唐诗','yuding','','[]','良宵複杪秋，把酒說羈遊。落木東西別，寒萍遠近流。',48,'御定全唐詩/json/268.json','["良宵複杪秋，把酒說羈遊。落木東西別，寒萍遠近流。", "蕭條旅館月，寂曆曙更籌。不是仇梅至，何人問百憂。"]'),
('yuding-83','盩厔客舍','耿湋','唐','御定全唐诗','yuding','','[]','寥寂荒壘下，客舍雨微微。門見苔生滿，心慚吏到稀。',48,'御定全唐詩/json/268.json','["寥寂荒壘下，客舍雨微微。門見苔生滿，心慚吏到稀。", "籬花看未發，海燕欲先歸。無限堪惆悵，誰家複擣衣。"]'),
('yuding-84','宿韋員外宅','耿湋','唐','御定全唐诗','yuding','','[]','傳經韋相後，賜筆漢家郎。幽閣諸生會，寒宵幾刻長。',48,'御定全唐詩/json/268.json','["傳經韋相後，賜筆漢家郎。幽閣諸生會，寒宵幾刻長。", "座中燈泛酒，簷外月如霜。人事多飄忽，邀歡詎可忘。"]'),
('yuding-85','登沃州山','耿湋','唐','御定全唐诗','yuding','','[]','沃州初望海，攜手盡時髦。小暑開鵬翼，新蓂長鷺濤。',48,'御定全唐詩/json/268.json','["沃州初望海，攜手盡時髦。小暑開鵬翼，新蓂長鷺濤。", "月如芳草遠，身比夕陽高。羊祜傷風景，誰雲異我曹。"]'),
('yuding-86','宿岐山薑明府廳','耿湋','唐','御定全唐诗','yuding','','[]','暝色休群動，秋齋遠客情。細風和雨氣，寒竹度簾聲。',48,'御定全唐詩/json/268.json','["暝色休群動，秋齋遠客情。細風和雨氣，寒竹度簾聲。", "日覺蹉跎近，天教懶慢成。誰能謁卿相，朝夕算浮榮。"]'),
('yuding-87','上巳日','耿湋','唐','御定全唐诗','yuding','','[]','共來修禊事，內顧一悲翁。玉鬢風塵下，花林絲管中。',48,'御定全唐詩/json/268.json','["共來修禊事，內顧一悲翁。玉鬢風塵下，花林絲管中。", "故山離水石，舊侶失鵷鴻。不及游魚樂，裴回蓮葉東。"]'),
('yuding-88','登樂游原','耿湋','唐','御定全唐诗','yuding','','[]','園廟何年廢，登臨有故丘。孤村連日靜，多雨及霖休。',48,'御定全唐詩/json/268.json','["園廟何年廢，登臨有故丘。孤村連日靜，多雨及霖休。", "常與秦山對，曾經漢主遊。豈知千載後，萬事水東流。"]'),
('yuding-89','題惟幹上人房','耿湋','唐','御定全唐诗','yuding','','[]','繩床茅屋下，獨坐味閑安。苦行無童子，忘機避宰官。',48,'御定全唐詩/json/268.json','["繩床茅屋下，獨坐味閑安。苦行無童子，忘機避宰官。", "是非齊已久，夏臘比應難。更悟真如性，塵心稍自寬。"]'),
('yuding-90','會鳳翔張少尹南亭','耿湋','唐','御定全唐诗','yuding','','[]','遠過張正見，詩興自依依。西府軍城暮，南庭吏事稀。',48,'御定全唐詩/json/268.json','["遠過張正見，詩興自依依。西府軍城暮，南庭吏事稀。", "草簷宜日過，花圃任煙歸。更料重關外，群僚候啟扉。"]'),
('yuding-91','早春宴高陵滑少府','耿湋','唐','御定全唐诗','yuding','','[]','且寬沈簿領，應賴酒如澠。春夜霜猶下，東城月未升。',48,'御定全唐詩/json/268.json','["且寬沈簿領，應賴酒如澠。春夜霜猶下，東城月未升。", "清言饒醉客，亂舞避寒燈。名字書仙籍，諸生病未能。"]'),
('yuding-92','寒蜂采菊蕊','耿湋','唐','御定全唐诗','yuding','','[]','遊颺下晴空，尋芳到菊叢。帶聲來蕊上，連影在香中。',48,'御定全唐詩/json/268.json','["遊颺下晴空，尋芳到菊叢。帶聲來蕊上，連影在香中。", "去住沾餘霧，高低順過風。終慚異蝴蝶，不與夢魂通。"]'),
('yuding-93','題楊著別業','耿湋','唐','御定全唐诗','yuding','','[]','柳巷向陂斜，回陽噪亂鴉。農桑子雲業，書籍蔡邕家。',48,'御定全唐詩/json/268.json','["柳巷向陂斜，回陽噪亂鴉。農桑子雲業，書籍蔡邕家。", "暮葉初翻砌，寒池轉露沙。如何守儒行，寂寞過年華。"]'),
('yuding-94','送太僕寺李丞赴都到桃林塞','耿湋','唐','御定全唐诗','yuding','','[]','遠過桃林塞，休年自昔聞。曲河隨暮草，重阜接閑雲。',48,'御定全唐詩/json/268.json','["遠過桃林塞，休年自昔聞。曲河隨暮草，重阜接閑雲。", "造父為周禦，詹嘉守晉軍。應多懷古思，落葉又紛紛。"]'),
('yuding-95','宋中','耿湋','唐','御定全唐诗','yuding','','[]','百戰無軍食，孤城陷虜塵。為傷多易子，翻吊淺為臣。',48,'御定全唐詩/json/268.json','["百戰無軍食，孤城陷虜塵。為傷多易子，翻吊淺為臣。", "漫漫東流水，悠悠南陌人。空思前事往，向曉淚沾巾。"]'),
('yuding-96','陪宴湖州公堂','耿湋','唐','御定全唐诗','yuding','','[]','謝公為楚郡，坐客是瑤林。文府重門奧，儒源積浪深。',48,'御定全唐詩/json/268.json','["謝公為楚郡，坐客是瑤林。文府重門奧，儒源積浪深。", "壺觴邀薄醉，笙磬發高音。末至才仍短，難隨白雪吟。"]'),
('yuding-97','尋覺公因寄李二端司空十四曙','耿湋','唐','御定全唐诗','yuding','','[]','少年嘗昧道，無事日悠悠。及至悟生死，尋僧已白頭。',48,'御定全唐詩/json/268.json','["少年嘗昧道，無事日悠悠。及至悟生死，尋僧已白頭。", "雲回廬瀑雨，樹落給園秋。為我謝宗許，塵中難久留。"]'),
('yuding-98','送郭秀才赴舉','耿湋','唐','御定全唐诗','yuding','','[]','鄉賦鹿鳴篇，君為貢士先。新經夢筆夜，才比棄繻年。',48,'御定全唐詩/json/268.json','["鄉賦鹿鳴篇，君為貢士先。新經夢筆夜，才比棄繻年。", "海雨沾隋柳，江潮赴楚船。相看南去雁，離恨倍潸然。"]'),
('yuding-99','送王閏','耿湋','唐','御定全唐诗','yuding','','[]','相送臨漢水，愴然望故關。江蕪連夢澤，楚雪入商山。',48,'御定全唐詩/json/268.json','["相送臨漢水，愴然望故關。江蕪連夢澤，楚雪入商山。", "語我他年舊，看君此日還。因將自悲淚，一灑別離間。"]'),
('yuding-100','送蜀客還','耿湋','唐','御定全唐诗','yuding','','[]','萬峰深積翠，路向此中難。欲暮多羈思，因高莫遠看。',48,'御定全唐詩/json/268.json','["萬峰深積翠，路向此中難。欲暮多羈思，因高莫遠看。", "卓家人寂寞，揚子業荒殘。唯見岷山水，悠悠帶月寒。"]'),
('yuding-101','送海州盧錄事','耿湋','唐','御定全唐诗','yuding','','[]','之官逢計吏，風土問如何。海口朝陽近，青州春氣多。',48,'御定全唐詩/json/268.json','["之官逢計吏，風土問如何。海口朝陽近，青州春氣多。", "郊原鵬影到，樓閣蜃雲和。損益關從事，期聽勞者歌。"]'),
('yuding-102','登鐘山館','耿湋','唐','御定全唐诗','yuding','','[]','匹馬宜春路，蕭條背館心。澗花寒夕雨，潭水黑朝林。',48,'御定全唐詩/json/268.json','["匹馬宜春路，蕭條背館心。澗花寒夕雨，潭水黑朝林。", "野市魚鹽隘，江村竹葦深。子規何處發，青樹滿高岑。"]'),
('yuding-103','秋日','耿湋','唐','御定全唐诗','yuding','','[]','照耀天山外，飛鴉幾共過。微紅拂秋漢，片白透長波。',48,'御定全唐詩/json/268.json','["照耀天山外，飛鴉幾共過。微紅拂秋漢，片白透長波。", "影促寒汀薄，光殘古木多。金霞與雲氣，散漫複相和。"]'),
('yuding-104','贈苗員外','耿湋','唐','御定全唐诗','yuding','','[]','為郎日賦詩，小謝少年時。業繼儒門後，心多道者期。',48,'御定全唐詩/json/268.json','["為郎日賦詩，小謝少年時。業繼儒門後，心多道者期。", "晚回長樂殿，新出夜明祠。行樂西園暮，春風動柳絲。"]'),
('yuding-105','詣順公問道','耿湋','唐','御定全唐诗','yuding','','[]','此身知是妄，遠遠詣支公。何法住持後，能逃生死中。',48,'御定全唐詩/json/268.json','["此身知是妄，遠遠詣支公。何法住持後，能逃生死中。", "秋苔經古徑，蘀葉滿疏叢。方便如開誘，南宗與北宗。"]'),
('yuding-106','廢慶寶寺','耿湋','唐','御定全唐诗','yuding','','[]','黃葉前朝寺，無僧寒殿開。池晴龜出暴，松暝鶴飛回。',48,'御定全唐詩/json/268.json','["黃葉前朝寺，無僧寒殿開。池晴龜出暴，松暝鶴飛回。", "古井碑橫草，陰廊畫雜苔。禪宮亦銷歇，塵世轉堪哀。"]'),
('yuding-107','赴許州留別洛中親故','耿湋','唐','御定全唐诗','yuding','','[]','淳風今變俗，末學誤為文。倖免投湘浦，那辭近汝墳。',48,'御定全唐詩/json/268.json','["淳風今變俗，末學誤為文。倖免投湘浦，那辭近汝墳。", "山遮魏闕路，日隱洛陽雲。誰念聯翩翼，煙中獨失群。"]'),
('yuding-108','送葉尊師歸處州','耿湋','唐','御定全唐诗','yuding','','[]','風馭南行遠，長山與夜江。群祆離分野，五嶽拜旌幢。',49,'御定全唐詩/json/268.json','["風馭南行遠，長山與夜江。群祆離分野，五嶽拜旌幢。", "石髓調金鼎，雲漿實玉缸。cB々吠聲曉，洞府有仙厖。"]'),
('yuding-0','酬張少尹秋日鳳翔西郊見寄','耿湋','唐','御定全唐诗','yuding','','[]','鼎氣孕河汾，英英濟舊勳。劉生曾任俠，張率自能文。',120,'御定全唐詩/json/269.json','["鼎氣孕河汾，英英濟舊勳。劉生曾任俠，張率自能文。", "官佐征西府，名齊將上軍。秋山遙出浦，野鶴暮離群。", "遠恨邊笳起，勞歌騎吏聞。廢關人不到，荒戍日空曛。", "草木涼初變，陰晴景半分。疊蟬臨積水，亂燕入過雲。", "麗藻終思我，衰髯亦為君。閑吟寡和曲，庭葉漸紛紛。"]'),
('yuding-1','春日書情寄元校書伯和相國元子','耿湋','唐','御定全唐诗','yuding','','[]','數歲平津邸，諸生出門時。羈孤力行早，疏賤托身遲。',96,'御定全唐詩/json/269.json','["數歲平津邸，諸生出門時。羈孤力行早，疏賤托身遲。", "芳草看無厭，青山到未期。貧居悲老大，春日上茅茨。", "衛玠瓊瑤色，玄成鼎鼐姿。友朋漢相府，兄弟謝家詩。", "律合聲雖應，勞歌調自悲。流年不可住，惆悵鏡中絲。"]'),
('yuding-2','奉送崔侍禦和蕃','耿湋','唐','御定全唐诗','yuding','','[]','萬里華戎隔，風沙道路秋。新恩明主啟，舊好使臣修。',72,'御定全唐詩/json/269.json','["萬里華戎隔，風沙道路秋。新恩明主啟，舊好使臣修。", "旌節隨邊草，關山見戍樓。俗殊人左衽，地遠水西流。", "日暮冰先合，春深雪未休。無論善長對，博望自封侯。"]'),
('yuding-3','春日即事','耿湋','唐','御定全唐诗','yuding','','[]','芳菲那變易，年鬢自蹉跎。室與千峰對，門唯二仲過。',72,'御定全唐詩/json/269.json','["芳菲那變易，年鬢自蹉跎。室與千峰對，門唯二仲過。", "宦情知己少，生事托人多。草色微風長，鶯聲細雨和。", "幾時猶滯拙，終日望恩波。縱欲論相報，無如漂母何。"]'),
('yuding-4','仙山行','耿湋','唐','御定全唐诗','yuding','','[]','深溪人不到，杖策獨緣源。花落尋無徑，雞鳴覺近村。',72,'御定全唐詩/json/269.json','["深溪人不到，杖策獨緣源。花落尋無徑，雞鳴覺近村。", "數翁皆藉草，對弈複傾尊。看畢初為局，歸逢幾世孫。", "雲迷入洞處，水引出山門。惆悵歸城郭，樵柯跡尚存。"]'),
('yuding-5','得替後書懷上第五相公','耿湋','唐','御定全唐诗','yuding','','[]','誰語恓惶客，偏承顧盼私。應逾骨肉分，敢忘死生期。',96,'御定全唐詩/json/269.json','["誰語恓惶客，偏承顧盼私。應逾骨肉分，敢忘死生期。", "山縣唯荒壘，雲屯盡老師。庖人寧自代，食檗謬相推。", "黃綬名空罷，青春鬢又衰。還來掃門處，猶未報恩時。", "獨立花飛滿，無言月下遲。不知丞相意，更欲遣何之。"]'),
('yuding-6','入塞曲','耿湋','唐','御定全唐诗','yuding','','[]','將軍帶十圍，重錦制戎衣。猿臂銷弓力，虯須長劍威。',72,'御定全唐詩/json/269.json','["將軍帶十圍，重錦制戎衣。猿臂銷弓力，虯須長劍威。", "首登平樂宴，新破大宛歸。樓上誅姬笑，門前問客稀。", "暮烽玄兔急，秋草紫騮肥。未奉君王詔，高槐晝掩扉。"]'),
('yuding-7','送姚校書因歸河中','耿湋','唐','御定全唐诗','yuding','','[]','十年相見少，一歲又還鄉。去住人惆悵，東西路渺茫。',72,'御定全唐詩/json/269.json','["十年相見少，一歲又還鄉。去住人惆悵，東西路渺茫。", "古陂無茂草，高樹有殘陽。委棄秋來稻，雕疏采後桑。", "月輪生舜廟，河水出關牆。明日過閭裏，光輝芸閣郎。"]'),
('yuding-8','題清源寺','耿湋','唐','御定全唐诗','yuding','','[]','儒墨兼宗道，雲泉隱舊廬。盂城今寂寞，輞水自紆餘。',72,'御定全唐詩/json/269.json','["儒墨兼宗道，雲泉隱舊廬。盂城今寂寞，輞水自紆餘。", "內學銷多累，西林易故居。深房春竹老，細雨夜鐘疏。", "陳跡留金地，遺文在石渠。不知登座客，誰得蔡邕書。"]'),
('yuding-9','奉送蔣尚書兼御史大夫東都留守','耿湋','唐','御定全唐诗','yuding','','[]','副相威名重，春卿禮樂崇。錫珪仍拜下，分命遂居東。',72,'御定全唐詩/json/269.json','["副相威名重，春卿禮樂崇。錫珪仍拜下，分命遂居東。", "高旆翻秋日，清鐃引細風。蟬稀金穀樹，草遍德陽宮。", "教用儒門儉，兵依武庫雄。誰雲千載後，周召獨為公。"]'),
('yuding-10','喜侯十七校書見訪','耿湋','唐','御定全唐诗','yuding','','[]','東城獨屏居，有客到吾廬。發廩因舂黍，開畦複剪蔬。',72,'御定全唐詩/json/269.json','["東城獨屏居，有客到吾廬。發廩因舂黍，開畦複剪蔬。", "許酣令乞酒，辭窶任無魚。遍出新成句，更通未悟書。", "藤絲秋不長，竹粉雨仍餘。誰為須張燭，涼空有望舒。"]'),
('yuding-11','晚春青門林亭燕集','耿湋','唐','御定全唐诗','yuding','','[]','都門連騎出，東野柳如絲。秦苑看山處，王孫逐草時。',72,'御定全唐詩/json/269.json','["都門連騎出，東野柳如絲。秦苑看山處，王孫逐草時。", "歡遊難再得，衰老是前期。林靜鶯啼遠，春深日過遲。", "落花今夕思，秉燭古人詩。對酒當為樂，雙杯未可辭。"]'),
('yuding-12','晚秋東遊寄猗氏第五明府解縣韓明府','耿湋','唐','御定全唐诗','yuding','','[]','步出青門去，疏鐘隔上林。四郊多難日，千里獨歸心。',72,'御定全唐詩/json/269.json','["步出青門去，疏鐘隔上林。四郊多難日，千里獨歸心。", "暮鳥聲偏苦，秋雲色易陰。亂墳松柏少，野徑草茅深。", "灞涘袁安履，汾南宓賤琴。何由聽白雪，只益淚沾襟。"]'),
('yuding-13','奉和元承杪秋憶終南舊居','耿湋','唐','御定全唐诗','yuding','','[]','白玉郎仍少，羊車上路平。秋風搖遠草，舊業起高情。',96,'御定全唐詩/json/269.json','["白玉郎仍少，羊車上路平。秋風搖遠草，舊業起高情。", "亂樹通秦苑，重原接杜城。溪雲隨暮淡，野水帶寒清。", "廣樹留峰翠，閑門響葉聲。近樵應已燒，多稼又新成。", "解佩從休沐，承家豈退耕。恭侯有遺躅，何事學泉明。"]'),
('yuding-14','晚夏即事臨南居','耿湋','唐','御定全唐诗','yuding','','[]','何須學從宦，其奈本無機。蕙草芳菲歇，青山早晚歸。',72,'御定全唐詩/json/269.json','["何須學從宦，其奈本無機。蕙草芳菲歇，青山早晚歸。", "廣庭餘落照，高枕對閑扉。樹色迎秋老，蟬聲過雨稀。", "艱難逢事異，去就與時違。遙憶衡門外，蒼蒼三徑微。"]'),
('yuding-15','省試驪珠詩','耿湋','唐','御定全唐诗','yuding','','[]','是日重泉下，言探徑寸珠。龍鱗今不逆，魚目也應殊。',72,'御定全唐詩/json/269.json','["是日重泉下，言探徑寸珠。龍鱗今不逆，魚目也應殊。", "掌上星初滿，盤中月正孤。酬恩光莫及，照乘色難逾。", "欲問投人否，先論按劍無。儻憐希代價，敢對此冰壺。"]'),
('yuding-16','元日早朝','耿湋','唐','御定全唐诗','yuding','','[]','九陌朝臣滿，三朝候鼓賒。遠珂時接韻，攢炬偶成花。',120,'御定全唐詩/json/269.json','["九陌朝臣滿，三朝候鼓賒。遠珂時接韻，攢炬偶成花。", "紫貝為高闕，黃龍建大牙。參差萬戟合，左右八貂斜。", "羽扇紛朱檻，金爐隔翠華。微風傳曙漏，曉日上春霞。", "環佩聲重疊，蠻夷服等差。樂和天易感，山固壽無涯。", "渥澤千年聖，車書四海家。盛明多在位，誰得守蓬麻。"]'),
('yuding-17','送歸中丞使新羅','耿湋','唐','御定全唐诗','yuding','','[]','遠國通王化，儒林得使臣。六君成典冊，萬里奉絲綸。',96,'御定全唐詩/json/269.json','["遠國通王化，儒林得使臣。六君成典冊，萬里奉絲綸。", "雲水連孤棹，恩私在一身。悠悠龍節去，渺渺蜃樓新。", "望裏行還暮，波中歲又春。昏明看日禦，靈怪問舟人。", "城邑分華夏，衣裳擬縉紳。他時禮命畢，歸路勿迷津。"]'),
('yuding-18','贈興平鄭明府','耿湋','唐','御定全唐诗','yuding','','[]','海內兵猶在，關西賦未均。仍勞持斧使，尚宰茂陵人。',120,'御定全唐詩/json/269.json','["海內兵猶在，關西賦未均。仍勞持斧使，尚宰茂陵人。", "遙夜重城掩，清宵片月新。綠琴聽古調，白屋被深仁。", "跡與儒生合，心惟靜者親。深情先結契，薄宦早趨塵。", "貧病休何日，艱難過此身。悠悠行遠道，冉冉過良辰。", "明主知封事，長沮笑問津。棲遑忽相見，欲語淚沾巾。"]'),
('yuding-19','和王懷州觀西營秋射','耿湋','唐','御定全唐诗','yuding','','[]','謝公親校武，草碧露漫漫。落葉停高駕，空林滿從官。',72,'御定全唐詩/json/269.json','["謝公親校武，草碧露漫漫。落葉停高駕，空林滿從官。", "迎籌皆疊鼓，揮箭或移竿。名借三軍勇，功推百中難。", "主皮山郡晚，飲算柳營寒。明日開鈴閣，新詩雙玉盤。"]'),
('yuding-20','晚登虔州即事寄李侍禦','耿湋','唐','御定全唐诗','yuding','','[]','章溪與貢水，何事會波瀾。萬里歸人少，孤舟行路難。',96,'御定全唐詩/json/269.json','["章溪與貢水，何事會波瀾。萬里歸人少，孤舟行路難。", "春光浮曲浪，暮色隔連灘。花發從南早，江流向北寬。", "故交參盛府，新角聳危冠。楚劍期終割，隋珠惜未彈。", "酒醒愁轉極，別遠淚初幹。願保喬松質，青青過大寒。"]'),
('yuding-21','奉和第五相公登鄱陽郡城西樓','耿湋','唐','御定全唐诗','yuding','','[]','茂德為邦久，豐貂舊相尊。發生傳雨露，均養助乾坤。',156,'御定全唐詩/json/269.json','["茂德為邦久，豐貂舊相尊。發生傳雨露，均養助乾坤。", "曉肆登樓目，春銷戀闕魂。女牆分吏事，遠道啟津門。", "湓浦潮聲盡，鐘陵暮色繁。夕陽移夢土，芳草接湘源。", "封內群甿複，兵間百賦存。童牛耕廢畝，壕木繞新村。", "野步漁聲溢，荒祠鼓舞喧。高齋成五字，遠岫發孤猿。", "一顧承英達，多榮及子孫。家貧仍受賜，身老未酬恩。", "屬和瑤華曲，堪將系組綸。"]'),
('yuding-22','甘泉詩','耿湋','唐','御定全唐诗','yuding','','[]','異井甘如醴，深仁遠未涯。氣寒堪破暑，源淨自蠲邪。',72,'御定全唐詩/json/269.json','["異井甘如醴，深仁遠未涯。氣寒堪破暑，源淨自蠲邪。", "修綆懸冰甃，新桐蔭玉沙。帶星凝曉露，拂霧湧秋華。", "綠溢涵千仞，清泠飲萬家。何能葛洪宅，終日閉煙霞。"]'),
('yuding-23','發綿津驛','耿湋','唐','御定全唐诗','yuding','','[]','孤舟北去暮心傷，細雨東風春草長。杳杳短亭分水陸，',40,'御定全唐詩/json/269.json','["孤舟北去暮心傷，細雨東風春草長。杳杳短亭分水陸，", "欲問長安今遠近，初年塞雁有歸行。"]'),
('yuding-24','塞上曲','耿湋','唐','御定全唐诗','yuding','','[]','慣習干戈事鞍馬，初從少小在邊城。身微久屬千夫長，',40,'御定全唐詩/json/269.json','["慣習干戈事鞍馬，初從少小在邊城。身微久屬千夫長，", "塞鴻過盡殘陽裏，樓上淒淒暮角聲。"]'),
('yuding-25','路旁老人','耿湋','唐','御定全唐诗','yuding','','[]','老人獨坐倚官樹，欲語潸然淚便垂。陌上歸心無產業，',40,'御定全唐詩/json/269.json','["老人獨坐倚官樹，欲語潸然淚便垂。陌上歸心無產業，", "綠水青山雖似舊，如今貧後複何為。"]'),
('yuding-26','贈別劉員外長卿','耿湋','唐','御定全唐诗','yuding','','[]','清如寒玉直如絲，世故多虞事莫期。建德津亭人別夜，',40,'御定全唐詩/json/269.json','["清如寒玉直如絲，世故多虞事莫期。建德津亭人別夜，", "不學朱雲能折檻，空羞獻納在丹墀。"]'),
('yuding-27','宿萬固寺因寄嚴補闕','耿湋','唐','御定全唐诗','yuding','','[]','曉隨樵客到青冥，因禮山僧宿化城。鐘梵已休初入定。',64,'御定全唐詩/json/269.json','["曉隨樵客到青冥，因禮山僧宿化城。鐘梵已休初入定。", "有無皆離本難名。雲開半夜千林靜，月上中峰萬壑明。", "為報故人雷處士，塵心終日自勞生。"]'),
('yuding-28','岐陽客舍呈張明府','耿湋','唐','御定全唐诗','yuding','','[]','逸妻稚子應溝壑，歸路茫茫東去遙。涼葉下時心悄悄，',40,'御定全唐詩/json/269.json','["逸妻稚子應溝壑，歸路茫茫東去遙。涼葉下時心悄悄，", "知己只今何處在，故山無事別漁樵。"]'),
('yuding-29','奉和李觀察登河中白樓','耿湋','唐','御定全唐诗','yuding','','[]','城上高樓飛鳥齊，從公一遂躡丹梯。黃河曲盡流天外，',40,'御定全唐詩/json/269.json','["城上高樓飛鳥齊，從公一遂躡丹梯。黃河曲盡流天外，", "何心更和陽春奏，況複秋風聞戰鼙。"]');
